export interface ActivityData {
  steps: number;
  calories: number;
  distance: number;
  stepGoal: number;
  calorieGoal: number; // Added custom goal
  distanceGoal: number; // Added custom goal
  history: { day: string; steps: number }[]; // Added 7-day history
}

export interface FoodMacro {
  calories: number;
  protein: number;
  fat: number;
  carbs: number;
}

export interface FoodAnalysis {
  name: string;
  macros: FoodMacro;
  healthScore: number; // 0-100
  verdict: 'Excellent' | 'Good' | 'Fair' | 'Avoid';
  advice: string;
  colorCode: 'green' | 'yellow' | 'red';
}

export enum ViewState {
  DASHBOARD = 'DASHBOARD',
  FOOD_LENS = 'FOOD_LENS',
  BMI_HUB = 'BMI_HUB',
}

export interface UserMetrics {
  height: number; // cm
  weight: number; // kg
}

import { GoogleGenAI, Type } from "@google/genai";
import { FoodAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING },
    macros: {
      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      }
    },
    healthScore: { type: Type.NUMBER },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] }
  }
};

export const analyzeFoodImage = async (base64Image: string): Promise<FoodAnalysis> => {
  try {
    const prompt = `Analyze this food image. Identify the item and estimate nutrition per serving.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] 
            }
          },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("No response from AI");

  } catch (error) {
    console.error("Gemini Image Error:", error);
    return getErrorFallback();
  }
};

export const analyzeFoodText = async (query: string): Promise<FoodAnalysis> => {
  try {
    const prompt = `Analyze the food item described as: "${query}". Estimate nutrition per serving.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("No response from AI");
  } catch (error) {
    console.error("Gemini Text Error:", error);
    return getErrorFallback();
  }
};

const getErrorFallback = (): FoodAnalysis => ({
  name: "Analysis Failed",
  macros: { calories: 0, protein: 0, fat: 0, carbs: 0 },
  healthScore: 0,
  verdict: "Avoid",
  advice: "Could not identify food. Please try again.",
  colorCode: "red"
});

import React, { useEffect, useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, Tooltip as RechartsTooltip } from 'recharts';
import { ActivityData } from '../types';
import { Flame, Footprints, MapPin, Settings, CheckCircle2 } from 'lucide-react';

interface DashboardProps {
  data: ActivityData;
  onUpdateGoals: (newGoals: Partial<ActivityData>) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ data, onUpdateGoals }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editValues, setEditValues] = useState({
    stepGoal: data.stepGoal,
    calorieGoal: data.calorieGoal,
    distanceGoal: data.distanceGoal
  });

  // Confetti trigger & Haptics
  const goalReached = data.steps >= data.stepGoal;

  useEffect(() => {
    if (goalReached) {
      // Haptic feedback for goal reached
      if (navigator.vibrate) navigator.vibrate([100, 50, 100]);
    }
  }, [goalReached]);

  const handleSaveGoals = () => {
    onUpdateGoals({
      stepGoal: Number(editValues.stepGoal),
      calorieGoal: Number(editValues.calorieGoal),
      distanceGoal: Number(editValues.distanceGoal)
    });
    setIsEditing(false);
    if (navigator.vibrate) navigator.vibrate(50);
  };

  // Data for Rings
  const stepsData = [
    { name: 'Completed', value: Math.min(data.steps, data.stepGoal) },
    { name: 'Remaining', value: Math.max(0, data.stepGoal - data.steps) },
  ];
  const calsData = [
    { name: 'Completed', value: data.calories },
    { name: 'Remaining', value: Math.max(0, data.calorieGoal - data.calories) },
  ];
  const distData = [
    { name: 'Completed', value: data.distance },
    { name: 'Remaining', value: Math.max(0, data.distanceGoal - data.distance) },
  ];

  return (
    <div className="h-full w-full flex flex-col p-6 pt-12 space-y-6 animate-fade-in pb-20">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-sm font-semibold text-gray-400 uppercase tracking-widest">Today's Activity</h2>
          <h1 className="text-3xl font-bold text-white mt-1">
            Keep Moving <span className="text-luxury-neon">.</span>
          </h1>
        </div>
        <button 
          onClick={() => isEditing ? handleSaveGoals() : setIsEditing(true)}
          className={`h-10 w-10 rounded-full flex items-center justify-center transition-all ${isEditing ? 'bg-luxury-neon text-black' : 'bg-white/10 text-white'}`}
        >
          {isEditing ? <CheckCircle2 size={20} /> : <Settings size={20} />}
        </button>
      </div>

      {/* Goal Editor Overlay (Visual Indication) */}
      {isEditing && (
        <div className="text-center text-xs text-luxury-neon animate-pulse uppercase tracking-widest">
          Editing Goals Mode Active
        </div>
      )}

      {/* Rings Container */}
      <div className="relative w-full h-72 flex items-center justify-center glass-panel rounded-3xl overflow-hidden shrink-0">
        {goalReached && (
          <div className="absolute inset-0 bg-luxury-neon/5 animate-pulse z-0 pointer-events-none" />
        )}

        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            {/* Steps Ring (Outer) */}
            <Pie
              data={stepsData}
              cx="50%"
              cy="50%"
              innerRadius={100}
              outerRadius={115}
              startAngle={90}
              endAngle={-270}
              dataKey="value"
              stroke="none"
              cornerRadius={10}
            >
              <Cell key="cell-0" fill="#a3e635" /> {/* Neon Green */}
              <Cell key="cell-1" fill="#333333" />
            </Pie>
            {/* Calories Ring (Middle) */}
            <Pie
              data={calsData}
              cx="50%"
              cy="50%"
              innerRadius={75}
              outerRadius={90}
              startAngle={90}
              endAngle={-270}
              dataKey="value"
              stroke="none"
              cornerRadius={10}
            >
              <Cell key="cell-0" fill="#eab308" /> {/* Gold */}
              <Cell key="cell-1" fill="#333333" />
            </Pie>
            {/* Distance Ring (Inner) */}
            <Pie
              data={distData}
              cx="50%"
              cy="50%"
              innerRadius={50}
              outerRadius={65}
              startAngle={90}
              endAngle={-270}
              dataKey="value"
              stroke="none"
              cornerRadius={10}
            >
              <Cell key="cell-0" fill="#ef4444" /> {/* Red */}
              <Cell key="cell-1" fill="#333333" />
            </Pie>
          </PieChart>
        </ResponsiveContainer>

        {/* Center Stats */}
        <div className="absolute flex flex-col items-center justify-center z-10">
          <Footprints className="text-luxury-neon mb-1 animate-bounce" size={20} />
          {isEditing ? (
            <input 
              type="number"
              value={editValues.stepGoal}
              onChange={(e) => setEditValues({...editValues, stepGoal: Number(e.target.value)})}
              className="w-24 bg-transparent text-center text-4xl font-bold tracking-tighter text-white border-b border-luxury-neon focus:outline-none"
            />
          ) : (
            <span className="text-4xl font-bold tracking-tighter">{data.steps.toLocaleString()}</span>
          )}
          <span className="text-xs text-gray-500 uppercase tracking-widest mt-1">Steps</span>
