export default Dashboard;

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { Camera, Zap, X, Search, Keyboard } from 'lucide-react';
import { analyzeFoodImage, analyzeFoodText } from '../services/geminiService';
import { FoodAnalysis } from '../types';

const FoodLens: React.FC = () => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<FoodAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [manualQuery, setManualQuery] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment' }
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      setError("Camera access denied. Check permissions.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const handleAnalysisSuccess = (data: FoodAnalysis) => {
    setResult(data);
    if (navigator.vibrate) navigator.vibrate(50); // Haptic success
    setAnalyzing(false);
    setIsTyping(false);
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    setAnalyzing(true);
    const video = videoRef.current;
    const canvas = canvasRef.current;

    // Match canvas size to video
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;

    // Draw current frame
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      const base64Image = canvas.toDataURL('image/jpeg', 0.7);

      try {
        const data = await analyzeFoodImage(base64Image);
        handleAnalysisSuccess(data);
      } catch (err) {
        console.error(err);
        setError("Failed to analyze. Try again.");
        setAnalyzing(false);
      }
    }
  };

  const handleManualSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!manualQuery.trim()) return;

    setAnalyzing(true);
    try {
      const data = await analyzeFoodText(manualQuery);
      handleAnalysisSuccess(data);
    } catch (err) {
      setError("Failed to analyze text.");
      setAnalyzing(false);
    }
  };

  const reset = () => {
    setResult(null);
    setError(null);
    setManualQuery('');
    // Ensure camera is running
    if (!stream) startCamera();
  };

  const getColorClass = (code: string) => {
    switch(code) {
      case 'green': return 'text-luxury-neon border-luxury-neon';
      case 'yellow': return 'text-luxury-gold border-luxury-gold';
      case 'red': return 'text-red-500 border-red-500';
      default: return 'text-white border-white';
    }
  };

  if (result) {
    return (
      <div className="h-full w-full flex flex-col p-6 animate-fade-in pt-12 relative">
         <div className="absolute top-0 left-0 w-full h-[40vh] bg-gradient-to-b from-transparent to-black" />
         {/* Show captured image ONLY if input was NOT manual */}
         {manualQuery === '' && (
            <img 
                src={canvasRef.current?.toDataURL()} 
                className="absolute top-0 left-0 w-full h-[40vh] object-cover opacity-50 mask-gradient" 
                alt="Captured"
            />
         )}

         <div className="z-10 mt-[20vh]">
            <div className={`glass-panel p-6 rounded-3xl border-l-4 ${getColorClass(result.colorCode)} transition-all duration-500`}>
              <div className="flex justify-between items-start mb-4">
                <div>
                   <h2 className="text-3xl font-bold">{result.name}</h2>
                   <div className={`inline-block px-3 py-1 rounded-full text-xs font-bold uppercase mt-2 bg-white/10 ${getColorClass(result.colorCode)}`}>
                      {result.verdict} Choice
                   </div>
                </div>
                <div className="text-right">
                  <span className="block text-4xl font-bold">{result.macros.calories}</span>
                  <span className="text-xs text-gray-400 uppercase">Calories</span>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-2 my-6">
                 <div className="text-center p-2 rounded-xl bg-white/5">
                    <span className="block font-bold text-luxury-neon">{result.macros.protein}g</span>
                    <span className="text-[10px] text-gray-400">PROT</span>
                 </div>
                 <div className="text-center p-2 rounded-xl bg-white/5">
                    <span className="block font-bold text-yellow-500">{result.macros.fat}g</span>
                    <span className="text-[10px] text-gray-400">FAT</span>
                 </div>
                 <div className="text-center p-2 rounded-xl bg-white/5">
                    <span className="block font-bold text-blue-400">{result.macros.carbs}g</span>
                    <span className="text-[10px] text-gray-400">CARB</span>
                 </div>
              </div>

              <div className="bg-white/5 p-4 rounded-xl border border-white/5">
                <p className="text-sm italic text-gray-300">"{result.advice}"</p>
              </div>
            </div>

            <button 
              onClick={reset}
              className="mt-8 w-full py-4 rounded-full bg-luxury-neon text-black font-bold text-lg hover:opacity-90 transition-opacity flex items-center justify-center gap-2"
            >
              <Camera size={20} /> Scan Another
            </button>
         </div>
      </div>
    );
  }

  return (
    <div className="h-full w-full relative bg-black">
      {/* Hidden Canvas for capture */}
      <canvas ref={canvasRef} className="hidden" />

      {/* Video Feed */}
      <div className="absolute inset-0 z-0">
        {stream ? (
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            className="w-full h-full object-cover opacity-80"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center text-gray-600">
             {error || "Initializing Camera..."}
          </div>
        )}
      </div>

      {/* AR Overlay UI */}
      <div className="absolute inset-0 z-10 p-6 flex flex-col justify-between pointer-events-none">
        <div className="pt-8 flex justify-between items-center">
            <div className="bg-black/40 backdrop-blur-md px-3 py-1 rounded-full border border-luxury-neon/50">
               <span className="text-luxury-neon text-xs font-mono animate-pulse">● AI VISION ACTIVE</span>
            </div>
            <div className="bg-black/40 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
               <span className="text-white text-xs font-mono">ISO 800</span>
            </div>
        </div>

        {/* Center Reticle */}
        {!isTyping && (
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 border border-white/30 rounded-3xl flex items-center justify-center transition-opacity duration-300">
                <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-luxury-neon rounded-tl-lg"></div>
                <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-luxury-neon rounded-tr-lg"></div>
                <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-luxury-neon rounded-bl-lg"></div>
                <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-luxury-neon rounded-br-lg"></div>

                {analyzing && (
                <div className="w-full h-1 bg-luxury-neon/50 absolute top-0 animate-scan blur-sm"></div>
                )}
            </div>
        )}

        <div className="pb-24 pointer-events-auto flex flex-col gap-4">
           {/* Manual Search Bar */}
           <form onSubmit={handleManualSearch} className="relative glass-panel rounded-full flex items-center px-4 py-2 border border-white/10 focus-within:border-luxury-neon transition-colors">
              <Keyboard className="text-gray-400 mr-2" size={18} />
              <input 
                type="text" 
                placeholder="Or type food name..." 
                value={manualQuery}
                onChange={(e) => setManualQuery(e.target.value)}
                onFocus={() => setIsTyping(true)}
                onBlur={() => setIsTyping(false)}
                className="bg-transparent border-none outline-none text-white text-sm w-full h-8 placeholder-gray-500"
              />
              {manualQuery && (
                 <button type="submit" className="bg-white/10 p-1 rounded-full text-luxury-neon">
                    <Search size={16} />
                 </button>
              )}
           </form>

           <p className="text-center text-gray-300 text-sm drop-shadow-md transition-opacity duration-300" style={{ opacity: isTyping ? 0 : 1 }}>
              Align food within frame
           </p>

           <button 
             onClick={captureAndAnalyze}
             disabled={analyzing}
             className="w-full py-4 rounded-full bg-white text-black font-bold text-lg hover:bg-gray-200 transition-all flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50"
           >
             {analyzing ? (
               <span className="animate-pulse">Analyzing...</span>
             ) : (
               <>
                 <Zap className="fill-black" size={20} /> Identify Image
               </>
             )}
           </button>
        </div>
      </div>
    </div>
  );
};

export default FoodLens;

import React, { useState, useEffect, useRef } from 'react';
import { UserMetrics } from '../types';

const BMIHub: React.FC = () => {
  const [metrics, setMetrics] = useState<UserMetrics>({ height: 175, weight: 70 });
  const [bmi, setBmi] = useState<number>(0);
  const [status, setStatus] = useState<string>('');
  const prevStatusRef = useRef<string>('');

  useEffect(() => {
    // BMI = kg / (m^2)
    const heightInMeters = metrics.height / 100;
    const calculatedBmi = metrics.weight / (heightInMeters * heightInMeters);
    const newBmi = Number(calculatedBmi.toFixed(1));
    setBmi(newBmi);

    let newStatus = '';
    if (newBmi < 18.5) newStatus = 'Underweight';
    else if (newBmi < 25) newStatus = 'Fit';
    else if (newBmi < 30) newStatus = 'Overweight';
    else newStatus = 'Obese';

    setStatus(newStatus);

    // Haptic feedback when crossing zones
    if (prevStatusRef.current !== '' && prevStatusRef.current !== newStatus) {
       if (navigator.vibrate) navigator.vibrate(20);
    }
    prevStatusRef.current = newStatus;
  }, [metrics]);

  // Visual Gauge needle rotation (-90deg to 90deg)
  const getNeedleRotation = () => {
    // Map BMI 15-40 to -90 to 90
    const minBMI = 15;
    const maxBMI = 40;
    const clampedBMI = Math.max(minBMI, Math.min(bmi, maxBMI));
    const percentage = (clampedBMI - minBMI) / (maxBMI - minBMI);
    return -90 + (percentage * 180);
  };

  const getStatusColor = () => {
    if (status === 'Fit') return 'text-luxury-neon';
    if (status === 'Overweight') return 'text-luxury-gold';
    if (status === 'Underweight') return 'text-blue-400';
    return 'text-red-500';
  };

  return (
    <div className="h-full w-full flex flex-col p-6 pt-12 animate-fade-in space-y-6">
      <div>
        <h2 className="text-sm font-semibold text-gray-400 uppercase tracking-widest">Intelligent Body Metrics</h2>
        <h1 className="text-3xl font-bold text-white mt-1">
          Your <span className="text-luxury-gold">Blueprint</span>.
        </h1>
      </div>

      {/* Gauge Visualization */}
      <div className="glass-panel rounded-3xl p-6 flex flex-col items-center justify-center relative overflow-hidden">
        <div className="w-64 h-32 relative overflow-hidden mb-4">
           {/* Segmented Arc Background 
               M 16 128 A 112 112 0 0 1 240 128 
               Total Length approx 352
               15 to 40 = range of 25 units.

               15-18.5 (3.5 units) = 14% -> Blue
               18.5-25 (6.5 units) = 26% -> Green
               25-30 (5 units) = 20% -> Yellow
               30-40 (10 units) = 40% -> Red
           */}
           <svg className="absolute top-0 left-0 w-full h-full" viewBox="0 0 256 128">
              {/* Track Background */}
              <path d="M 16 128 A 112 112 0 0 1 240 128" fill="none" stroke="#222" strokeWidth="24" strokeLinecap="round" />

              {/* Segments - using stroke-dasharray to carve out sections. Total ~351 */}

              {/* Blue (Underweight) 0 to 14% */}
              <path d="M 16 128 A 112 112 0 0 1 240 128" fill="none" stroke="#60a5fa" strokeWidth="24" strokeLinecap="round" 
                strokeDasharray="49 302" strokeDashoffset="0" />

