import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import { ViewState, ActivityData } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  // Simulated State for Pedometer (Live Update effect)
  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 6430,
    calories: 320,
    distance: 3.2,
    stepGoal: 10000,
    calorieGoal: 800,
    distanceGoal: 5.0,
    history: [
      { day: 'Mon', steps: 6500 },
      { day: 'Tue', steps: 8200 },
      { day: 'Wed', steps: 4800 },
      { day: 'Thu', steps: 9100 },
      { day: 'Fri', steps: 5200 },
      { day: 'Sat', steps: 11200 },
      { day: 'Sun', steps: 6430 }, // Today
    ]
  });

  // Effect to simulate live steps (Mocking sensors)
  useEffect(() => {
    const interval = setInterval(() => {
      setActivityData(prev => {
        // Only increment occasionally to simulate walking
        if (Math.random() > 0.7) {
          const addedSteps = Math.floor(Math.random() * 3) + 1;
          const newSteps = prev.steps + addedSteps;

          // Update history for today (Sun) as well
          const newHistory = [...prev.history];
          newHistory[6] = { ...newHistory[6], steps: newSteps };

          return {
            ...prev,
            steps: newSteps,
            calories: prev.calories + (addedSteps * 0.04), // approx cal per step
            distance: prev.distance + (addedSteps * 0.0007), // approx km per step
            history: newHistory
          };
        }
        return prev;
      });
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => {
    setActivityData(prev => ({ ...prev, ...newGoals }));
  };

  const renderView = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard data={activityData} onUpdateGoals={handleUpdateGoals} />;
      case ViewState.FOOD_LENS:
        return <FoodLens />;
      case ViewState.BMI_HUB:
        return <BMIHub />;
      default:
        return <Dashboard data={activityData} onUpdateGoals={handleUpdateGoals} />;
    }
  };

  return (
    <div className="min-h-screen bg-black text-white relative overflow-hidden font-sans selection:bg-luxury-neon selection:text-black">
      {/* Ambient Background Glows */}
      <div className="fixed top-[-10%] right-[-10%] w-[50vh] h-[50vh] bg-luxury-neon/5 rounded-full blur-[100px] pointer-events-none z-0"></div>
      <div className="fixed bottom-[-10%] left-[-10%] w-[40vh] h-[40vh] bg-luxury-gold/5 rounded-full blur-[80px] pointer-events-none z-0"></div>

      {/* Main Content Area */}
      <main className="relative z-10 h-screen overflow-y-auto no-scrollbar">
        {renderView()}
      </main>

      {/* Navigation */}
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

