import { GoogleGenAI, Type } from "@google/genai";
import { FoodAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING },
    macros: {
      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      }
    },
    healthScore: { type: Type.NUMBER },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] },
    boundingBox: {
      type: Type.ARRAY,
      items: { type: Type.NUMBER },
      description: "Bounding box of the food item in [ymin, xmin, ymax, xmax] format (normalized 0-1)."
    }
  }
};

export const analyzeFoodImage = async (base64Image: string): Promise<FoodAnalysis> => {
  try {
    const prompt = `Analyze this food image. Identify the item, estimate nutrition per serving, and provide the bounding box [ymin, xmin, ymax, xmax] of the main food item.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] 
            }
          },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("No response from AI");

  } catch (error) {
    console.error("Gemini Image Error:", error);
    return getErrorFallback();
  }
};

export const analyzeFoodText = async (query: string): Promise<FoodAnalysis> => {
  try {
    const prompt = `Analyze the food item described as: "${query}". Estimate nutrition per serving.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("No response from AI");
  } catch (error) {
    console.error("Gemini Text Error:", error);
    return getErrorFallback();
  }
};

const getErrorFallback = (): FoodAnalysis => ({
  name: "Analysis Failed",
  macros: { calories: 0, protein: 0, fat: 0, carbs: 0 },
  healthScore: 0,
  verdict: "Avoid",
  advice: "Could not identify food. Please try again.",
  colorCode: "red"
});

