import React, { useRef, useState, useCallback, useEffect } from 'react';
import { Camera, Zap, X, Search, Keyboard, ZapOff, History, ArrowLeft, Clock } from 'lucide-react';
import { analyzeFoodImage, analyzeFoodText } from '../services/geminiService';
import { FoodAnalysis, FoodHistoryItem } from '../types';

interface FoodLensProps {
  history: FoodHistoryItem[];
  onAddToHistory: (item: FoodHistoryItem) => void;
}

const FoodLens: React.FC<FoodLensProps> = ({ history, onAddToHistory }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<FoodAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [manualQuery, setManualQuery] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  // New Features State
  const [showHistory, setShowHistory] = useState(false);
  const [hasFlash, setHasFlash] = useState(false);
  const [isFlashOn, setIsFlashOn] = useState(false);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { 
          facingMode: 'environment',
          width: { ideal: 1920 },
          height: { ideal: 1080 }
        }
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }

      // Check for Flash/Torch capability
      const track = mediaStream.getVideoTracks()[0];
      const capabilities = track.getCapabilities ? track.getCapabilities() : {};
      // @ts-ignore - torch is not standard in all TS lib definitions yet
      if (capabilities.torch) {
        setHasFlash(true);
      }

    } catch (err) {
      setError("Camera access denied. Check permissions.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => {
        track.stop();
      });
      setStream(null);
    }
  };

  useEffect(() => {
    if (!showHistory && !result) {
      startCamera();
    } else {
      stopCamera();
    }
    return () => stopCamera();
  }, [showHistory, result]);

  const toggleFlash = async () => {
    if (!stream || !hasFlash) return;
    const track = stream.getVideoTracks()[0];
    const newFlashState = !isFlashOn;

    try {
      // @ts-ignore
      await track.applyConstraints({
        advanced: [{ torch: newFlashState }]
      });
      setIsFlashOn(newFlashState);
    } catch (err) {
      console.error("Flash toggle failed", err);
    }
  };

  const triggerAutoFocus = async () => {
    if (!stream) return;
    const track = stream.getVideoTracks()[0];
    try {
      // @ts-ignore
      await track.applyConstraints({
        advanced: [{ focusMode: 'continuous' }]
      });
    } catch (err) {
      // Ignore if not supported
    }
  };

  const handleAnalysisSuccess = (data: FoodAnalysis) => {
    const newItem: FoodHistoryItem = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      analysis: data
    };
    onAddToHistory(newItem);
    setResult(data);
    if (navigator.vibrate) navigator.vibrate(50); // Haptic success
    setAnalyzing(false);
    setIsTyping(false);
    setIsFlashOn(false); // Turn off flash after capture
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    setAnalyzing(true);
    const video = videoRef.current;
    const canvas = canvasRef.current;

    // Match canvas size to video
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;

    // Draw current frame
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      const base64Image = canvas.toDataURL('image/jpeg', 0.8);

      try {
        const data = await analyzeFoodImage(base64Image);
        handleAnalysisSuccess(data);
      } catch (err) {
        console.error(err);
        setError("Failed to analyze. Try again.");
        setAnalyzing(false);
      }
    }
  };

  const handleManualSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!manualQuery.trim()) return;

    setAnalyzing(true);
    try {
      const data = await analyzeFoodText(manualQuery);
      handleAnalysisSuccess(data);
    } catch (err) {
      setError("Failed to analyze text.");
      setAnalyzing(false);
    }
  };

  const reset = () => {
    setResult(null);
    setError(null);
    setManualQuery('');
    setShowHistory(false);
  };

  const getColorClass = (code: string) => {
    switch(code) {
      case 'green': return 'text-luxury-neon border-luxury-neon';
      case 'yellow': return 'text-luxury-gold border-luxury-gold';
      case 'red': return 'text-red-500 border-red-500';
      default: return 'text-white border-white';
    }
  };

  // --- History View ---
  if (showHistory) {
    return (
      <div className="h-full w-full flex flex-col p-6 animate-fade-in pt-12">
        <div className="flex items-center gap-4 mb-8">
          <button onClick={() => setShowHistory(false)} className="bg-white/10 p-2 rounded-full text-white">
            <ArrowLeft size={24} />
          </button>
          <h1 className="text-2xl font-bold">Food Log</h1>
        </div>

        <div className="flex-1 overflow-y-auto space-y-4 pb-20">
          {history.length === 0 ? (
            <div className="text-center text-gray-500 mt-20">
              <Clock size={48} className="mx-auto mb-4 opacity-50" />
              <p>No meals tracked yet.</p>
            </div>
          ) : (
            history.map((item) => (
              <div key={item.id} className="glass-panel p-4 rounded-2xl flex justify-between items-center">
                <div>
                  <h3 className="font-bold text-lg">{item.analysis.name}</h3>
                  <p className="text-xs text-gray-400">
                    {new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </p>
                </div>
                <div className="text-right">
                   <span className="block font-bold text-luxury-neon">{item.analysis.macros.calories} cal</span>
                   <span className={`text-xs uppercase px-2 py-0.5 rounded-full border ${getColorClass(item.analysis.colorCode).replace('text-', 'border-').split(' ')[1]} ${getColorClass(item.analysis.colorCode).split(' ')[0]}`}>
                     {item.analysis.verdict}
                   </span>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    );
  }

  // --- Result View ---
  if (result) {
    // Bounding Box Calculation
    // API returns [ymin, xmin, ymax, xmax] normalized 0-1
    const bb = result.boundingBox;
    const boxStyle = bb ? {
      top: `${bb[0] * 100}%`,
      left: `${bb[1] * 100}%`,
      height: `${(bb[2] - bb[0]) * 100}%`,
      width: `${(bb[3] - bb[1]) * 100}%`
    } : {};

    return (
      <div className="h-full w-full flex flex-col p-6 animate-fade-in pt-12 relative">
         <div className="absolute top-0 left-0 w-full h-[50vh] bg-gradient-to-b from-transparent to-black" />

         {/* Background Image Container */}
         {manualQuery === '' && (
            <div className="absolute top-0 left-0 w-full h-[50vh] overflow-hidden opacity-60 mask-gradient">
              <img 
                  src={canvasRef.current?.toDataURL()} 
                  className="w-full h-full object-cover" 
                  alt="Captured"
              />
              {/* Bounding Box Overlay */}
              {bb && (
                <div 
                  className="absolute border-2 border-luxury-neon shadow-[0_0_15px_rgba(163,230,53,0.5)] rounded-lg z-10 animate-pulse-slow"
                  style={boxStyle}
                >
                  <div className="absolute -top-6 left-0 bg-luxury-neon text-black text-[10px] font-bold px-2 py-0.5 rounded-t">
                    DETECTED
                  </div>
                </div>
              )}
            </div>
         )}

         <div className="z-10 mt-[30vh]">
            <div className={`glass-panel p-6 rounded-3xl border-l-4 ${getColorClass(result.colorCode)} transition-all duration-500`}>
              <div className="flex justify-between items-start mb-4">
                <div>
                   <h2 className="text-3xl font-bold line-clamp-2">{result.name}</h2>
                   <div className={`inline-block px-3 py-1 rounded-full text-xs font-bold uppercase mt-2 bg-white/10 ${getColorClass(result.colorCode)}`}>
                      {result.verdict} Choice
                   </div>
                </div>
                <div className="text-right shrink-0 ml-2">
                  <span className="block text-4xl font-bold">{result.macros.calories}</span>
                  <span className="text-xs text-gray-400 uppercase">Calories</span>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-2 my-6">
                 <div className="text-center p-2 rounded-xl bg-white/5">
                    <span className="block font-bold text-luxury-neon">{result.macros.protein}g</span>
                    <span className="text-[10px] text-gray-400">PROT</span>
                 </div>
                 <div className="text-center p-2 rounded-xl bg-white/5">
                    <span className="block font-bold text-yellow-500">{result.macros.fat}g</span>
                    <span className="text-[10px] text-gray-400">FAT</span>
                 </div>
                 <div className="text-center p-2 rounded-xl bg-white/5">
                    <span className="block font-bold text-blue-400">{result.macros.carbs}g</span>
                    <span className="text-[10px] text-gray-400">CARB</span>
                 </div>
              </div>

              <div className="bg-white/5 p-4 rounded-xl border border-white/5">
                <p className="text-sm italic text-gray-300">"{result.advice}"</p>
              </div>
            </div>

            <button 
              onClick={reset}
              className="mt-8 w-full py-4 rounded-full bg-luxury-neon text-black font-bold text-lg hover:opacity-90 transition-opacity flex items-center justify-center gap-2"
            >
              <Camera size={20} /> Scan Another
            </button>
         </div>
      </div>
    );
  }

  // --- Camera/Scan View ---
  return (
    <div className="h-full w-full relative bg-black">
      {/* Hidden Canvas for capture */}
      <canvas ref={canvasRef} className="hidden" />

      {/* Video Feed */}
