import { useState, useEffect } from 'react';

function useLocalStorage<T>(key: string, initialValue: T): [T, (value: T | ((val: T) => T)) => void] {
  // Get from local storage then parse stored json or return initialValue
  const readValue = (): T => {
    if (typeof window === 'undefined') {
      return initialValue;
    }

    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.warn(`Error reading localStorage key “${key}”:`, error);
      return initialValue;
    }
  };

  const [storedValue, setStoredValue] = useState<T>(readValue);

  // Return a wrapped version of useState's setter function that ...
  // ... persists the new value to localStorage.
  const setValue = (value: T | ((val: T) => T)) => {
    try {
      // Allow value to be a function so we have same API as useState
      const valueToStore = value instanceof Function ? value(storedValue) : value;

      // Save state
      setStoredValue(valueToStore);

      // Save to local storage
      if (typeof window !== 'undefined') {
        window.localStorage.setItem(key, JSON.stringify(valueToStore));
      }
    } catch (error) {
      console.warn(`Error setting localStorage key “${key}”:`, error);
    }
  };

  useEffect(() => {
    setStoredValue(readValue());
  }, []);

  return [storedValue, setValue];
}

export default useLocalStorage;

import { useState, useEffect, useRef } from 'react';

interface PedometerHook {
  isTracking: boolean;
  toggleTracking: () => Promise<void>;
  permissionGranted: boolean;
  liveSteps: number;
  resetLiveSteps: () => void;
}

const usePedometer = (): PedometerHook => {
  const [isTracking, setIsTracking] = useState(false);
  const [permissionGranted, setPermissionGranted] = useState(false);
  const [liveSteps, setLiveSteps] = useState(0);

  // Refs for algorithm to avoid re-renders
  const lastMag = useRef(0);
  const isPeak = useRef(false);
  const lastStepTime = useRef(0);

  const handleMotion = (event: DeviceMotionEvent) => {
    if (!event.accelerationIncludingGravity) return;

    const { x, y, z } = event.accelerationIncludingGravity;
    if (x === null || y === null || z === null) return;

    // Calculate magnitude vector
    const mag = Math.sqrt(x*x + y*y + z*z);

    // Step Detection Algorithm
    // Standard gravity is ~9.8 m/s^2. 
    // Walking creates peaks > 11-12. Running > 15.
    // We use a threshold and debounce time (300ms) to filter jitter.
    const THRESHOLD = 11.5; 
    const MIN_STEP_DELAY = 300; 
    const now = Date.now();

    if (mag > THRESHOLD && !isPeak.current) {
      if (now - lastStepTime.current > MIN_STEP_DELAY) {
        isPeak.current = true;
        setLiveSteps(prev => prev + 1);
        lastStepTime.current = now;
      }
    } else if (mag < THRESHOLD && isPeak.current) {
      isPeak.current = false;
    }

    lastMag.current = mag;
  };

  const requestPermission = async (): Promise<boolean> => {
    // iOS 13+ requires explicit permission
    // @ts-ignore
    if (typeof DeviceMotionEvent !== 'undefined' && typeof DeviceMotionEvent.requestPermission === 'function') {
      try {
        // @ts-ignore
        const permissionState = await DeviceMotionEvent.requestPermission();
        return permissionState === 'granted';
      } catch (e) {
        console.error(e);
        return false;
      }
    }
    return true; // Non-iOS devices usually don't need explicit permission if over HTTPS
  };

  const toggleTracking = async () => {
    if (isTracking) {
      window.removeEventListener('devicemotion', handleMotion);
      setIsTracking(false);
    } else {
      const granted = await requestPermission();
      if (granted) {
        setPermissionGranted(true);
        window.addEventListener('devicemotion', handleMotion);
        setIsTracking(true);
      } else {
        alert("Motion sensor permission is required to count steps.");
      }
    }
  };

  // Cleanup
  useEffect(() => {
    return () => {
      window.removeEventListener('devicemotion', handleMotion);
    };
  }, []);

  const resetLiveSteps = () => setLiveSteps(0);

  return { isTracking, toggleTracking, permissionGranted, liveSteps, resetLiveSteps };
};

export default usePedometer;

