import React, { useState, useEffect, useRef } from 'react';
import { UserMetrics } from '../types';
import useLocalStorage from '../hooks/useLocalStorage';

const BMIHub: React.FC = () => {
  // Use persistent storage for metrics
  const [metrics, setMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [bmi, setBmi] = useState<number>(0);
  const [status, setStatus] = useState<string>('');
  const prevStatusRef = useRef<string>('');

  useEffect(() => {
    // BMI = kg / (m^2)
    const heightInMeters = metrics.height / 100;
    const calculatedBmi = metrics.weight / (heightInMeters * heightInMeters);
    const newBmi = Number(calculatedBmi.toFixed(1));
    setBmi(newBmi);

    let newStatus = '';
    if (newBmi < 18.5) newStatus = 'Underweight';
    else if (newBmi < 25) newStatus = 'Fit';
    else if (newBmi < 30) newStatus = 'Overweight';
    else newStatus = 'Obese';

    setStatus(newStatus);

    // Haptic feedback when crossing zones
    if (prevStatusRef.current !== '' && prevStatusRef.current !== newStatus) {
       if (navigator.vibrate) navigator.vibrate(20);
    }
    prevStatusRef.current = newStatus;
  }, [metrics]);

  // Visual Gauge needle rotation (-90deg to 90deg)
  const getNeedleRotation = () => {
    // Map BMI 15-40 to -90 to 90
    const minBMI = 15;
    const maxBMI = 40;
    const clampedBMI = Math.max(minBMI, Math.min(bmi, maxBMI));
    const percentage = (clampedBMI - minBMI) / (maxBMI - minBMI);
    return -90 + (percentage * 180);
  };

  const getStatusColor = () => {
    if (status === 'Fit') return 'text-luxury-neon';
    if (status === 'Overweight') return 'text-luxury-gold';
    if (status === 'Underweight') return 'text-blue-400';
    return 'text-red-500';
  };

  return (
    <div className="h-full w-full flex flex-col p-6 pt-12 animate-fade-in space-y-6">
      <div>
        <h2 className="text-sm font-semibold text-gray-400 uppercase tracking-widest">Intelligent Body Metrics</h2>
        <h1 className="text-3xl font-bold text-white mt-1">
          Your <span className="text-luxury-gold">Blueprint</span>.
        </h1>
      </div>

      {/* Gauge Visualization */}
      <div className="glass-panel rounded-3xl p-6 flex flex-col items-center justify-center relative overflow-hidden">
        <div className="w-64 h-32 relative overflow-hidden mb-4">
           <svg className="absolute top-0 left-0 w-full h-full" viewBox="0 0 256 128">
              {/* Track Background */}
              <path d="M 16 128 A 112 112 0 0 1 240 128" fill="none" stroke="#222" strokeWidth="24" strokeLinecap="round" />

              {/* Segments - using stroke-dasharray to carve out sections. Total ~351 */}

              {/* Blue (Underweight) 0 to 14% */}
              <path d="M 16 128 A 112 112 0 0 1 240 128" fill="none" stroke="#60a5fa" strokeWidth="24" strokeLinecap="round" 
                strokeDasharray="49 302" strokeDashoffset="0" />

              {/* Green (Fit) 14% to 40% (length 91) */}
              <path d="M 16 128 A 112 112 0 0 1 240 128" fill="none" stroke="#a3e635" strokeWidth="24" strokeLinecap="round" 
                strokeDasharray="91 260" strokeDashoffset="-49" />

              {/* Yellow (Overweight) 40% to 60% (length 70) */}
              <path d="M 16 128 A 112 112 0 0 1 240 128" fill="none" stroke="#eab308" strokeWidth="24" strokeLinecap="round" 
                strokeDasharray="70 281" strokeDashoffset="-140" />

              {/* Red (Obese) 60% to 100% (length 141) */}
              <path d="M 16 128 A 112 112 0 0 1 240 128" fill="none" stroke="#ef4444" strokeWidth="24" strokeLinecap="round" 
                strokeDasharray="141 210" strokeDashoffset="-210" />

           </svg>
           {/* Needle */}
           <div 
             className="absolute bottom-0 left-1/2 w-1 h-32 bg-white origin-bottom transition-transform duration-700 ease-out z-10"
             style={{ transform: `translateX(-50%) rotate(${getNeedleRotation()}deg)` }}
           >
             <div className="w-4 h-4 bg-white rounded-full absolute bottom-0 left-1/2 -translate-x-1/2 shadow-[0_0_10px_white]"></div>
           </div>
        </div>

        <div className="text-center z-10">
           <span className="text-5xl font-bold tracking-tighter block">{bmi}</span>
           <span className={`text-lg font-bold uppercase tracking-widest ${getStatusColor()}`}>{status}</span>
        </div>
      </div>

      {/* Interactive Inputs */}
      <div className="space-y-8 mt-4">
        {/* Height Slider */}
        <div className="glass-panel p-4 rounded-2xl">
           <div className="flex justify-between mb-2">
             <span className="text-gray-400 text-xs uppercase">Height</span>
             <span className="text-white font-bold">{metrics.height} cm</span>
           </div>
           <input 
             type="range" 
             min="140" 
             max="220" 
             value={metrics.height} 
             onChange={(e) => setMetrics({...metrics, height: parseInt(e.target.value)})}
             className="w-full h-2 bg-gray-800 rounded-lg appearance-none cursor-pointer accent-luxury-neon"
           />
           <div className="w-full h-4 mt-2 ruler-bg opacity-30"></div>
        </div>

        {/* Weight Slider */}
        <div className="glass-panel p-4 rounded-2xl">
           <div className="flex justify-between mb-2">
             <span className="text-gray-400 text-xs uppercase">Weight</span>
             <span className="text-white font-bold">{metrics.weight} kg</span>
           </div>
           <input 
             type="range" 
             min="40" 
             max="150" 
             value={metrics.weight} 
             onChange={(e) => setMetrics({...metrics, weight: parseInt(e.target.value)})}
             className="w-full h-2 bg-gray-800 rounded-lg appearance-none cursor-pointer accent-luxury-gold"
           />
           <div className="w-full h-4 mt-2 ruler-bg opacity-30"></div>
        </div>
      </div>

      {/* Advice */}
      <div className="p-4 border border-white/10 rounded-xl bg-white/5">
         <p className="text-sm text-gray-300 leading-relaxed">
           <span className="text-luxury-neon font-bold">Pro Tip: </span>
           {status === 'Fit' 
             ? "You are in the optimal zone. Focus on strength training to maintain muscle density." 
             : status === 'Overweight' 
             ? "Increase daily steps by 2,000 and reduce carb intake by 15% to reach the Green Zone."
             : status === 'Underweight'
             ? "Consider increasing caloric surplus with protein-rich foods to build mass."
             : "Consult a nutrition specialist for a personalized roadmap to the Green Zone."}
         </p>
      </div>
    </div>
  );
};

