import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import { ViewState, ActivityData, FoodHistoryItem } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  // Real Sensor Hook
  const { isTracking, toggleTracking, liveSteps, resetLiveSteps } = usePedometer();

  // Persistent State for Activity Data
  const [activityData, setActivityData] = useLocalStorage<ActivityData>('activity_data', {
    steps: 0,
    calories: 0,
    distance: 0,
    stepGoal: 10000,
    calorieGoal: 800,
    distanceGoal: 5.0,
    history: [
      { day: 'Mon', steps: 0 },
      { day: 'Tue', steps: 0 },
      { day: 'Wed', steps: 0 },
      { day: 'Thu', steps: 0 },
      { day: 'Fri', steps: 0 },
      { day: 'Sat', steps: 0 },
      { day: 'Sun', steps: 0 },
    ]
  });

  // Persistent State for Food History
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);

  // Update Activity Data based on Real Sensors
  useEffect(() => {
    if (liveSteps > 0) {
      setActivityData(prev => {
        // Average stats: 0.04 kcal/step, 0.00076 km/step (76cm stride)
        const addedCalories = 0.04;
        const addedDistance = 0.00076;

        const updatedHistory = [...prev.history];
        // Assume 'Sun' is today/current bucket for simplicity in this structure
        const todayIndex = 6; 
        updatedHistory[todayIndex] = {
           ...updatedHistory[todayIndex],
           steps: updatedHistory[todayIndex].steps + 1
        };

        return {
          ...prev,
          steps: prev.steps + 1,
          calories: prev.calories + addedCalories,
          distance: prev.distance + addedDistance,
          history: updatedHistory
        };
      });
      // Reset live counter so we don't double count, since we integrated it into persistent state
      resetLiveSteps();
    }
  }, [liveSteps, setActivityData, resetLiveSteps]);

  const handleAddToHistory = (item: FoodHistoryItem) => {
    setFoodHistory(prev => [item, ...prev]);
    // Also update dashboard calories
    setActivityData(prev => ({
      ...prev,
      calories: prev.calories + item.analysis.macros.calories
    }));
  };

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => {
    setActivityData(prev => ({ ...prev, ...newGoals }));
  };

  const renderView = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return (
          <Dashboard 
            data={activityData} 
            onUpdateGoals={handleUpdateGoals} 
            isTracking={isTracking}
            onToggleTracking={toggleTracking}
          />
        );
      case ViewState.FOOD_LENS:
        return <FoodLens history={foodHistory} onAddToHistory={handleAddToHistory} />;
      case ViewState.BMI_HUB:
        return <BMIHub />;
      default:
        return (
          <Dashboard 
            data={activityData} 
            onUpdateGoals={handleUpdateGoals} 
            isTracking={isTracking}
            onToggleTracking={toggleTracking}
          />
        );
    }
  };

  return (
    <div className="min-h-screen bg-black text-white relative overflow-hidden font-sans selection:bg-luxury-neon selection:text-black">
      {/* Ambient Background Glows */}
      <div className="fixed top-[-10%] right-[-10%] w-[50vh] h-[50vh] bg-luxury-neon/5 rounded-full blur-[100px] pointer-events-none z-0"></div>
      <div className="fixed bottom-[-10%] left-[-10%] w-[40vh] h-[40vh] bg-luxury-gold/5 rounded-full blur-[80px] pointer-events-none z-0"></div>

      {/* Main Content Area */}
      <main className="relative z-10 h-screen overflow-y-auto no-scrollbar">
        {renderView()}
      </main>

      {/* Navigation */}
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

