import React, { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';

interface DialControlProps {
  value: number;
  min: number;
  max: number;
  step: number;
  onChange: (val: number) => void;
  label: string;
  unit: string;
  color: string;
}

const DialControl: React.FC<DialControlProps> = ({ value, min, max, step, onChange, label, unit, color }) => {
  const dialRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [angle, setAngle] = useState(0);

  // Convert value to angle (-135 to 135 deg)
  useEffect(() => {
    const percentage = (value - min) / (max - min);
    setAngle(-135 + (percentage * 270));
  }, [value, min, max]);

  const handleInteraction = (clientX: number, clientY: number) => {
    if (!dialRef.current) return;
    const rect = dialRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;

    // Calculate angle from center
    const deltaX = clientX - centerX;
    const deltaY = clientY - centerY;
    let deg = Math.atan2(deltaY, deltaX) * (180 / Math.PI);

    // Normalize to our dial orientation (roughly 90deg is bottom)
    // We want -135 (bottom left) to 135 (bottom right)
    // Rotation logic correction for better UX
    deg = deg + 90; 
    if (deg > 180) deg -= 360;

    // Clamp
    const clampedDeg = Math.max(-135, Math.min(135, deg));

    // Convert back to value
    const percentage = (clampedDeg + 135) / 270;
    let newValue = min + (percentage * (max - min));

    // Round to step
    newValue = Math.round(newValue / step) * step;

    if (newValue !== value) {
      onChange(newValue);
      // Haptics
      if (navigator.vibrate) navigator.vibrate(5);
    }
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    handleInteraction(e.clientX, e.clientY);
  };

  const handleMouseMove = (e: MouseEvent) => {
    if (isDragging) {
      handleInteraction(e.clientX, e.clientY);
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  // Touch support
  const handleTouchStart = (e: React.TouchEvent) => {
    setIsDragging(true);
    handleInteraction(e.touches[0].clientX, e.touches[0].clientY);
  };

  const handleTouchMove = (e: TouchEvent) => {
    if (isDragging) {
      e.preventDefault(); // Prevent scrolling while adjusting
      handleInteraction(e.touches[0].clientX, e.touches[0].clientY);
    }
  };

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      // @ts-ignore
      window.addEventListener('touchmove', handleTouchMove, { passive: false });
      window.addEventListener('touchend', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      // @ts-ignore
      window.removeEventListener('touchmove', handleTouchMove);
      window.removeEventListener('touchend', handleMouseUp);
    };
  }, [isDragging]);

  return (
    <div className="flex flex-col items-center justify-center p-4">
      <div 
        className="relative w-48 h-48 flex items-center justify-center cursor-pointer touch-none"
        ref={dialRef}
        onMouseDown={handleMouseDown}
        onTouchStart={handleTouchStart}
      >
        {/* Track SVG */}
        <svg className="absolute w-full h-full pointer-events-none" viewBox="0 0 200 200">
           {/* Background Track */}
           <path 
             d="M 40 170 A 90 90 0 1 1 160 170" 
             fill="none" 
             stroke="#333" 
             strokeWidth="8" 
             strokeLinecap="round" 
           />
           {/* Active Track */}
           <motion.path 
             d="M 40 170 A 90 90 0 1 1 160 170" 
             fill="none" 
             stroke={color} 
             strokeWidth="8" 
             strokeLinecap="round" 
             strokeDasharray="400"
             strokeDashoffset={400 - (400 * ((angle + 135) / 270))}
             transition={{ type: "spring", stiffness: 300, damping: 30 }}
           />
        </svg>

        {/* Knob */}
        <motion.div 
           className="w-32 h-32 rounded-full glass-panel shadow-2xl flex items-center justify-center border border-white/10 relative"
           animate={{ rotate: angle }}
           transition={{ type: "spring", stiffness: 300, damping: 30 }}
        >
           <div className="absolute top-2 w-2 h-4 rounded-full bg-white shadow-[0_0_10px_white]"></div>
        </motion.div>

        {/* Center Text (Does not rotate) */}
        <div className="absolute flex flex-col items-center justify-center pointer-events-none">
           <span className="text-3xl font-bold tracking-tighter drop-shadow-lg">{value.toLocaleString()}</span>
           <span className="text-xs uppercase text-gray-400 font-bold tracking-widest">{unit}</span>
        </div>
      </div>
      <p className="mt-2 text-sm text-gray-500 font-semibold">{label}</p>
    </div>
  );
};

export default DialControl;

