import React, { useEffect, useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, Tooltip as RechartsTooltip } from 'recharts';
import { motion, AnimatePresence } from 'framer-motion';
import { ActivityData } from '../types';
import { Flame, Footprints, MapPin, Settings, CheckCircle2, Play, Pause, X } from 'lucide-react';
import DialControl from './DialControl';

interface DashboardProps {
  data: ActivityData;
  onUpdateGoals: (newGoals: Partial<ActivityData>) => void;
  isTracking: boolean;
  onToggleTracking: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ data, onUpdateGoals, isTracking, onToggleTracking }) => {
  const [isEditing, setIsEditing] = useState(false);

  // Confetti trigger & Haptics
  const goalReached = data.steps >= data.stepGoal;

  useEffect(() => {
    if (goalReached && navigator.vibrate) {
      navigator.vibrate([100, 50, 100]);
    }
  }, [goalReached]);

  // Data for Rings
  const stepsData = [
    { name: 'Completed', value: Math.min(data.steps, data.stepGoal) },
    { name: 'Remaining', value: Math.max(0, data.stepGoal - data.steps) },
  ];
  const calsData = [
    { name: 'Completed', value: data.calories },
    { name: 'Remaining', value: Math.max(0, data.calorieGoal - data.calories) },
  ];
  const distData = [
    { name: 'Completed', value: data.distance },
    { name: 'Remaining', value: Math.max(0, data.distanceGoal - data.distance) },
  ];

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.95 }}
      transition={{ duration: 0.5 }}
      className="h-full w-full flex flex-col p-6 pt-12 space-y-6 pb-24 relative"
    >
      {/* Background Ambient Glows */}
      <div className="absolute top-20 right-0 w-64 h-64 bg-luxury-neon/10 rounded-full blur-[80px] pointer-events-none"></div>

      {/* Header */}
      <div className="flex justify-between items-center z-10">
        <div>
          <motion.h2 layoutId="header-subtitle" className="text-sm font-semibold text-gray-400 uppercase tracking-widest">Today's Activity</motion.h2>
          <motion.h1 layoutId="header-title" className="text-3xl font-bold text-white mt-1">
            Keep Moving <span className="text-luxury-neon">.</span>
          </motion.h1>
        </div>
        <motion.button 
          whileTap={{ scale: 0.9 }}
          onClick={() => setIsEditing(true)}
          className="h-10 w-10 rounded-full flex items-center justify-center bg-white/10 text-white backdrop-blur-md"
        >
          <Settings size={20} />
        </motion.button>
      </div>

      {/* Goal Editing Modal Overlay */}
      <AnimatePresence>
        {isEditing && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black/80 backdrop-blur-xl flex flex-col items-center justify-center p-6"
          >
            <motion.button 
              onClick={() => setIsEditing(false)}
              className="absolute top-6 right-6 p-2 bg-white/10 rounded-full text-white"
            >
              <X size={24} />
            </motion.button>

            <h2 className="text-2xl font-bold mb-8">Set Your Goals</h2>

            <div className="flex flex-col gap-8 w-full max-w-sm">
               <DialControl 
                 value={data.stepGoal} 
                 min={1000} 
                 max={20000} 
                 step={500} 
                 color="#a3e635" 
                 label="Daily Steps Target"
                 unit="STEPS"
                 onChange={(val) => onUpdateGoals({ stepGoal: val })}
               />

               <DialControl 
                 value={data.calorieGoal} 
                 min={200} 
                 max={4000} 
                 step={50} 
                 color="#eab308" 
                 label="Daily Calorie Target"
                 unit="KCAL"
                 onChange={(val) => onUpdateGoals({ calorieGoal: val })}
               />
            </div>

            <motion.button
              whileTap={{ scale: 0.95 }}
              onClick={() => setIsEditing(false)}
              className="mt-12 px-8 py-3 bg-white text-black font-bold rounded-full"
            >
              Save Changes
            </motion.button>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Tracking Control */}
      <motion.button 
        layout
        whileTap={{ scale: 0.98 }}
        onClick={onToggleTracking}
        className={`w-full py-4 rounded-2xl flex items-center justify-center gap-2 font-bold transition-all shadow-lg ${isTracking ? 'bg-red-500/10 text-red-500 border border-red-500/20' : 'bg-gradient-to-r from-luxury-neon/20 to-luxury-neon/5 text-luxury-neon border border-luxury-neon/20'}`}
      >
          {isTracking ? (
            <>
              <span className="relative flex h-3 w-3 mr-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
              </span>
              <Pause size={18} /> Stop Tracking
            </>
          ) : (
            <>
              <Play size={18} /> Start Live Tracking
            </>
          )}
      </motion.button>

      {/* Rings Container */}
      <motion.div 
        layoutId="rings-container"
        className="relative w-full h-72 flex items-center justify-center glass-panel rounded-3xl overflow-hidden shrink-0 shadow-[0_10px_40px_rgba(0,0,0,0.5)]"
      >
        {goalReached && (
          <div className="absolute inset-0 bg-luxury-neon/5 animate-pulse z-0 pointer-events-none" />
        )}

        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie data={stepsData} cx="50%" cy="50%" innerRadius={100} outerRadius={115} startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={10}>
              <Cell key="cell-0" fill="#a3e635" />
              <Cell key="cell-1" fill="#222" />
            </Pie>
            <Pie data={calsData} cx="50%" cy="50%" innerRadius={75} outerRadius={90} startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={10}>
              <Cell key="cell-0" fill="#eab308" />
              <Cell key="cell-1" fill="#222" />
            </Pie>
            <Pie data={distData} cx="50%" cy="50%" innerRadius={50} outerRadius={65} startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={10}>
              <Cell key="cell-0" fill="#ef4444" />
              <Cell key="cell-1" fill="#222" />
            </Pie>
          </PieChart>
        </ResponsiveContainer>

        <div className="absolute flex flex-col items-center justify-center z-10 pointer-events-none">
          <Footprints className="text-luxury-neon mb-1" size={20} />
          <motion.span 
             key={data.steps}
             initial={{ scale: 1.2, color: '#fff' }}
             animate={{ scale: 1, color: '#fff' }}
             className="text-4xl font-bold tracking-tighter"
          >
            {data.steps.toLocaleString()}
          </motion.span>
          <span className="text-xs text-gray-500 uppercase tracking-widest mt-1">Steps</span>
        </div>
      </motion.div>

      {/* Detailed Grid */}
      <div className="grid grid-cols-2 gap-4 shrink-0">
        <motion.div whileHover={{ scale: 1.02 }} className="glass-panel p-4 rounded-2xl flex flex-col justify-between h-32 hover:bg-white/5 transition-colors relative overflow-hidden group">
          <div className="absolute -right-4 -top-4 w-20 h-20 bg-luxury-gold/10 rounded-full blur-xl group-hover:bg-luxury-gold/20 transition-all"></div>
          <div className="flex justify-between items-start z-10">
            <Flame className="text-luxury-gold" size={20} />
            <span className="text-xs text-gray-500">KCAL</span>
          </div>
          <div className="z-10">
             <span className="text-3xl font-bold block">{Math.floor(data.calories)}</span>
             <span className="text-xs text-gray-400">Target: {data.calorieGoal}</span>
          </div>
        </motion.div>

        <motion.div whileHover={{ scale: 1.02 }} className="glass-panel p-4 rounded-2xl flex flex-col justify-between h-32 hover:bg-white/5 transition-colors relative overflow-hidden group">
          <div className="absolute -right-4 -top-4 w-20 h-20 bg-red-500/10 rounded-full blur-xl group-hover:bg-red-500/20 transition-all"></div>
          <div className="flex justify-between items-start z-10">
            <MapPin className="text-red-500" size={20} />
            <span className="text-xs text-gray-500">KM</span>
          </div>
          <div className="z-10">
             <span className="text-3xl font-bold block">{data.distance.toFixed(2)}</span>
             <span className="text-xs text-gray-400">Target: {data.distanceGoal}km</span>
          </div>
        </motion.div>
      </div>

      {/* History Chart */}
      <div className="glass-panel p-4 rounded-3xl flex-1 flex flex-col">
        <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-widest mb-4">Last 7 Days</h3>
        <div className="w-full h-full min-h-[120px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data.history}>
              <XAxis dataKey="day" axisLine={false} tickLine={false} tick={{ fill: '#666', fontSize: 10 }} dy={10} />
              <RechartsTooltip cursor={{fill: 'rgba(255,255,255,0.05)'}} contentStyle={{ backgroundColor: '#121212', borderColor: '#333', borderRadius: '8px' }} itemStyle={{ color: '#fff' }} />
              <Bar dataKey="steps" fill="#333" activeBar={{ fill: '#a3e635' }} radius={[4, 4, 4, 4]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </motion.div>
  );
};

export default Dashboard;

