import { useState, useEffect, useRef } from 'react';

interface PedometerHook {
  isTracking: boolean;
  toggleTracking: () => Promise<void>;
  permissionGranted: boolean;
  liveSteps: number;
  resetLiveSteps: () => void;
  status: 'Idle' | 'Active' | 'Walking';
}

const usePedometer = (): PedometerHook => {
  const [isTracking, setIsTracking] = useState(false);
  const [permissionGranted, setPermissionGranted] = useState(false);
  const [liveSteps, setLiveSteps] = useState(0);
  const [status, setStatus] = useState<'Idle' | 'Active' | 'Walking'>('Idle');

  const wakeLock = useRef<WakeLockSentinel | null>(null);

  // Algorithm State
  const lastGrav = useRef({ x: 0, y: 0, z: 0 });
  const lastStepTime = useRef(0);
  const lastMotionTime = useRef(0);

  // Constants
  // Alpha for Low Pass Filter (isolating gravity). Higher = slower adaptation to orientation change.
  const ALPHA = 0.8; 
  // Threshold for step detection in m/s^2 (Linear Acceleration). 
  // 1.2 is a good balance for walking vs handling phone.
  const THRESHOLD = 1.2; 
  const MIN_STEP_DELAY = 300; // ms (limits to ~3.3 steps/sec max)
  const IDLE_TIMEOUT = 2000; // ms before switching status to Idle

  const requestWakeLock = async () => {
    if ('wakeLock' in navigator) {
      try {
        wakeLock.current = await navigator.wakeLock.request('screen');
      } catch (err) {
        console.warn('Wake Lock request failed:', err);
      }
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLock.current) {
      await wakeLock.current.release();
      wakeLock.current = null;
    }
  };

  const handleMotion = (event: DeviceMotionEvent) => {
    let x = 0, y = 0, z = 0;
    let usingHardwareGravity = false;

    // 1. Try to use hardware-provided linear acceleration (gravity removed)
    if (event.acceleration && event.acceleration.x !== null) {
      x = event.acceleration.x;
      y = event.acceleration.y || 0;
      z = event.acceleration.z || 0;
      usingHardwareGravity = true;
    } 
    // 2. Fallback: Calculate linear acceleration manually from accelerationIncludingGravity
    else if (event.accelerationIncludingGravity && event.accelerationIncludingGravity.x !== null) {
      const gx = event.accelerationIncludingGravity.x;
      const gy = event.accelerationIncludingGravity.y || 0;
      const gz = event.accelerationIncludingGravity.z || 0;

      // Simple Low-Pass Filter to estimate gravity component
      lastGrav.current.x = ALPHA * lastGrav.current.x + (1 - ALPHA) * gx;
      lastGrav.current.y = ALPHA * lastGrav.current.y + (1 - ALPHA) * gy;
      lastGrav.current.z = ALPHA * lastGrav.current.z + (1 - ALPHA) * gz;

      // High-Pass Filter: Remove gravity to get user motion
      x = gx - lastGrav.current.x;
      y = gy - lastGrav.current.y;
      z = gz - lastGrav.current.z;
    } else {
      return; // No sensor data available
    }

    // 3. Calculate Magnitude of User Force
    const mag = Math.sqrt(x*x + y*y + z*z);
    const now = Date.now();

    // 4. Update Status based on general motion noise
    if (mag > 0.5) {
      lastMotionTime.current = now;
      if (status === 'Idle') setStatus('Active');
    }

    // 5. Step Detection
    if (mag > THRESHOLD) {
      if (now - lastStepTime.current > MIN_STEP_DELAY) {
        setLiveSteps(prev => prev + 1);
        lastStepTime.current = now;
        setStatus('Walking');

        // Very subtle haptic click for confirmation if desired (can be battery intensive)
        // if (navigator.vibrate) navigator.vibrate(5);
      }
    }

    // 6. Reset Status to Active/Idle if no steps recently
    if (now - lastStepTime.current > IDLE_TIMEOUT) {
       setStatus(Date.now() - lastMotionTime.current < IDLE_TIMEOUT ? 'Active' : 'Idle');
    }
  };

  const requestPermission = async (): Promise<boolean> => {
    // iOS 13+ requires explicit permission
    // @ts-ignore
    if (typeof DeviceMotionEvent !== 'undefined' && typeof DeviceMotionEvent.requestPermission === 'function') {
      try {
        // @ts-ignore
        const permissionState = await DeviceMotionEvent.requestPermission();
        return permissionState === 'granted';
      } catch (e) {
        console.error(e);
        return false;
      }
    }
    return true; // Non-iOS devices usually don't need explicit permission if served over HTTPS
  };

  const toggleTracking = async () => {
    if (isTracking) {
      window.removeEventListener('devicemotion', handleMotion);
      releaseWakeLock();
      setIsTracking(false);
      setStatus('Idle');
    } else {
      const granted = await requestPermission();
      if (granted) {
        setPermissionGranted(true);
        window.addEventListener('devicemotion', handleMotion);
        requestWakeLock(); // Keep screen on
        setIsTracking(true);
        setStatus('Active');
      } else {
        alert("Motion sensor permission is required to count steps.");
      }
    }
  };

  // Re-acquire wake lock if visibility changes (e.g. user switches tabs and comes back)
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible' && isTracking) {
        requestWakeLock();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [isTracking]);

  // Cleanup
  useEffect(() => {
    return () => {
      window.removeEventListener('devicemotion', handleMotion);
      releaseWakeLock();
    };
  }, []);

  const resetLiveSteps = () => setLiveSteps(0);

  return { isTracking, toggleTracking, permissionGranted, liveSteps, resetLiveSteps, status };
};

export default usePedometer;

import React, { useEffect, useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, Tooltip as RechartsTooltip } from 'recharts';
import { motion, AnimatePresence } from 'framer-motion';
import { ActivityData } from '../types';
import { Flame, Footprints, MapPin, Settings, CheckCircle2, Play, Pause, X, Activity } from 'lucide-react';
