import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { FoodAnalysis, UserMetrics, ActivityData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING },
    macros: {
      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      }
    },
    healthScore: { type: Type.NUMBER },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] },
    boundingBox: {
      type: Type.ARRAY,
      items: { type: Type.NUMBER },
      description: "Bounding box of the food item in [ymin, xmin, ymax, xmax] format (normalized 0-1)."
    }
  }
};

export const analyzeFoodImage = async (base64Image: string): Promise<FoodAnalysis> => {
  try {
    const prompt = `Analyze this food image. Identify the item, estimate nutrition per serving, and provide the bounding box [ymin, xmin, ymax, xmax] of the main food item.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] 
            }
          },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("No response from AI");

  } catch (error) {
    console.error("Gemini Image Error:", error);
    return getErrorFallback();
  }
};

export const analyzeFoodText = async (query: string): Promise<FoodAnalysis> => {
  try {
    const prompt = `Analyze the food item described as: "${query}". Estimate nutrition per serving.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("No response from AI");
  } catch (error) {
    console.error("Gemini Text Error:", error);
    return getErrorFallback();
  }
};

export const getCoachChatStream = async (
  message: string, 
  history: { role: 'user' | 'model', parts: { text: string }[] }[],
  metrics: UserMetrics,
  activity: ActivityData
) => {
  const systemInstruction = `You are the Healthy.hub Elite Coach. 
  User Metrics: Height ${metrics.height}cm, Weight ${metrics.weight}kg.
  Today's Progress: ${activity.steps} steps, ${activity.calories.toFixed(0)} kcal burned.

  Your goal is to provide luxury fitness advice. 
  When asked for a diet plan: Give a professional, balanced, and premium meal structure.
  When asked for a workout: Tailor it to their body conditions and specific equipment they mention.
  Be motivating, concise, and use a sophisticated tone.`;

  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: systemInstruction,
      temperature: 0.7,
    },
    history: history,
  });

  return await chat.sendMessageStream({ message });
};

const getErrorFallback = (): FoodAnalysis => ({
  name: "Analysis Failed",
  macros: { calories: 0, protein: 0, fat: 0, carbs: 0 },
  healthScore: 0,
  verdict: "Avoid",
  advice: "Could not identify food. Please try again.",
  colorCode: "red"
});

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, User, Bot, Sparkles, Loader2 } from 'lucide-react';
import { getCoachChatStream } from '../services/geminiService';
import { ChatMessage, UserMetrics, ActivityData } from '../types';

interface ChatBotProps {
  metrics: UserMetrics;
  activity: ActivityData;
}

const ChatBot: React.FC<ChatBotProps> = ({ metrics, activity }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const stream = await getCoachChatStream(input, history, metrics, activity);

      let coachMessageId = (Date.now() + 1).toString();
      let coachText = '';

      setMessages(prev => [...prev, {
        id: coachMessageId,
        role: 'model',
        text: '',
        timestamp: Date.now(),
      }]);

      for await (const chunk of stream) {
        coachText += chunk.text || '';
        setMessages(prev => prev.map(m => 
          m.id === coachMessageId ? { ...m, text: coachText } : m
        ));
      }
    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, {
        id: 'error',
        role: 'model',
        text: "I apologize, my elite connection is flickering. Please try again in a moment.",
        timestamp: Date.now(),
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="h-full w-full flex flex-col bg-black animate-fade-in relative overflow-hidden">
      {/* Background Decorative Element */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-32 bg-gradient-to-b from-luxury-neon/5 to-transparent pointer-events-none"></div>

      {/* Header */}
      <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 backdrop-blur-md">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-luxury-neon/20 flex items-center justify-center border border-luxury-neon/30 shadow-[0_0_15px_rgba(163,230,53,0.2)]">
            <Sparkles className="text-luxury-neon" size={20} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-white">Coach Gemini</h1>
            <p className="text-[10px] text-luxury-neon uppercase tracking-widest font-bold">Elite Performance AI</p>
          </div>
        </div>
      </div>

      {/* Messages */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar pb-32"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-60 px-8">
            <Bot size={48} className="text-luxury-gold" />
            <p className="text-gray-400">Welcome. I am your elite fitness consultant. How may I optimize your performance today?</p>
            <div className="flex flex-wrap gap-2 justify-center">
              {["Diet Plan", "Workout Plan", "Analysis"].map(tag => (
                <button 
                  key={tag}
                  onClick={() => setInput(`Give me an elite ${tag.toLowerCase()}`)}
                  className="px-3 py-1 rounded-full border border-white/10 text-xs text-gray-400 hover:border-luxury-neon hover:text-luxury-neon transition-colors"
                >
                  {tag}
                </button>
              ))}
            </div>
          </div>
        )}

        <AnimatePresence>
          {messages.map((msg) => (
            <motion.div
              key={msg.id}
              initial={{ opacity: 0, y: 10, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div className={`max-w-[85%] p-4 rounded-2xl relative ${
                msg.role === 'user' 
                  ? 'bg-luxury-neon/10 border border-luxury-neon/20 text-white rounded-br-none' 
                  : 'glass-panel border-l-2 border-l-luxury-gold text-gray-200 rounded-bl-none'
              }`}>
                {msg.role === 'model' && (
                  <div className="flex items-center gap-2 mb-2">
                    <Sparkles size={12} className="text-luxury-gold" />
                    <span className="text-[10px] font-bold text-luxury-gold uppercase tracking-tighter">Coach</span>
                  </div>
                )}
                <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.text}</p>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>

        {isTyping && messages[messages.length-1]?.role !== 'model' && (
          <div className="flex justify-start">
            <div className="glass-panel p-4 rounded-2xl animate-pulse">
              <Loader2 className="animate-spin text-luxury-gold" size={20} />
            </div>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="fixed bottom-24 left-4 right-4 z-20">
        <form 
          onSubmit={handleSend}
          className="glass-panel p-2 rounded-full border border-white/10 focus-within:border-luxury-neon/50 transition-all flex items-center shadow-2xl"
        >
          <input 
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask your coach anything..."
            className="flex-1 bg-transparent border-none outline-none px-4 text-sm text-white placeholder-gray-500"
          />
          <motion.button
            whileTap={{ scale: 0.9 }}
            type="submit"
            disabled={!input.trim() || isTyping}
            className="w-10 h-10 rounded-full bg-luxury-neon text-black flex items-center justify-center disabled:opacity-50"
          >
            <Send size={18} />
          </motion.button>
        </form>
      </div>
    </div>
  );
};

