  history: FoodHistoryItem[];
  onAddToHistory: (item: FoodHistoryItem) => void;
}

const FoodLens: React.FC<FoodLensProps> = ({ history, onAddToHistory }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<FoodAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [manualQuery, setManualQuery] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isFlashOn, setIsFlashOn] = useState(false);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }
      });
      setStream(mediaStream);
      if (videoRef.current) videoRef.current.srcObject = mediaStream;
    } catch (err) {
      setError("Camera access is required for AI Vision.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    if (!showHistory && !result) startCamera();
    else stopCamera();
    return () => stopCamera();
  }, [showHistory, result]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || analyzing) return;
    setAnalyzing(true);

    const video = videoRef.current;
    const canvas = canvasRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');

    if (ctx) {
      ctx.drawImage(video, 0, 0);
      const base64 = canvas.toDataURL('image/jpeg', 0.8);
      try {
        const data = await analyzeFoodImage(base64);
        onAddToHistory({ id: Date.now().toString(), timestamp: Date.now(), analysis: data });
        setResult(data);
        if (navigator.vibrate) navigator.vibrate(50);
      } catch (err) {
        setError("AI Analysis failed. Please try again.");
      } finally {
        setAnalyzing(false);
      }
    }
  };

  const getColorClass = (code: string) => {
    switch(code) {
      case 'green': return 'text-luxury-neon border-luxury-neon';
      case 'yellow': return 'text-luxury-gold border-luxury-gold';
      case 'red': return 'text-red-500 border-red-500';
      default: return 'text-white border-white';
    }
  };

  if (showHistory) {
    return (
      <div className="h-full w-full flex flex-col p-6 pt-12">
        <div className="flex items-center gap-4 mb-8">
          <button onClick={() => setShowHistory(false)} className="bg-white/10 p-2 rounded-full"><ArrowLeft /></button>
          <h1 className="text-2xl font-bold">Food Log</h1>
        </div>
        <div className="flex-1 overflow-y-auto space-y-4 pb-24 no-scrollbar">
          {history.length === 0 ? <p className="text-center text-gray-500 mt-20">No items tracked.</p> : history.map(item => (
            <div key={item.id} className="glass-panel p-4 rounded-2xl flex justify-between items-center">
              <div>
                <h3 className="font-bold">{item.analysis.name}</h3>
                <p className="text-xs text-gray-500">{new Date(item.timestamp).toLocaleTimeString()}</p>
              </div>
              <div className="text-right">
                <span className="block font-bold text-luxury-neon">{item.analysis.macros.calories} kcal</span>
                <span className="text-[10px] uppercase text-gray-400">{item.analysis.verdict}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (result) {
    return (
      <div className="h-full w-full flex flex-col p-6 pt-12">
        <div className={`glass-panel p-6 rounded-[32px] border-l-4 ${getColorClass(result.colorCode)} mt-10`}>
          <div className="flex justify-between items-start mb-6">
            <h2 className="text-3xl font-bold">{result.name}</h2>
            <div className="text-right">
              <span className="text-4xl font-bold block">{result.macros.calories}</span>
              <span className="text-xs text-gray-500 uppercase">Calories</span>
            </div>
          </div>
          <div className="grid grid-cols-3 gap-3 mb-6">
            <div className="bg-white/5 p-3 rounded-2xl text-center">
              <span className="block font-bold text-luxury-neon">{result.macros.protein}g</span>
              <span className="text-[10px] text-gray-400">PROT</span>
            </div>
            <div className="bg-white/5 p-3 rounded-2xl text-center">
              <span className="block font-bold text-luxury-gold">{result.macros.fat}g</span>
              <span className="text-[10px] text-gray-400">FAT</span>
            </div>
            <div className="bg-white/5 p-3 rounded-2xl text-center">
              <span className="block font-bold text-blue-400">{result.macros.carbs}g</span>
              <span className="text-[10px] text-gray-400">CARB</span>
            </div>
          </div>
          <p className="text-sm italic text-gray-300 bg-white/5 p-4 rounded-2xl">"{result.advice}"</p>
        </div>
        <button onClick={() => setResult(null)} className="mt-auto mb-24 w-full py-4 bg-luxury-neon text-black font-bold rounded-full">Scan New Item</button>
      </div>
    );
  }

  return (
    <div className="h-full w-full relative bg-black">
      <canvas ref={canvasRef} className="hidden" />
      <div className="absolute inset-0">
        {stream ? <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" /> : <div className="h-full w-full flex items-center justify-center text-gray-600">Initializing AI...</div>}
      </div>
      <div className="absolute inset-0 flex flex-col justify-between p-6 pointer-events-none">
        <div className="flex justify-between items-center pointer-events-auto pt-8">
          <button onClick={() => setShowHistory(true)} className="glass-panel w-12 h-12 rounded-full flex items-center justify-center"><History /></button>
          <div className="bg-black/40 px-4 py-1 rounded-full border border-luxury-neon/50"><span className="text-luxury-neon text-[10px] font-bold animate-pulse">AI VISION ACTIVE</span></div>
          <div className="w-12"></div>
        </div>
        <div className="pb-24 pointer-events-auto">
          <button onClick={captureAndAnalyze} disabled={analyzing} className="w-full py-5 rounded-full bg-white text-black font-extrabold text-lg flex items-center justify-center gap-3">
            {analyzing ? <Loader2 className="animate-spin" /> : <Camera size={24} />}
            {analyzing ? "Analyzing Meal..." : "Capture for Analysis"}
          </button>
        </div>
      </div>
    </div>
  );
};

