import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { FoodAnalysis, UserMetrics, ActivityData } from "../types";

// Initialize the Google GenAI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const foodResponseSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "Name of the food item" },
    macros: {
      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      },
      required: ["calories", "protein", "fat", "carbs"]
    },
    healthScore: { type: Type.NUMBER, description: "Score from 0-100" },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING, description: "Short nutritional tip" },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] },
    boundingBox: {
      type: Type.ARRAY,
      items: { type: Type.NUMBER },
      description: "Bounding box in [ymin, xmin, ymax, xmax] format (0-1)."
    }
  },
  required: ["name", "macros", "healthScore", "verdict", "advice", "colorCode"]
};

/**
 * Analyze food image using gemini-2.5-flash for multimodal vision capabilities
 */
export const analyzeFoodImage = async (base64Image: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] 
            }
          },
          { text: "Analyze this meal. Identify ingredients and provide strict nutrition JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: foodResponseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Image Analysis Error:", error);
    return getFallbackAnalysis("Scan failed. Ensure clear image.");
  }
};

/**
 * Analyze food description text
 */
export const analyzeFoodText = async (query: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Estimate nutrition for: ${query}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: foodResponseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Text Analysis Error:", error);
    return getFallbackAnalysis("Manual entry failed.");
  }
};

/**
 * Get the streaming coach chat with strict Professional Trainer behavior.
 */
export const getCoachChatStream = async (
  message: string, 
  history: any[],
  metrics: UserMetrics,
  activity: ActivityData
) => {
  const systemInstruction = `You are the Healthy.hub Elite Professional Trainer.
  Follow these strict rules for every interaction:

  Persona: You are a world-class professional trainer. Your advice is scientifically grounded, elite, and highly personalized.

  Behavior Rules:
  1. FIRST REQUEST HANDLING: When a user asks for a workout or diet plan, DO NOT provide it immediately. First, you MUST ASK: "What equipment do you have available? (e.g., Dumbbells, Gym, Resistance bands, or Bodyweight only?)"
  2. CUSTOMIZATION: Once the user provides details about their available equipment, only then generate a customized, elite-level plan tailored specifically to that equipment and their personal body metrics.
  3. MANDATORY FOOTER: At the end of EVERY SINGLE response you send, you MUST append this exact text on its own separate line:
  "⚠️ Note: Please cross-verify this plan with a certified medical or fitness professional before starting."

  User Profile:
  - Height: ${metrics.height}cm
  - Weight: ${metrics.weight}kg
  - Today's Progress: ${activity.steps} steps

  Current Date: ${new Date().toLocaleDateString()}
  Maintain conversation history to provide contextual continuity.`;

  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: systemInstruction,
      temperature: 0.7,
    },
    history: history,
  });

  return await chat.sendMessageStream({ message });
};

const getFallbackAnalysis = (reason: string): FoodAnalysis => ({
  name: "System Offline",
  macros: { calories: 0, protein: 0, fat: 0, carbs: 0 },
  healthScore: 0,
  verdict: "Avoid",
  advice: reason,
  colorCode: "red"
});

import React, { useRef, useState, useEffect } from 'react';
import { Camera, Zap, X, Search, Keyboard, ZapOff, History, ArrowLeft, Clock, Loader2 } from 'lucide-react';
import { analyzeFoodImage, analyzeFoodText } from '../services/geminiService';
import { FoodAnalysis, FoodHistoryItem } from '../types';

interface FoodLensProps {
  history: FoodHistoryItem[];
  onAddToHistory: (item: FoodHistoryItem) => void;
}

const FoodLens: React.FC<FoodLensProps> = ({ history, onAddToHistory }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<FoodAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showHistory, setShowHistory] = useState(false);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }
      });
      setStream(mediaStream);
    } catch (err) {
      console.error("Camera Error:", err);
      setError("Camera access is required for AI Vision.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    if (!showHistory && !result) {
      startCamera();
    } else {
      stopCamera();
    }
    return () => stopCamera();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showHistory, result]);

  // Fix: Assign stream to video element whenever stream changes and videoRef is ready
  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
      videoRef.current.play().catch(e => console.error("Video play error:", e));
    }
  }, [stream]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || analyzing) return;
    setAnalyzing(true);

    const video = videoRef.current;
    const canvas = canvasRef.current;

    // Ensure canvas dimensions match video
    if (video.videoWidth && video.videoHeight) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;

        const ctx = canvas.getContext('2d');
        if (ctx) {
            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
            const base64 = canvas.toDataURL('image/jpeg', 0.8);
            try {
                const data = await analyzeFoodImage(base64);
                onAddToHistory({ id: Date.now().toString(), timestamp: Date.now(), analysis: data });
                setResult(data);
                if (navigator.vibrate) navigator.vibrate(50);
            } catch (err) {
                console.error(err);
                setError("AI Analysis failed. Please try again.");
            } finally {
                setAnalyzing(false);
            }
        }
    } else {
        setAnalyzing(false);
    }
  };

  const getColorClass = (code: string) => {
    switch(code) {
      case 'green': return 'text-luxury-neon border-luxury-neon';
      case 'yellow': return 'text-luxury-gold border-luxury-gold';
      case 'red': return 'text-red-500 border-red-500';
      default: return 'text-white border-white';
    }
  };

  if (showHistory) {
    return (
      <div className="h-full w-full flex flex-col p-6 pt-12 animate-fade-in">
        <div className="flex items-center gap-4 mb-8">
          <button onClick={() => setShowHistory(false)} className="bg-white/10 p-2 rounded-full hover:bg-white/20 transition-colors"><ArrowLeft /></button>
          <h1 className="text-2xl font-bold">Food Log</h1>
        </div>
        <div className="flex-1 overflow-y-auto space-y-4 pb-24 no-scrollbar">
          {history.length === 0 ? <p className="text-center text-gray-500 mt-20">No items tracked.</p> : history.map(item => (
            <div key={item.id} className="glass-panel p-4 rounded-2xl flex justify-between items-center">
              <div>
                <h3 className="font-bold">{item.analysis.name}</h3>
                <p className="text-xs text-gray-500">{new Date(item.timestamp).toLocaleTimeString()}</p>
              </div>
              <div className="text-right">
                <span className="block font-bold text-luxury-neon">{item.analysis.macros.calories} kcal</span>
                <span className="text-[10px] uppercase text-gray-400">{item.analysis.verdict}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (result) {
    return (
      <div className="h-full w-full flex flex-col p-6 pt-12 animate-fade-in">
        <div className={`glass-panel p-6 rounded-[32px] border-l-4 ${getColorClass(result.colorCode)} mt-10`}>
          <div className="flex justify-between items-start mb-6">
            <h2 className="text-3xl font-bold">{result.name}</h2>
            <div className="text-right">
              <span className="text-4xl font-bold block">{result.macros.calories}</span>
              <span className="text-xs text-gray-500 uppercase">Calories</span>
            </div>
          </div>
          <div className="grid grid-cols-3 gap-3 mb-6">
            <div className="bg-white/5 p-3 rounded-2xl text-center">
              <span className="block font-bold text-luxury-neon">{result.macros.protein}g</span>
              <span className="text-[10px] text-gray-400">PROT</span>
            </div>
            <div className="bg-white/5 p-3 rounded-2xl text-center">
              <span className="block font-bold text-luxury-gold">{result.macros.fat}g</span>
              <span className="text-[10px] text-gray-400">FAT</span>
            </div>
            <div className="bg-white/5 p-3 rounded-2xl text-center">
              <span className="block font-bold text-blue-400">{result.macros.carbs}g</span>
              <span className="text-[10px] text-gray-400">CARB</span>
            </div>
          </div>
          <p className="text-sm italic text-gray-300 bg-white/5 p-4 rounded-2xl">"{result.advice}"</p>
        </div>
        <button onClick={() => setResult(null)} className="mt-auto mb-24 w-full py-4 bg-luxury-neon text-black font-bold rounded-full shadow-lg hover:scale-105 transition-transform">Scan New Item</button>
      </div>
    );
  }

  return (
    <div className="h-full w-full relative bg-black overflow-hidden">
      <canvas ref={canvasRef} className="hidden" />
      <div className="absolute inset-0 z-0">
        {stream ? (
           <video 
             ref={videoRef} 
             autoPlay 
             playsInline 
             muted 
             className="w-full h-full object-cover" 
           />
        ) : (
           <div className="h-full w-full flex items-center justify-center text-gray-600 bg-black">
             {error ? (
                <div className="text-center px-6">
                  <p className="text-red-500 mb-2"><ZapOff className="inline mr-2"/>Camera Unavailable</p>
                  <p className="text-xs">{error}</p>
                </div>
             ) : (
                <div className="flex flex-col items-center">
                  <Loader2 className="animate-spin mb-2" />
                  <span className="text-xs tracking-widest uppercase">Initializing Vision</span>
                </div>
             )}
           </div>
        )}
      </div>

      {/* Overlay UI */}
      <div className="absolute inset-0 flex flex-col justify-between p-6 pointer-events-none z-10">
        <div className="flex justify-between items-center pointer-events-auto pt-8">
          <button onClick={() => setShowHistory(true)} className="glass-panel w-12 h-12 rounded-full flex items-center justify-center hover:bg-white/10 transition-colors"><History size={20}/></button>

          <div className="bg-black/40 backdrop-blur-md px-4 py-1.5 rounded-full border border-luxury-neon/50 shadow-[0_0_15px_rgba(0,230,118,0.3)]">
             <div className="flex items-center gap-2">
               <span className="w-2 h-2 rounded-full bg-luxury-neon animate-pulse"></span>
               <span className="text-luxury-neon text-[10px] font-bold tracking-widest">AI VISION ACTIVE</span>
             </div>
          </div>

          <div className="w-12"></div> {/* Spacer for alignment */}
        </div>

        {/* Scan Frame Guides */}
        <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
           <div className="w-[70%] aspect-square border-2 border-white/20 rounded-3xl relative">
              <div className="absolute top-0 left-0 w-6 h-6 border-t-4 border-l-4 border-luxury-neon rounded-tl-xl"></div>
              <div className="absolute top-0 right-0 w-6 h-6 border-t-4 border-r-4 border-luxury-neon rounded-tr-xl"></div>
              <div className="absolute bottom-0 left-0 w-6 h-6 border-b-4 border-l-4 border-luxury-neon rounded-bl-xl"></div>
              <div className="absolute bottom-0 right-0 w-6 h-6 border-b-4 border-r-4 border-luxury-neon rounded-br-xl"></div>
              <div className="absolute top-1/2 left-0 right-0 h-0.5 bg-luxury-neon/50 animate-scan"></div>
           </div>
        </div>

        <div className="pb-24 pointer-events-auto">
          <button 
            onClick={captureAndAnalyze} 
            disabled={analyzing || !!error} 
            className="w-full py-5 rounded-full bg-white text-black font-extrabold text-lg flex items-center justify-center gap-3 shadow-[0_0_30px_rgba(255,255,255,0.3)] active:scale-95 transition-all disabled:opacity-50 disabled:active:scale-100"
          >
            {analyzing ? <Loader2 className="animate-spin" /> : <Camera size={24} />}
            {analyzing ? "Analyzing Meal..." : "Capture for Analysis"}
          </button>
        </div>
      </div>
    </div>
  );
};

