/**
 * Creates the user document in Firestore upon registration.
 * Path: users/{userId}
 */
export const createUserDocument = async (user: User, name: string) => {
  if (!user) return;

  const userRef = doc(db, 'users', user.uid);
  const snapshot = await getDoc(userRef);

  if (!snapshot.exists()) {
    const defaultData = {
      name: name,
      email: user.email,
      createdAt: Timestamp.now(),
      avatarUrl: `https://api.dicebear.com/7.x/avataaars/svg?seed=${name}&backgroundColor=b6e3f4`,
      goals: {
        stepGoal: 10000,
        calorieGoal: 2000,
        distanceGoal: 5.0
      },
      currentActivity: {
        steps: 0,
        calories: 0,
        distance: 0,
        history: [
            { day: 'Mon', steps: 0 },
            { day: 'Tue', steps: 0 },
            { day: 'Wed', steps: 0 },
            { day: 'Thu', steps: 0 },
            { day: 'Fri', steps: 0 },
            { day: 'Sat', steps: 0 },
            { day: 'Sun', steps: 0 },
        ]
      }
    };

    try {
      await setDoc(userRef, defaultData);
    } catch (error) {
      console.error("Error creating user document", error);
    }
  }
};

/**
 * Listens to the current user's document.
 * Returns an unsubscribe function.
 */
export const subscribeToUserData = (uid: string, onUpdate: (data: any) => void) => {
  return onSnapshot(doc(db, 'users', uid), (doc) => {
    if (doc.exists()) {
      onUpdate(doc.data());
    }
  });
};

/**
 * Updates the user's activity goals or data
 */
export const updateUserActivity = async (uid: string, data: Partial<ActivityData>, goals?: Partial<ActivityData>) => {
    const userRef = doc(db, 'users', uid);
    const updatePayload: any = {};

    if (data) updatePayload['currentActivity'] = data;
    if (goals) updatePayload['goals'] = goals;

    // Note: In a real app, use dot notation (e.g., 'currentActivity.steps') to merge instead of overwrite,
    // or manually merge before sending. For this demo, we assume the UI passes full objects or we perform a merge logic here.
    // Simplifying for this snippet to use setDoc with merge: true
    await setDoc(userRef, updatePayload, { merge: true });
};

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { createUserWithEmailAndPassword, signInWithEmailAndPassword, updateProfile } from 'firebase/auth';
import { auth, createUserDocument } from '../services/firebase';
import { Loader2, Mail, Lock, User as UserIcon, AlertCircle, ArrowRight } from 'lucide-react';

interface AuthProps {
  onLoginSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form Fields
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      if (isLogin) {
        // --- LOGIN FLOW ---
        await signInWithEmailAndPassword(auth, email, password);
        onLoginSuccess();
      } else {
        // --- SIGN UP FLOW ---
        if (password !== confirmPassword) {
          throw new Error("Passwords do not match.");
        }
        if (password.length < 6) {
           throw new Error("Password must be at least 6 characters.");
        }

        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        // Update Profile Name
        await updateProfile(user, { displayName: name });

        // Create Firestore Document
        await createUserDocument(user, name);

        onLoginSuccess();
      }
    } catch (err: any) {
      console.error(err);
      // Clean up firebase error messages
      let msg = err.message;
      if (msg.includes('auth/email-already-in-use')) msg = "Email is already in use.";
      if (msg.includes('auth/invalid-email')) msg = "Invalid email address.";
      if (msg.includes('auth/weak-password')) msg = "Password is too weak.";
      if (msg.includes('auth/user-not-found') || msg.includes('auth/wrong-password')) msg = "Invalid credentials.";
      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  return (
