        </motion.div>

        <motion.div 
          layout
          className="glass-panel p-8 rounded-3xl border border-white/10 shadow-2xl relative overflow-hidden"
        >
          {/* Top Line Scan Animation */}
          <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-luxury-neon to-transparent opacity-50"></div>

          <h2 className="text-2xl font-bold text-white mb-6 text-center">
