import { ActivityData } from '../types';

// --- MOCK TYPES ---
export interface User {
  uid: string;
  email: string | null;
  displayName: string | null;
  photoURL: string | null;
}

// --- MOCK AUTH STATE ---
let currentUser: User | null = null;
const authListeners: ((user: User | null) => void)[] = [];

// Helper to persist mock user session
const saveUserSession = (user: User | null) => {
  currentUser = user;
  if (user) {
    localStorage.setItem('healthy_hub_user', JSON.stringify(user));
  } else {
    localStorage.removeItem('healthy_hub_user');
  }
  authListeners.forEach(listener => listener(user));
};

// Initialize from storage
try {
  const stored = localStorage.getItem('healthy_hub_user');
  if (stored) {
    currentUser = JSON.parse(stored);
  }
} catch (e) {
  console.error("Failed to load auth state", e);
}

// --- EXPORTED MOCK AUTH FUNCTIONS ---

export const auth = {}; // Mock auth object

export const onAuthStateChanged = (authObj: any, callback: (user: User | null) => void) => {
  authListeners.push(callback);
  // Fire immediately
  callback(currentUser);
  // Unsubscribe function
  return () => {
    const index = authListeners.indexOf(callback);
    if (index > -1) authListeners.splice(index, 1);
  };
};

export const signInWithEmailAndPassword = async (authObj: any, email: string, psw: string) => {
  await new Promise(resolve => setTimeout(resolve, 800)); // Simulate network delay

  // Simple mock login: Check if user exists in "database" (localStorage)
  const db = getMockDb();
  const existingUser = Object.values(db).find((u: any) => u.email === email) as any;

  if (existingUser) {
    const user: User = {
      uid: existingUser.uid,
      email: existingUser.email,
      displayName: existingUser.name,
      photoURL: existingUser.avatarUrl
    };
    saveUserSession(user);
    return { user };
  }

  throw new Error("User not found or invalid credentials.");
};

export const createUserWithEmailAndPassword = async (authObj: any, email: string, psw: string) => {
  await new Promise(resolve => setTimeout(resolve, 800));

  // Check if email taken
  const db = getMockDb();
  const taken = Object.values(db).some((u: any) => u.email === email);
  if (taken) throw new Error("Email already in use.");

  const uid = 'user_' + Math.random().toString(36).substr(2, 9);
  const user: User = {
    uid,
    email,
    displayName: null,
    photoURL: null
  };

  saveUserSession(user);
  return { user };
};

export const signOut = async (authObj: any) => {
  saveUserSession(null);
};

export const updateProfile = async (user: User, profile: { displayName?: string, photoURL?: string }) => {
  if (currentUser && currentUser.uid === user.uid) {
    const updated = { ...currentUser, ...profile };
    saveUserSession(updated);
  }
};

// --- MOCK FIRESTORE FUNCTIONS ---

const DB_KEY = 'healthy_hub_db';

const getMockDb = () => {
  try {
    return JSON.parse(localStorage.getItem(DB_KEY) || '{}');
  } catch {
    return {};
  }
};

const saveMockDb = (data: any) => {
  localStorage.setItem(DB_KEY, JSON.stringify(data));
};

export const db = {}; // Mock db object

export const createUserDocument = async (user: User, name: string) => {
  const dbData = getMockDb();
  if (!dbData[user.uid]) {
    dbData[user.uid] = {
      uid: user.uid,
      name,
      email: user.email,
      avatarUrl: `https://api.dicebear.com/7.x/avataaars/svg?seed=${name}&backgroundColor=b6e3f4`,
      goals: {
        stepGoal: 10000,
        calorieGoal: 2000,
        distanceGoal: 5.0
      },
      currentActivity: {
        steps: 0,
        calories: 0,
        distance: 0,
        history: [
            { day: 'Mon', steps: 0 },
            { day: 'Tue', steps: 0 },
            { day: 'Wed', steps: 0 },
            { day: 'Thu', steps: 0 },
            { day: 'Fri', steps: 0 },
            { day: 'Sat', steps: 0 },
            { day: 'Sun', steps: 0 },
        ]
      }
    };
    saveMockDb(dbData);
  }
};

export const subscribeToUserData = (uid: string, onUpdate: (data: any) => void) => {
  // Initial call
  const dbData = getMockDb();
  if (dbData[uid]) {
    onUpdate(dbData[uid]);
  }

  // Poll for changes (simple way to sync across components/tabs for this mock)
  const interval = setInterval(() => {
    const current = getMockDb();
    if (current[uid]) {
      onUpdate(current[uid]);
    }
  }, 1000);

  return () => clearInterval(interval);
};

export const updateUserActivity = async (uid: string, data: Partial<ActivityData>, goals?: Partial<ActivityData>) => {
  const dbData = getMockDb();
  if (dbData[uid]) {
    if (data) {
      dbData[uid].currentActivity = { ...dbData[uid].currentActivity, ...data };
    }
    if (goals) {
      dbData[uid].goals = { ...dbData[uid].goals, ...goals };
    }
    saveMockDb(dbData);
  }
};

import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { 
  auth, 
  subscribeToUserData, 
  updateUserActivity, 
  onAuthStateChanged, 
  User 
} from './services/firebase';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import ChatBot from './components/ChatBot';
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserProfile, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingAuth, setLoadingAuth] = useState(true);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  const { isTracking, toggleTracking, liveSteps, resetLiveSteps, status } = usePedometer();

  // Initialize with safe defaults, will be overwritten by Firestore
  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0,
    calories: 0,
    distance: 0,
    stepGoal: 10000,
    calorieGoal: 2000,
    distanceGoal: 5.0,
    history: [
      { day: 'Mon', steps: 0 },
      { day: 'Tue', steps: 0 },
      { day: 'Wed', steps: 0 },
      { day: 'Thu', steps: 0 },
      { day: 'Fri', steps: 0 },
      { day: 'Sat', steps: 0 },
      { day: 'Sun', steps: 0 },
    ]
  });

  const [bmiMetrics, setBmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);

  // --- Auth & Data Listener ---
  useEffect(() => {
    const unsubscribeAuth = onAuthStateChanged(auth, (user) => {
      setCurrentUser(user);
      if (user) {
        // Subscribe to Firestore Data
        const unsubscribeData = subscribeToUserData(user.uid, (data) => {
            if (data) {
                // Map Firestore data to local state
                setUserProfile({
                    name: data.name,
                    email: data.email,
                    avatarUrl: data.avatarUrl
                });

                if (data.currentActivity) {
                   setActivityData(prev => ({
                     ...prev,
                     ...data.currentActivity,
                     stepGoal: data.goals?.stepGoal || prev.stepGoal,
                     calorieGoal: data.goals?.calorieGoal || prev.calorieGoal,
                     distanceGoal: data.goals?.distanceGoal || prev.distanceGoal
                   }));
                }
            }
        });
        setLoadingAuth(false);
        return () => unsubscribeData();
      } else {
        setUserProfile(null);
        setLoadingAuth(false);
      }
    });

    return () => unsubscribeAuth();
  }, []);

  // Sync Pedometer Updates to Firestore
  useEffect(() => {
    if (liveSteps > 0 && currentUser) {
       // Calculate new values locally first for UI responsiveness
       const addedCalories = 0.04;
       const addedDistance = 0.00076;

       const newSteps = activityData.steps + 1;
       const newCals = activityData.calories + addedCalories;
       const newDist = activityData.distance + addedDistance;

       const updatedHistory = [...activityData.history];
       // Simply incrementing current day (index 6) for demo purposes
       updatedHistory[6] = { ...updatedHistory[6], steps: updatedHistory[6].steps + 1 };

       const newData = {
          steps: newSteps,
          calories: newCals,
          distance: newDist,
          history: updatedHistory,
          stepGoal: activityData.stepGoal,
          calorieGoal: activityData.calorieGoal,
          distanceGoal: activityData.distanceGoal
       };

       setActivityData(newData);
       resetLiveSteps();

       // Debounce sync to firestore could be added here, but for now we update live
       updateUserActivity(currentUser.uid, newData);
    }
  }, [liveSteps, currentUser, activityData, resetLiveSteps]);

  const handleAddToHistory = (item: FoodHistoryItem) => {
    setFoodHistory(prev => [item, ...prev]);
    if (currentUser) {
       const newCalories = activityData.calories + item.analysis.macros.calories;
       setActivityData(prev => ({ ...prev, calories: newCalories }));
       updateUserActivity(currentUser.uid, { ...activityData, calories: newCalories });
    }
  };

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => {
    setActivityData(prev => ({ ...prev, ...newGoals }));
    if (currentUser) {
        updateUserActivity(currentUser.uid, {}, { ...activityData, ...newGoals });
    }
  };

  if (loadingAuth) {
     return <div className="h-screen w-full bg-black flex items-center justify-center text-luxury-neon animate-pulse">Loading Healthy.hub...</div>;
  }

  if (!currentUser) {
    return <Auth onLoginSuccess={() => {}} />;
  }

  return (
    <div className="min-h-screen bg-black text-white relative overflow-hidden font-sans selection:bg-luxury-neon selection:text-black">
      {/* Ambient Background */}
      <div className="fixed top-[-10%] right-[-10%] w-[50vh] h-[50vh] bg-luxury-neon/5 rounded-full blur-[100px] pointer-events-none z-0"></div>
      <div className="fixed bottom-[-10%] left-[-10%] w-[40vh] h-[40vh] bg-luxury-gold/5 rounded-full blur-[80px] pointer-events-none z-0"></div>

      <main className="relative z-10 h-screen overflow-y-auto no-scrollbar">
        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && (
             <Dashboard 
                key="dashboard"
                data={activityData} 
                onUpdateGoals={handleUpdateGoals} 
                isTracking={isTracking}
                onToggleTracking={toggleTracking}
                status={status}
             />
          )}
          {currentView === ViewState.FOOD_LENS && (
            <motion.div
               key="foodlens"
               initial={{ opacity: 0, scale: 0.95 }}
               animate={{ opacity: 1, scale: 1 }}
               exit={{ opacity: 0, scale: 1.05 }}
               transition={{ duration: 0.3 }}
               className="h-full"
            >
               <FoodLens history={foodHistory} onAddToHistory={handleAddToHistory} />
            </motion.div>
          )}
          {currentView === ViewState.BMI_HUB && (
            <motion.div
               key="bmi"
               initial={{ opacity: 0, x: 20 }}
               animate={{ opacity: 1, x: 0 }}
               exit={{ opacity: 0, x: -20 }}
               transition={{ duration: 0.3 }}
               className="h-full"
            >
               <BMIHub />
            </motion.div>
          )}
          {currentView === ViewState.CHAT && (
            <motion.div
               key="chat"
               initial={{ opacity: 0, y: 20 }}
               animate={{ opacity: 1, y: 0 }}
               exit={{ opacity: 0, y: -20 }}
               transition={{ duration: 0.4 }}
               className="h-full"
            >
               <ChatBot metrics={bmiMetrics} activity={activityData} />
            </motion.div>
          )}
        </AnimatePresence>
      </main>

      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

