  const [showPassword, setShowPassword] = useState(false);

  // Form Fields
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      if (isLogin) {
        // --- LOGIN FLOW ---
        await signInWithEmailAndPassword(auth, email, password);
        onLoginSuccess();
      } else {
        // --- SIGN UP FLOW ---
        if (password !== confirmPassword) {
          throw new Error("Passwords do not match.");
        }
        if (password.length < 6) {
           throw new Error("Password must be at least 6 characters.");
        }

        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        // Update Profile Name
        await updateProfile(user, { displayName: name });

        // Create Firestore Document
        await createUserDocument(user, name);

        onLoginSuccess();
      }
    } catch (err: any) {
      console.error(err);
      let msg = err.message;
      if (msg.includes('auth/email-already-in-use')) msg = "Email is already in use.";
      if (msg.includes('auth/invalid-email')) msg = "Invalid email address.";
      if (msg.includes('auth/weak-password')) msg = "Password is too weak.";
      if (msg.includes('auth/user-not-found') || msg.includes('auth/wrong-password') || msg.includes('auth/invalid-credential')) msg = "Invalid email or password.";
      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

