      <div className="relative z-10 w-full max-w-md px-6">
        <motion.div 
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.5 }}
          className="glass-panel rounded-3xl p-8 md:p-10 shadow-2xl border border-white/10"
        >
          {/* Logo Section - Replaced with Image */}
          <div className="flex flex-col items-center mb-10">
            <img 
              src="/logo.png" 
              alt="Healthy Hub"
              // brightness-0 turns it black, invert turns it white. This ensures the logo is white regardless of original color.
