import React, { useState, useEffect, useRef, useMemo } from 'react';
import { motion, useSpring, useTransform, useMotionValue, animate } from 'framer-motion';
import { UserMetrics } from '../types';
import useLocalStorage from '../hooks/useLocalStorage';
import { Ruler, CheckCircle2, AlertTriangle, Info } from 'lucide-react';

const BMIHub: React.FC = () => {
  const [metrics, setMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [bmi, setBmi] = useState<number>(0);
  const [status, setStatus] = useState<string>('');

  // Physics-based springs for smooth needle/number animations
  const bmiSpring = useSpring(0, { stiffness: 60, damping: 15 });
  const heightSpring = useSpring(metrics.height, { stiffness: 100, damping: 20 });
  const weightSpring = useSpring(metrics.weight, { stiffness: 100, damping: 20 });

  useEffect(() => {
    // Calculate BMI
    const heightInMeters = metrics.height / 100;
    const val = metrics.weight / (heightInMeters * heightInMeters);
    const newBmi = Math.min(Math.max(val, 10), 45); // Clamp for gauge visualization

    setBmi(Number(val.toFixed(1)));
    bmiSpring.set(newBmi);
    heightSpring.set(metrics.height);
    weightSpring.set(metrics.weight);

    // Determine Status
    if (val < 18.5) setStatus('Underweight');
    else if (val < 25) setStatus('Normal');
    else if (val < 30) setStatus('Overweight');
    else setStatus('Obese');
  }, [metrics, bmiSpring, heightSpring, weightSpring]);

  const getStatusColor = (s: string) => {
    switch (s) {
      case 'Underweight': return '#60a5fa'; // Blue
      case 'Normal': return '#CEF245'; // Neon
      case 'Overweight': return '#D4AF37'; // Gold
      case 'Obese': return '#ef4444'; // Red
      default: return '#fff';
    }
  };

  const currentColor = getStatusColor(status);

  return (
    <div className="h-full w-full flex flex-col bg-[#050505] relative overflow-hidden text-white font-sans selection:bg-luxury-neon selection:text-black">
      {/* Background Ambience */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full max-w-lg h-1/2 bg-gradient-to-b from-luxury-neon/5 to-transparent blur-[100px] pointer-events-none" />

      {/* Header */}
      <div className="p-6 pt-12 z-10 flex justify-between items-end">
        <div>
          <h2 className="text-xs font-bold text-gray-500 uppercase tracking-[0.2em] mb-1">Body Metrics</h2>
          <h1 className="text-2xl font-black text-white tracking-tight">
            BIO<span className="text-luxury-neon">SCAN</span>
          </h1>
        </div>
        <div className="px-3 py-1 rounded-full bg-white/5 border border-white/10 flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full animate-pulse`} style={{ backgroundColor: currentColor }}></div>
            <span className="text-[10px] font-bold uppercase tracking-widest text-gray-300">Live Analysis</span>
        </div>
      </div>

      {/* Main Layout: Gauge Top, Rulers Bottom/Right */}
      <div className="flex-1 flex flex-col relative z-10">

        {/* HERO GAUGE */}
        <div className="flex-1 flex flex-col items-center justify-center relative min-h-[300px]">
           <Gauge value={bmiSpring} status={status} color={currentColor} displayValue={bmi} />

           {/* Result Card */}
           <motion.div 
             initial={{ opacity: 0, y: 20 }}
             animate={{ opacity: 1, y: 0 }}
             key={status} // Re-animate on status change
             className="mt-8 glass-panel px-6 py-4 rounded-2xl border-l-4 backdrop-blur-md max-w-[80%]"
             style={{ borderColor: currentColor }}
           >
             <div className="flex justify-between items-center gap-8">
               <div>
                  <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-1">Condition</h3>
                  <p className="text-xl font-bold" style={{ color: currentColor }}>{status}</p>
               </div>
               <div className="h-8 w-[1px] bg-white/10"></div>
               <div className="text-right">
                  <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-1">Ideal Range</h3>
                  <p className="text-sm font-medium text-white">18.5 - 24.9</p>
               </div>
             </div>
           </motion.div>
        </div>

        {/* CONTROLS AREA */}
        <div className="h-[280px] w-full relative">

            {/* Weight Ruler (Horizontal - Bottom) */}
            <div className="absolute bottom-0 left-0 right-16 h-32 glass-panel border-t border-white/10 rounded-tr-3xl overflow-hidden">
                <div className="absolute top-4 left-6 z-10 pointer-events-none">
                    <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">Weight (KG)</span>
                </div>
                <HorizontalRuler 
                    value={metrics.weight} 
                    min={40} max={150} 
                    onChange={(w) => setMetrics(m => ({...m, weight: w}))} 
                />
            </div>

            {/* Height Ruler (Vertical - Right) */}
            <div className="absolute bottom-0 right-0 w-24 h-full glass-panel border-l border-white/10 rounded-tl-3xl overflow-hidden flex flex-col">
                 <div className="absolute top-6 left-0 w-full text-center z-10 pointer-events-none">
                    <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest vertical-text">Height (CM)</span>
                </div>
                <VerticalRuler 
                    value={metrics.height} 
                    min={140} max={220} 
                    onChange={(h) => setMetrics(m => ({...m, height: h}))} 
                />
            </div>

            {/* Corner Connector Decoration */}
            <div className="absolute bottom-0 right-0 w-24 h-32 pointer-events-none">
                 <div className="absolute bottom-4 right-4 text-luxury-grey opacity-20">
                    <Ruler size={48} strokeWidth={1} />
                 </div>
            </div>
        </div>
      </div>
    </div>
  );
};

// --- GAUGE COMPONENT ---

const Gauge = ({ value, status, color, displayValue }: { value: any, status: string, color: string, displayValue: number }) => {
  // Map BMI 10-45 to degrees -90 to 90
  const rotation = useTransform(value, [10, 45], [-90, 90]);

  // Generate arc path
  // Standard gauge from 10 to 45
  // Zones: <18.5 (Blue), 18.5-25 (Green), 25-30 (Gold), >30 (Red)

  return (
    <div className="relative w-72 h-36">
       {/* Background Pulse Effect */}
       <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-full h-full flex items-end justify-center pointer-events-none">
          <motion.div 
             key={status} // Reset pulse on status change
             initial={{ scale: 0.8, opacity: 0.5 }}
             animate={{ scale: 1.5, opacity: 0 }}
             transition={{ duration: 2, repeat: Infinity, ease: "easeOut" }}
             className="w-48 h-48 rounded-full border-2 blur-sm absolute bottom-[-50px]"
             style={{ borderColor: color }}
          />
       </div>

       <svg className="w-full h-full overflow-visible" viewBox="0 0 200 100">
          {/* Track Background */}
          <path d="M 20 100 A 80 80 0 0 1 180 100" fill="none" stroke="#1a1a1a" strokeWidth="12" strokeLinecap="round" />

          {/* Zones */}
          {/* Calculations based on 10-45 range = 35 units total. 180 degrees total. ~5.14 deg per unit */}
          {/* Underweight (10 to 18.5) -> 8.5 units * 5.14 = 43.7 deg */}
          <path d="M 20 100 A 80 80 0 0 1 180 100" fill="none" stroke="#60a5fa" strokeWidth="12" strokeLinecap="round" 
             strokeDasharray="44 500" strokeDashoffset="0" className="opacity-40" />

          {/* Normal (18.5 to 25) -> 6.5 units * 5.14 = 33.4 deg. Starts at 43.7 */}
          <path d="M 20 100 A 80 80 0 0 1 180 100" fill="none" stroke="#CEF245" strokeWidth="12" strokeLinecap="round" 
             strokeDasharray="34 500" strokeDashoffset="-46" className="opacity-40" />

          {/* Overweight (25 to 30) -> 5 units * 5.14 = 25.7 deg. Starts at 77.1 */}
          <path d="M 20 100 A 80 80 0 0 1 180 100" fill="none" stroke="#D4AF37" strokeWidth="12" strokeLinecap="round" 
             strokeDasharray="26 500" strokeDashoffset="-82" className="opacity-40" />

          {/* Obese (30 to 45) -> 15 units * 5.14 = 77.1 deg. Starts at 102.8 */}
          <path d="M 20 100 A 80 80 0 0 1 180 100" fill="none" stroke="#ef4444" strokeWidth="12" strokeLinecap="round" 
             strokeDasharray="78 500" strokeDashoffset="-110" className="opacity-40" />

          {/* Needle Container - Rotates */}
          <motion.g style={{ rotate: rotation, originX: "100px", originY: "100px" }}>
             {/* The Needle */}
             <path d="M 100 100 L 100 25" stroke={color} strokeWidth="4" strokeLinecap="round" className="drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]" />
             <circle cx="100" cy="100" r="6" fill={color} />
          </motion.g>
       </svg>

       {/* Digital Readout */}
       <div className="absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-1/2 text-center">
          <motion.span className="text-6xl font-black tracking-tighter block leading-none drop-shadow-2xl">
             {displayValue}
          </motion.span>
          <span className="text-[10px] text-gray-500 font-bold uppercase tracking-[0.3em]">BMI Score</span>
       </div>
    </div>
  );
};


// --- INTERACTIVE RULERS ---

// Horizontal Ruler for Weight
const HorizontalRuler = ({ value, min, max, onChange }: { value: number, min: number, max: number, onChange: (v: number) => void }) => {
    // Generate ticks
    const range = max - min;

    return (
        <div className="w-full h-full flex items-center justify-center relative">
           <input 
             type="range" 
             min={min} 
             max={max} 
             value={value}
             onChange={(e) => {
                 onChange(Number(e.target.value));
                 if (navigator.vibrate) navigator.vibrate(5);
             }}
             className="w-[85%] z-20 opacity-0 cursor-pointer h-16 absolute top-1/2 -translate-y-1/2"
           />

           {/* Visual Track */}
           <div className="w-[85%] h-16 relative overflow-hidden flex items-center">
              <div className="absolute w-full h-[1px] bg-white/10 top-1/2"></div>

              {/* Dynamic Value Display */}
              <div 
                 className="absolute top-1/2 -translate-y-1/2 flex items-center justify-center pointer-events-none transition-all duration-100 ease-out will-change-transform"
                 style={{ left: `${((value - min) / range) * 100}%`, transform: 'translateX(-50%)' }}
              >
                  {/* Thumb Glow */}
                  <div className="w-1 h-12 bg-luxury-neon shadow-[0_0_15px_#CEF245] rounded-full"></div>

                  {/* Floating Number Bubble */}
                  <div className="absolute -top-12 bg-luxury-neon text-black font-bold text-lg px-3 py-1 rounded-xl shadow-lg">
                      {value}<span className="text-[10px] ml-1 opacity-70">KG</span>
                  </div>
              </div>

              {/* Ticks (Simplified for performance) */}
              <div className="absolute inset-0 w-full h-full flex justify-between px-1 pointer-events-none">
                  {Array.from({ length: 21 }).map((_, i) => (
                      <div key={i} className={`h-full flex flex-col justify-center items-center`}>
                          <div className={`w-[1px] ${i % 5 === 0 ? 'h-6 bg-white/40' : 'h-3 bg-white/10'}`}></div>
                      </div>
                  ))}
              </div>
           </div>
        </div>
    );
};

