import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

// --- ORIENTATION LOCK IMPLEMENTATION ---
// Simulating SystemChrome.setPreferredOrientations([DeviceOrientation.portraitUp])
const lockOrientation = async () => {
  if (screen.orientation && 'lock' in screen.orientation) {
    try {
      // @ts-ignore - The lock API is experimental in some definitions
      await screen.orientation.lock('portrait');
      console.log("Orientation locked to portrait.");
    } catch (error) {
      console.warn("Orientation lock failed (likely needs fullscreen or unsupported):", error);
    }
  }
};

// Attempt lock on initialization
lockOrientation();

// Also attempt re-lock if the user rotates
window.addEventListener('orientationchange', () => {
  if (window.orientation === 90 || window.orientation === -90) {
     // If rotation happens, try to lock again or show UI warning (handled in CSS/App if needed)
     lockOrientation();
  }
});

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

