}

import { StreakData } from "../types";

const STREAK_KEY = 'healthy_hub_streak';

export const getMotivationalMessage = (streak: number): string => {
  if (streak === 0) return "Let's start the journey today! 💪";
  if (streak < 3) return "You're warming up! Keep going. 🔥";
  if (streak < 7) return `You're on fire! 🔥 ${streak} days in a row!`;
  if (streak < 30) return `Unstoppable! ${streak} day streak! 🚀`;
  return `GOD MODE ENABLED. ${streak} DAYS. 👑`;
};

export const updateStreak = (): StreakData => {
  let stored: StreakData = { currentStreak: 0, lastLoginDate: '', milestoneReached: false };

  try {
    const item = localStorage.getItem(STREAK_KEY);
    if (item) stored = JSON.parse(item);
  } catch (e) {
    console.warn("Failed to parse streak", e);
  }

  const today = new Date().toISOString().split('T')[0];
  const lastDate = stored.lastLoginDate;

  // If already logged in today, return current state (no change)
  if (lastDate === today) {
    return { ...stored, milestoneReached: false }; // Milestone only triggers once per new day
  }

  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);
  const yesterdayString = yesterday.toISOString().split('T')[0];

  let newStreak = stored.currentStreak;
  let isMilestone = false;

  if (lastDate === yesterdayString) {
    // Streak continues
    newStreak += 1;
    // Check Milestones (3, 7, 30)
    if ([3, 7, 30, 100].includes(newStreak)) {
      isMilestone = true;
    }
  } else {
    // Streak broken (missed at least one day)
    // Exception: If this is the very first use (lastDate is empty), start at 1
    newStreak = 1; 
  }

  const newState: StreakData = {
    currentStreak: newStreak,
    lastLoginDate: today,
    milestoneReached: isMilestone
  };

  localStorage.setItem(STREAK_KEY, JSON.stringify(newState));
  return newState;
};

import React, { useEffect } from 'react';
import { motion } from 'framer-motion';
import { Flame, Trophy, Zap } from 'lucide-react';
import confetti from 'canvas-confetti';

interface StreakWidgetProps {
  streak: number;
  milestoneReached: boolean;
}

const StreakWidget: React.FC<StreakWidgetProps> = ({ streak, milestoneReached }) => {

  useEffect(() => {
    if (milestoneReached) {
      triggerExplosion();
    }
  }, [milestoneReached]);

  const triggerExplosion = () => {
    const duration = 3000;
    const end = Date.now() + duration;

    const frame = () => {
      confetti({
        particleCount: 5,
        angle: 60,
        spread: 55,
        origin: { x: 0 },
        colors: ['#CEF245', '#D4AF37', '#ff5500']
      });
      confetti({
        particleCount: 5,
        angle: 120,
        spread: 55,
        origin: { x: 1 },
        colors: ['#CEF245', '#D4AF37', '#ff5500']
      });

      if (Date.now() < end) {
        requestAnimationFrame(frame);
      }
    };
    frame();
  };

  // Determine Visual State
  let flameColor = "text-yellow-400";
  let flameShadow = "drop-shadow-[0_0_10px_rgba(250,204,21,0.5)]";
  let borderColor = "from-orange-500/50 to-red-500/50";
  let intensity = 1;

  if (streak >= 3 && streak < 10) {
    // Burning Flame
    flameColor = "text-orange-500";
    flameShadow = "drop-shadow-[0_0_20px_rgba(249,115,22,0.6)]";
    borderColor = "from-orange-500 to-red-600";
    intensity = 1.2;
  } else if (streak >= 10) {
    // God Mode (Blue Inferno)
    flameColor = "text-blue-500";
    flameShadow = "drop-shadow-[0_0_30px_rgba(59,130,246,0.8)]";
    borderColor = "from-blue-500 to-purple-600";
    intensity = 1.5;
  }

  return (
    <div className={`relative w-full rounded-2xl p-[1px] bg-gradient-to-r ${borderColor} shadow-2xl overflow-hidden group`}>
       {/* Inner Background */}
       <div className="bg-[#0a0a0a] w-full h-full rounded-2xl p-4 flex items-center justify-between relative overflow-hidden">

          {/* Ambient Glow */}
          <div className={`absolute -right-4 -top-4 w-24 h-24 rounded-full blur-[50px] opacity-40 ${streak >= 10 ? 'bg-blue-600' : 'bg-orange-600'}`}></div>

          <div className="flex flex-col z-10">
             <div className="flex items-center gap-2 mb-1">
                <Zap size={14} className={streak >= 10 ? "text-blue-400" : "text-orange-400"} />
                <span className="text-xs font-bold uppercase tracking-widest text-gray-400">Current Streak</span>
             </div>
             <div className="flex items-baseline gap-1">
                <span className={`text-4xl font-black italic tracking-tighter ${streak >= 10 ? 'text-white' : 'text-white'}`}>
                   {streak}
                </span>
                <span className="text-sm font-bold text-gray-500 uppercase">Days</span>
             </div>
          </div>

          {/* Animated Flame Icon (Simulating Lottie) */}
          <div className="relative z-10 w-16 h-16 flex items-center justify-center">
             <motion.div
               animate={{ 
                 scale: [1 * intensity, 1.1 * intensity, 1 * intensity],
                 opacity: [0.8, 1, 0.8],
                 rotate: [0, -5, 5, 0]
               }}
               transition={{ 
                 duration: 2 / intensity, 
                 repeat: Infinity, 
                 ease: "easeInOut" 
               }}
               className={`${flameColor} ${flameShadow}`}
             >
                <Flame size={48} strokeWidth={2.5} fill="currentColor" fillOpacity={0.2} />
             </motion.div>

             {/* Core Heat */}
             <motion.div 
               animate={{ scale: [0.8, 1, 0.8], opacity: [0.5, 0.8, 0.5] }}
               transition={{ duration: 1, repeat: Infinity }}
               className={`absolute inset-0 blur-md ${streak >= 10 ? 'bg-blue-400/30' : 'bg-orange-400/30'} rounded-full`} 
             />
          </div>
       </div>
    </div>
  );
};

