  signInWithEmailAndPassword, 
  updateProfile,
  sendPasswordResetEmail
} from '../services/firebase';
import { Loader2, Eye, EyeOff, AlertCircle, User as UserIcon, Mail, Lock, ArrowRight, X, CheckCircle } from 'lucide-react';

interface AuthProps {
  onLoginSuccess: () => void;
}

