      await sendPasswordResetEmail(auth, resetEmail);
      setResetFeedback({
        type: 'success',
        message: 'Reset link sent! Check your email.'
      });
      // Clear after success
      setTimeout(() => {
        setIsResetModalOpen(false);
        setResetEmail('');
        setResetFeedback(null);
      }, 3000);
    } catch (err: any) {
      setResetFeedback({
        type: 'error',
        message: err.message || 'Failed to send reset email.'
      });
    } finally {
      setResetLoading(false);
    }
