  auth, 
  createUserDocument, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile,
  sendPasswordResetEmail
} from '../services/firebase';
import { Loader2, Eye, EyeOff, AlertCircle, User as UserIcon, Mail, Lock, ArrowRight, X, CheckCircle, Info } from 'lucide-react';

interface AuthProps {
  onLoginSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  // Forgot Password State
  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetLoading, setResetLoading] = useState(false);
  const [resetFeedback, setResetFeedback] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  // Form Fields - Initialized with demo credentials for easy testing
  const [name, setName] = useState('');
  const [email, setEmail] = useState('admin@healthyhub.com');
  const [password, setPassword] = useState('password');
  const [confirmPassword, setConfirmPassword] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    try {
      if (isLogin) {
        // --- LOGIN FLOW ---
        await signInWithEmailAndPassword(auth, email, password);
        onLoginSuccess();
      } else {
        // --- SIGN UP FLOW ---
        if (password !== confirmPassword) {
          throw new Error("Passwords do not match.");
        }
        if (password.length < 6) {
           throw new Error("Password must be at least 6 characters.");
        }

        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        // Update Profile Name
        await updateProfile(user, { displayName: name });

        // Create Firestore Document
        await createUserDocument(user, name);

        onLoginSuccess();
      }
    } catch (err: any) {
      console.error(err);
      let msg = err.message;
      if (msg.includes('auth/email-already-in-use')) msg = "Email is already in use.";
      if (msg.includes('auth/invalid-email')) msg = "Invalid email address.";
      if (msg.includes('auth/weak-password')) msg = "Password is too weak.";
      if (msg.includes('auth/user-not-found') || msg.includes('auth/wrong-password') || msg.includes('auth/invalid-credential')) msg = "Invalid email or password.";
      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const handleResetPassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!resetEmail.trim()) return;

    setResetLoading(true);
    setResetFeedback(null);

    try {
      await sendPasswordResetEmail(auth, resetEmail);
      setResetFeedback({
        type: 'success',
        message: 'Reset link sent! Check your email.'
      });
      // Clear after success
      setTimeout(() => {
        setIsResetModalOpen(false);
        setResetEmail('');
        setResetFeedback(null);
      }, 3000);
    } catch (err: any) {
      setResetFeedback({
        type: 'error',
        message: err.message || 'Failed to send reset email.'
      });
    } finally {
      setResetLoading(false);
