              <AnimatePresence>
                {resetFeedback && (
                  <motion.div 
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0 }}
                    className={`mb-6 p-4 rounded-xl flex items-center gap-3 text-sm ${
                      resetFeedback.type === 'success' 
                        ? 'bg-luxury-neon/10 border border-luxury-neon/30 text-luxury-neon' 
                        : 'bg-red-500/10 border border-red-500/30 text-red-400'
                    }`}
                  >
                    {resetFeedback.type === 'success' ? <CheckCircle size={18} /> : <AlertCircle size={18} />}
                    <p className="font-medium">{resetFeedback.message}</p>
                  </motion.div>
                )}
              </AnimatePresence>

              <form onSubmit={handleResetPassword} className="space-y-6">
                <div className="space-y-1.5">
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-wider ml-1">Account Email</label>
                  <div className="relative group">
                    <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                      <Mail className="h-5 w-5 text-gray-500 group-focus-within:text-luxury-neon transition-colors" />
                    </div>
                    <input
                      type="email"
                      required
                      value={resetEmail}
                      onChange={(e) => setResetEmail(e.target.value)}
                      className="block w-full pl-11 pr-4 py-4 bg-white/5 border border-white/10 rounded-xl text-white placeholder-gray-600 focus:border-luxury-neon focus:ring-1 focus:ring-luxury-neon/50 focus:bg-black/40 transition-all outline-none text-sm font-medium"
                      placeholder="name@example.com"
                    />
                  </div>
                </div>

                <motion.button
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  disabled={resetLoading || !resetEmail.trim()}
                  className="w-full flex items-center justify-center py-4 bg-luxury-neon text-black text-sm font-black uppercase tracking-widest rounded-xl hover:bg-[#b5d63d] transition-all shadow-[0_4px_15px_rgba(206,242,69,0.3)] disabled:opacity-50"
                >
                  {resetLoading ? (
                    <Loader2 className="h-5 w-5 animate-spin" />
                  ) : (
                    'Send Reset Link'
                  )}
                </motion.button>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { 
  auth, 
  subscribeToUserData, 
  updateUserActivity, 
  onAuthStateChanged, 
  User 
} from './services/firebase';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import DashboardSkeleton from './components/DashboardSkeleton';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import ChatBot from './components/ChatBot';
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserProfile, UserMetrics, StreakData } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';
import { updateStreak } from './services/streakService';
import { calculateAdaptiveGoals } from './services/goalService';
import { Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingAuth, setLoadingAuth] = useState(true);
  const [loadingData, setLoadingData] = useState(false);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  const { isTracking, toggleTracking, liveSteps, resetLiveSteps, status } = usePedometer();

  const [adaptiveGoalsEnabled, setAdaptiveGoalsEnabled] = useLocalStorage<boolean>('adaptive_goals_enabled', false);
  const [showGoalToast, setShowGoalToast] = useState(false);

  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0,
    calories: 0,
    distance: 0,
    stepGoal: 10000,
    calorieGoal: 2000,
    distanceGoal: 5.0,
    history: [
      { day: 'Mon', steps: 0 }, { day: 'Tue', steps: 0 }, { day: 'Wed', steps: 0 },
      { day: 'Thu', steps: 0 }, { day: 'Fri', steps: 0 }, { day: 'Sat', steps: 0 }, { day: 'Sun', steps: 0 },
    ]
  });

  const [bmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);

  useEffect(() => {
    const unsubscribeAuth = onAuthStateChanged(auth, (user) => {
      setCurrentUser(user);
      if (user) {
        setLoadingData(true);
        const unsubscribeData = subscribeToUserData(user.uid, (data) => {
            if (data) {
                setUserProfile({
                    name: data.name,
                    email: data.email,
                    avatarUrl: data.avatarUrl
                });

                if (data.currentActivity) {
                   setActivityData(prev => ({
                     ...prev,
                     ...data.currentActivity,
                     stepGoal: data.goals?.stepGoal || prev.stepGoal,
                     calorieGoal: data.goals?.calorieGoal || prev.calorieGoal,
                     distanceGoal: data.goals?.distanceGoal || prev.distanceGoal
                   }));
                }
            }
            setLoadingData(false);
        });
        setLoadingAuth(false);
        return () => unsubscribeData();
      } else {
        setUserProfile(null);
        setLoadingAuth(false);
        setLoadingData(false);
      }
    });

    return () => unsubscribeAuth();
  }, []);

  useEffect(() => {
    if (currentUser && adaptiveGoalsEnabled && !loadingData) {
        const streakInfo = updateStreak();
        const lastAdaptationKey = `last_adaptation_${currentUser.uid}`;
        const today = new Date().toISOString().split('T')[0];
        const lastAdaptation = localStorage.getItem(lastAdaptationKey);

        if (lastAdaptation !== today) {
            const proposedGoals = calculateAdaptiveGoals(activityData, streakInfo.currentStreak);
            if (proposedGoals) {
                setActivityData(prev => ({ ...prev, ...proposedGoals }));
                updateUserActivity(currentUser.uid, {}, proposedGoals);
                localStorage.setItem(lastAdaptationKey, today);
                setShowGoalToast(true);
                setTimeout(() => setShowGoalToast(false), 5000);
            }
        }
    }
  }, [currentUser, adaptiveGoalsEnabled, loadingData, activityData]);

  useEffect(() => {
    if (liveSteps > 0 && currentUser) {
       const addedCalories = 0.04;
       const addedDistance = 0.00076;
       const newSteps = activityData.steps + 1;
       const newCals = activityData.calories + addedCalories;
       const newDist = activityData.distance + addedDistance;
       const updatedHistory = [...activityData.history];
       updatedHistory[6] = { ...updatedHistory[6], steps: updatedHistory[6].steps + 1 };

       const newData = {
          steps: newSteps,
          calories: newCals,
          distance: newDist,
          history: updatedHistory,
          stepGoal: activityData.stepGoal,
          calorieGoal: activityData.calorieGoal,
          distanceGoal: activityData.distanceGoal
       };

       setActivityData(newData);
       resetLiveSteps();
       updateUserActivity(currentUser.uid, newData);
    }
  }, [liveSteps, currentUser, activityData, resetLiveSteps]);

  const handleAddToHistory = (item: FoodHistoryItem) => {
    setFoodHistory(prev => [item, ...prev]);
    if (currentUser) {
       const newCalories = activityData.calories + item.analysis.macros.calories;
       setActivityData(prev => ({ ...prev, calories: newCalories }));
       updateUserActivity(currentUser.uid, { ...activityData, calories: newCalories });
    }
  };

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => {
    setActivityData(prev => ({ ...prev, ...newGoals }));
    if (currentUser) {
        updateUserActivity(currentUser.uid, {}, { ...activityData, ...newGoals });
    }
  };

  if (loadingAuth) {
     return <div className="h-screen w-full bg-black flex items-center justify-center text-luxury-neon animate-pulse">Establishing Secure Session...</div>;
  }

  if (!currentUser) {
    return <Auth onLoginSuccess={() => {}} />;
  }

  return (
    <div className="min-h-screen bg-black text-white relative overflow-hidden font-sans selection:bg-luxury-neon selection:text-black">
      {/* Ambient Background */}
      <div className="fixed top-[-10%] right-[-10%] w-[50vh] h-[50vh] bg-luxury-neon/5 rounded-full blur-[100px] pointer-events-none z-0"></div>
      <div className="fixed bottom-[-10%] left-[-10%] w-[40vh] h-[40vh] bg-luxury-gold/5 rounded-full blur-[80px] pointer-events-none z-0"></div>

      {/* Adaptive Goal Toast - Top Safe Area Aware */}
      <AnimatePresence>
        {showGoalToast && (
          <motion.div 
            initial={{ y: -100, opacity: 0 }}
            animate={{ y: 'env(safe-area-inset-top, 16px)', opacity: 1 }}
            exit={{ y: -100, opacity: 0 }}
            className="fixed left-4 right-4 z-[60] glass-panel bg-luxury-neon/10 border border-luxury-neon p-4 rounded-2xl flex items-center gap-4 shadow-[0_0_30px_rgba(206,242,69,0.2)]"
          >
             <div className="p-2 bg-luxury-neon text-black rounded-full shrink-0">
               <Sparkles size={20} />
             </div>
             <div>
               <h4 className="text-xs font-bold text-luxury-neon uppercase tracking-wider">Performance Optimized</h4>
               <p className="text-white text-sm">Goals increased based on your streak.</p>
             </div>
          </motion.div>
        )}
      </AnimatePresence>

      <main className="relative z-10 h-screen overflow-y-auto no-scrollbar pb-[env(safe-area-inset-bottom, 80px)]">
        {/* Safe Area Top Padding */}
        <div className="h-[env(safe-area-inset-top, 24px)]" />

        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && (
             loadingData ? (
                 <motion.div key="skeleton" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                    <DashboardSkeleton />
                 </motion.div>
             ) : (
                 <Dashboard 
                    key="dashboard"
                    data={activityData} 
                    onUpdateGoals={handleUpdateGoals} 
                    isTracking={isTracking}
                    onToggleTracking={toggleTracking}
                    status={status}
                    adaptiveGoalsEnabled={adaptiveGoalsEnabled}
                    onToggleAdaptiveGoals={setAdaptiveGoalsEnabled}
                 />
             )
          )}
          {currentView === ViewState.FOOD_LENS && (
            <motion.div key="foodlens" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="h-full">
               <FoodLens history={foodHistory} onAddToHistory={handleAddToHistory} />
            </motion.div>
          )}
          {currentView === ViewState.BMI_HUB && (
            <motion.div key="bmi" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="h-full">
               <BMIHub />
            </motion.div>
          )}
          {currentView === ViewState.CHAT && (
            <motion.div key="chat" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="h-full">
               <ChatBot metrics={bmiMetrics} activity={activityData} />
            </motion.div>
          )}
        </AnimatePresence>
      </main>

      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

