  const [notification, setNotification] = useState<string | null>(null);

  const goalReached = data.steps >= data.stepGoal;

  useEffect(() => {
    if (goalReached && navigator.vibrate) {
      navigator.vibrate([100, 50, 100]);
    }
  }, [goalReached]);

  useEffect(() => {
    const { currentStreak, milestoneReached } = updateStreak();
    setStreakData({ count: currentStreak, milestone: milestoneReached });
    const msg = getMotivationalMessage(currentStreak);
    const timer = setTimeout(() => {
       setNotification(msg);
       setTimeout(() => setNotification(null), 6000);
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  const stepsData = [
    { name: 'Completed', value: Math.min(data.steps, data.stepGoal) },
    { name: 'Remaining', value: Math.max(0, data.stepGoal - data.steps) },
  ];
  const calsData = [
    { name: 'Completed', value: data.calories },
    { name: 'Remaining', value: Math.max(0, data.calorieGoal - data.calories) },
