        {notification && (
          <motion.div 
             initial={{ y: -50, opacity: 0 }}
             animate={{ y: 0, opacity: 1 }}
             exit={{ opacity: 0 }}
             className="fixed top-6 left-4 right-4 z-[100] mx-auto max-w-sm glass-panel bg-black/90 border-l-4 border-luxury-neon rounded-2xl p-4 shadow-2xl flex items-center gap-4"
