        <ResponsiveContainer width="90%" height="90%">
          <PieChart>
            <Pie data={stepsData} cx="50%" cy="50%" innerRadius="75%" outerRadius="85%" startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={10}><Cell fill="#CEF245" /><Cell fill="#1a1a1a" /></Pie>
            <Pie data={calsData} cx="50%" cy="50%" innerRadius="60%" outerRadius="70%" startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={10}><Cell fill="#eab308" /><Cell fill="#1a1a1a" /></Pie>
            <Pie data={distData} cx="50%" cy="50%" innerRadius="45%" outerRadius="55%" startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={10}><Cell fill="#ef4444" /><Cell fill="#1a1a1a" /></Pie>
          </PieChart>
        </ResponsiveContainer>
        <div className="absolute flex flex-col items-center justify-center pointer-events-none">
          <Footprints className="text-luxury-neon mb-1" size={20} />
          <span className="text-4xl font-black tracking-tighter text-white">{data.steps.toLocaleString()}</span>
          <span className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Steps</span>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="glass-panel p-4 rounded-2xl flex flex-col justify-between min-h-[110px] border border-white/5">
          <div className="flex justify-between items-start"><Flame className="text-luxury-gold" size={18} /><span className="text-[10px] text-gray-500 font-bold">KCAL</span></div>
          <div><span className="text-2xl font-black block text-white">{Math.floor(data.calories)}</span><span className="text-[10px] text-gray-400 font-bold uppercase">Burned</span></div>
        </div>
        <div className="glass-panel p-4 rounded-2xl flex flex-col justify-between min-h-[110px] border border-white/5">
          <div className="flex justify-between items-start"><MapPin className="text-red-500" size={18} /><span className="text-[10px] text-gray-500 font-bold">KM</span></div>
          <div><span className="text-2xl font-black block text-white">{data.distance.toFixed(2)}</span><span className="text-[10px] text-gray-400 font-bold uppercase">Covered</span></div>
        </div>
      </div>

      <div className="glass-panel p-5 rounded-3xl border border-white/5 flex flex-col">
        <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-6">Weekly Velocity</h3>
        <div className="w-full h-32">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data.history}>
              <XAxis dataKey="day" axisLine={false} tickLine={false} tick={{ fill: '#666', fontSize: 10 }} dy={10} />
