import React, { useState, useEffect } from 'react';
import { motion, useSpring, useTransform } from 'framer-motion';
import { UserMetrics } from '../types';
import useLocalStorage from '../hooks/useLocalStorage';
import { Ruler } from 'lucide-react';

const BMIHub: React.FC = () => {
  const [metrics, setMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [bmi, setBmi] = useState<number>(0);
  const [status, setStatus] = useState<string>('');

  const bmiSpring = useSpring(0, { stiffness: 60, damping: 15 });

  useEffect(() => {
    const heightInMeters = metrics.height / 100;
    const val = metrics.weight / (heightInMeters * heightInMeters);
    const clampedBmi = Math.min(Math.max(val, 10), 45);
    setBmi(Number(val.toFixed(1)));
    bmiSpring.set(clampedBmi);

    if (val < 18.5) setStatus('Underweight');
    else if (val < 25) setStatus('Normal');
    else if (val < 30) setStatus('Overweight');
    else setStatus('Obese');
  }, [metrics, bmiSpring]);

  const currentColor = (() => {
    switch (status) {
      case 'Underweight': return '#60a5fa';
      case 'Normal': return '#CEF245';
      case 'Overweight': return '#D4AF37';
      case 'Obese': return '#ef4444';
      default: return '#fff';
    }
  })();

  return (
    <div className="min-h-full w-full flex flex-col bg-black relative p-6 pb-32">
      <div className="pt-8 mb-8">
        <h2 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em] mb-1">Body Composition</h2>
        <h1 className="text-3xl font-black text-white">BIO<span className="text-luxury-neon">SCAN</span></h1>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center gap-12">
        <div className="w-full flex justify-center">
            <Gauge value={bmiSpring} color={currentColor} displayValue={bmi} />
        </div>

        <motion.div 
          key={status}
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="glass-panel w-full max-w-sm px-6 py-5 rounded-3xl border-l-4 flex justify-between items-center"
          style={{ borderColor: currentColor }}
        >
          <div>
            <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Diagnosis</h3>
            <p className="text-xl font-black" style={{ color: currentColor }}>{status}</p>
          </div>
          <div className="text-right">
            <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Ideal Range</h3>
            <p className="text-sm font-bold text-white">18.5 - 24.9</p>
          </div>
        </motion.div>
      </div>

      <div className="mt-12 space-y-8 w-full max-w-sm mx-auto">
        <div className="glass-panel p-6 rounded-3xl border border-white/5">
           <div className="flex justify-between items-center mb-6">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Weight (KG)</span>
              <span className="text-xl font-black text-luxury-neon">{metrics.weight}</span>
           </div>
           <input type="range" min={40} max={150} value={metrics.weight} 
             onChange={(e) => setMetrics(m => ({...m, weight: Number(e.target.value)}))}
             className="w-full h-1 bg-white/10 rounded-full appearance-none accent-luxury-neon" />
        </div>

        <div className="glass-panel p-6 rounded-3xl border border-white/5">
           <div className="flex justify-between items-center mb-6">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Height (CM)</span>
              <span className="text-xl font-black text-white">{metrics.height}</span>
           </div>
           <input type="range" min={140} max={220} value={metrics.height} 
             onChange={(e) => setMetrics(m => ({...m, height: Number(e.target.value)}))}
             className="w-full h-1 bg-white/10 rounded-full appearance-none accent-white" />
        </div>
      </div>
    </div>
  );
};

const Gauge = ({ value, color, displayValue }: { value: any, color: string, displayValue: number }) => {
  const rotation = useTransform(value, [10, 45], [-90, 90]);
  return (
    <div className="relative w-64 h-32">
       <svg className="w-full h-full overflow-visible" viewBox="0 0 200 100">
          <path d="M 20 100 A 80 80 0 0 1 180 100" fill="none" stroke="#111" strokeWidth="12" strokeLinecap="round" />
          <path d="M 20 100 A 80 80 0 0 1 180 100" fill="none" stroke={color} strokeWidth="12" strokeLinecap="round" strokeDasharray="180 500" className="opacity-20" />
          <motion.g style={{ rotate: rotation, originX: "100px", originY: "100px" }}>
             <path d="M 100 100 L 100 25" stroke={color} strokeWidth="4" strokeLinecap="round" />
             <circle cx="100" cy="100" r="6" fill={color} />
          </motion.g>
       </svg>
       <div className="absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-2 text-center">
          <span className="text-6xl font-black tracking-tighter text-white block">{displayValue}</span>
          <span className="text-[8px] text-gray-500 font-black uppercase tracking-[0.4em]">Current BMI</span>
       </div>
    </div>
  );
};

export default BMIHub;

import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { 
  auth, 
  subscribeToUserData, 
  updateUserActivity, 
  onAuthStateChanged, 
  User 
} from './services/firebase';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import DashboardSkeleton from './components/DashboardSkeleton';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import ChatBot from './components/ChatBot';
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserProfile, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';
import { updateStreak } from './services/streakService';
import { calculateAdaptiveGoals } from './services/goalService';
import { Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingAuth, setLoadingAuth] = useState(true);
  const [loadingData, setLoadingData] = useState(false);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  const { isTracking, toggleTracking, liveSteps, resetLiveSteps, status } = usePedometer();

  const [adaptiveGoalsEnabled, setAdaptiveGoalsEnabled] = useLocalStorage<boolean>('adaptive_goals_enabled', false);
  const [showGoalToast, setShowGoalToast] = useState(false);

  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0,
    calories: 0,
    distance: 0,
    stepGoal: 10000,
    calorieGoal: 2000,
    distanceGoal: 5.0,
    history: [
      { day: 'Mon', steps: 0 }, { day: 'Tue', steps: 0 }, { day: 'Wed', steps: 0 },
      { day: 'Thu', steps: 0 }, { day: 'Fri', steps: 0 }, { day: 'Sat', steps: 0 }, { day: 'Sun', steps: 0 },
    ]
  });

  const [bmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);

  useEffect(() => {
    const unsubscribeAuth = onAuthStateChanged(auth, (user) => {
      setCurrentUser(user);
      if (user) {
        setLoadingData(true);
        const unsubscribeData = subscribeToUserData(user.uid, (data) => {
            if (data) {
                setUserProfile({
                    name: data.name,
                    email: data.email,
                    avatarUrl: data.avatarUrl
                });

                if (data.currentActivity) {
                   setActivityData(prev => ({
                     ...prev,
                     ...data.currentActivity,
                     stepGoal: data.goals?.stepGoal || prev.stepGoal,
                     calorieGoal: data.goals?.calorieGoal || prev.calorieGoal,
                     distanceGoal: data.goals?.distanceGoal || prev.distanceGoal
                   }));
                }
            }
            setLoadingData(false);
        });
        setLoadingAuth(false);
        return () => unsubscribeData();
      } else {
        setUserProfile(null);
        setLoadingAuth(false);
        setLoadingData(false);
      }
    });

    return () => unsubscribeAuth();
  }, []);

  useEffect(() => {
    if (currentUser && adaptiveGoalsEnabled && !loadingData) {
        const streakInfo = updateStreak();
        const lastAdaptationKey = `last_adaptation_${currentUser.uid}`;
        const today = new Date().toISOString().split('T')[0];
        const lastAdaptation = localStorage.getItem(lastAdaptationKey);

        if (lastAdaptation !== today) {
            const proposedGoals = calculateAdaptiveGoals(activityData, streakInfo.currentStreak);
            if (proposedGoals) {
                setActivityData(prev => ({ ...prev, ...proposedGoals }));
                updateUserActivity(currentUser.uid, {}, proposedGoals);
                localStorage.setItem(lastAdaptationKey, today);
                setShowGoalToast(true);
                setTimeout(() => setShowGoalToast(false), 5000);
            }
        }
    }
  }, [currentUser, adaptiveGoalsEnabled, loadingData, activityData]);

  useEffect(() => {
    if (liveSteps > 0 && currentUser) {
       const addedCalories = 0.04;
       const addedDistance = 0.00076;
       const newSteps = activityData.steps + 1;
       const newCals = activityData.calories + addedCalories;
       const newDist = activityData.distance + addedDistance;
       const updatedHistory = [...activityData.history];
       updatedHistory[6] = { ...updatedHistory[6], steps: updatedHistory[6].steps + 1 };

       const newData = {
          steps: newSteps,
          calories: newCals,
          distance: newDist,
          history: updatedHistory,
          stepGoal: activityData.stepGoal,
          calorieGoal: activityData.calorieGoal,
          distanceGoal: activityData.distanceGoal
       };

       setActivityData(newData);
       resetLiveSteps();
       updateUserActivity(currentUser.uid, newData);
    }
  }, [liveSteps, currentUser, activityData, resetLiveSteps]);

  const handleAddToHistory = (item: FoodHistoryItem) => {
    setFoodHistory(prev => [item, ...prev]);
    if (currentUser) {
       const newCalories = activityData.calories + item.analysis.macros.calories;
       setActivityData(prev => ({ ...prev, calories: newCalories }));
       updateUserActivity(currentUser.uid, { ...activityData, calories: newCalories });
    }
  };

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => {
    setActivityData(prev => ({ ...prev, ...newGoals }));
    if (currentUser) {
        updateUserActivity(currentUser.uid, {}, { ...activityData, ...newGoals });
    }
  };

  if (loadingAuth) {
     return <div className="h-screen w-full bg-black flex items-center justify-center text-luxury-neon animate-pulse font-medium tracking-widest text-xs uppercase">Elite Session Sync...</div>;
  }

  if (!currentUser) {
    return <Auth onLoginSuccess={() => {}} />;
  }

  return (
    <div className="min-h-screen bg-black text-white relative overflow-hidden font-sans selection:bg-luxury-neon selection:text-black">
      {/* Luxury Atmospheric Leaks */}
      <div className="fixed top-[-10%] right-[-5%] w-[60vh] h-[60vh] bg-luxury-neon/5 rounded-full blur-[120px] pointer-events-none z-0 animate-leak-1"></div>
      <div className="fixed bottom-[-10%] left-[-5%] w-[50vh] h-[50vh] bg-luxury-gold/5 rounded-full blur-[100px] pointer-events-none z-0 animate-leak-2"></div>

      {/* Adaptive Goal Toast - Ultra Refined */}
      <AnimatePresence>
        {showGoalToast && (
          <motion.div 
            initial={{ y: -100, opacity: 0 }}
            animate={{ y: 20, opacity: 1 }}
            exit={{ y: -100, opacity: 0 }}
            className="fixed left-6 right-6 z-[60] glass-panel bg-white/5 border border-luxury-neon/20 p-4 rounded-2xl flex items-center gap-4 shadow-2xl"
          >
             <div className="p-2 bg-luxury-neon text-black rounded-xl shrink-0">
               <Sparkles size={20} />
             </div>
             <div>
               <h4 className="text-[10px] font-black text-luxury-neon uppercase tracking-[0.2em]">System Optimized</h4>
               <p className="text-white text-xs font-medium">Metric targets calibrated for peak performance.</p>
             </div>
          </motion.div>
        )}
      </AnimatePresence>

      <main className="relative z-10 h-screen overflow-y-auto no-scrollbar pb-32">
        <div className="h-[env(safe-area-inset-top, 24px)]" />

        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && (
             loadingData ? (
                 <motion.div key="skeleton" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                    <DashboardSkeleton />
                 </motion.div>
             ) : (
                 <Dashboard 
                    key="dashboard"
                    data={activityData} 
                    onUpdateGoals={handleUpdateGoals} 
                    isTracking={isTracking}
                    onToggleTracking={toggleTracking}
                    status={status}
                    adaptiveGoalsEnabled={adaptiveGoalsEnabled}
                    onToggleAdaptiveGoals={setAdaptiveGoalsEnabled}
                 />
             )
          )}
          {currentView === ViewState.FOOD_LENS && (
            <motion.div key="foodlens" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="h-full">
               <FoodLens history={foodHistory} onAddToHistory={handleAddToHistory} />
            </motion.div>
          )}
          {currentView === ViewState.BMI_HUB && (
            <motion.div key="bmi" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="h-full">
               <BMIHub />
            </motion.div>
          )}
          {currentView === ViewState.CHAT && (
            <motion.div key="chat" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="h-full">
               <ChatBot metrics={bmiMetrics} activity={activityData} />
            </motion.div>
          )}
        </AnimatePresence>
      </main>

      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

