             className="fixed top-10 left-8 right-8 z-[100] mx-auto max-w-sm glass-card p-4 rounded-2xl flex items-center gap-4 shadow-2xl"
          >
             <div className="p-2 bg-luxury-neon/20 rounded-xl">
