import React, { useState, useEffect } from 'react';
import { motion, useSpring, useTransform } from 'framer-motion';
import { UserMetrics } from '../types';
import useLocalStorage from '../hooks/useLocalStorage';

const BMIHub: React.FC = () => {
  const [metrics, setMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [bmi, setBmi] = useState<number>(0);
  const [status, setStatus] = useState<string>('');

  const bmiSpring = useSpring(0, { stiffness: 45, damping: 20 });

  useEffect(() => {
    const heightInMeters = metrics.height / 100;
    const val = metrics.weight / (heightInMeters * heightInMeters);
    const clampedBmi = Math.min(Math.max(val, 10), 45);
    setBmi(Number(val.toFixed(1)));
    bmiSpring.set(clampedBmi);

    if (val < 18.5) setStatus('Underweight');
    else if (val < 25) setStatus('Normal');
    else if (val < 30) setStatus('Overweight');
    else setStatus('Obese');
  }, [metrics, bmiSpring]);

  const currentColor = (() => {
    switch (status) {
      case 'Underweight': return '#60a5fa';
      case 'Normal': return '#CEF245';
      case 'Overweight': return '#D4AF37';
      case 'Obese': return '#ef4444';
      default: return '#fff';
    }
  })();

  return (
    <div className="min-h-full w-full flex flex-col bg-black relative p-8 pb-32">
      <div className="pt-10 mb-10">
        <h2 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.5em] mb-2">Biometric Analysis</h2>
        <h1 className="text-4xl font-black text-white leading-none tracking-tight">BIO<span className="text-luxury-neon neon-glow-text">SCAN</span></h1>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center gap-16">
        <div className="w-full flex justify-center">
            <ChronometerGauge value={bmiSpring} color={currentColor} displayValue={bmi} />
        </div>

        <motion.div 
          key={status}
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          className="glass-card w-full max-w-sm px-8 py-6 rounded-[2.5rem] flex justify-between items-center shadow-2xl relative overflow-hidden"
        >
          <div className="absolute top-0 left-0 w-1 h-full" style={{ backgroundColor: currentColor }}></div>
          <div>
            <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mb-1">Health Index</h3>
            <p className="text-2xl font-black" style={{ color: currentColor }}>{status}</p>
          </div>
          <div className="text-right">
            <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] mb-1">Optimal Range</h3>
            <p className="text-sm font-bold text-white">18.5 — 24.9</p>
          </div>
        </motion.div>
      </div>

      {/* Tactile High-End Sliders */}
      <div className="mt-16 space-y-10 w-full max-w-sm mx-auto">
        <div className="relative">
           <div className="flex justify-between items-end mb-4">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em]">Mass (KG)</span>
              <span className="text-3xl font-black text-luxury-neon">{metrics.weight}</span>
           </div>
           <input type="range" min={40} max={150} value={metrics.weight} 
             onChange={(e) => setMetrics(m => ({...m, weight: Number(e.target.value)}))}
             className="w-full" />
           <div className="flex justify-between mt-2 px-1">
              {[40, 60, 80, 100, 120, 150].map(v => <span key={v} className="text-[8px] text-gray-700 font-bold">{v}</span>)}
           </div>
        </div>

        <div className="relative">
           <div className="flex justify-between items-end mb-4">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em]">Vertical (CM)</span>
              <span className="text-3xl font-black text-white">{metrics.height}</span>
           </div>
           <input type="range" min={140} max={220} value={metrics.height} 
             onChange={(e) => setMetrics(m => ({...m, height: Number(e.target.value)}))}
             className="w-full" />
           <div className="flex justify-between mt-2 px-1">
              {[140, 160, 180, 200, 220].map(v => <span key={v} className="text-[8px] text-gray-700 font-bold">{v}</span>)}
           </div>
        </div>
      </div>
    </div>
  );
};

const ChronometerGauge = ({ value, color, displayValue }: { value: any, color: string, displayValue: number }) => {
  const rotation = useTransform(value, [10, 45], [-90, 90]);

  return (
    <div className="relative w-72 h-36">
       <svg className="w-full h-full overflow-visible" viewBox="0 0 200 100">
          {/* Main Track */}
          <path d="M 20 100 A 80 80 0 0 1 180 100" fill="none" stroke="#0A0A0A" strokeWidth="1" />

          {/* Ticks (Every 5 BMI) */}
          {[10, 15, 20, 25, 30, 35, 40, 45].map((tick) => {
            const angle = ((tick - 10) / 35) * 180 - 180;
            const r = 80;
            const x1 = 100 + (r - 10) * Math.cos((angle * Math.PI) / 180);
            const y1 = 100 + (r - 10) * Math.sin((angle * Math.PI) / 180);
            const x2 = 100 + r * Math.cos((angle * Math.PI) / 180);
            const y2 = 100 + r * Math.sin((angle * Math.PI) / 180);
            return <line key={tick} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#333" strokeWidth="2" />;
          })}

          {/* Glowing Lightbeam Needle */}
          <motion.g style={{ rotate: rotation, originX: "100px", originY: "100px" }}>
             <defs>
                <linearGradient id="beam" x1="0" y1="0" x2="0" y2="1">
                   <stop offset="0%" stopColor={color} stopOpacity="0.8" />
                   <stop offset="100%" stopColor={color} stopOpacity="0" />
                </linearGradient>
             </defs>
             <path d="M 100 100 L 98 25 L 102 25 Z" fill="url(#beam)" />
             <line x1="100" y1="100" x2="100" y2="25" stroke={color} strokeWidth="1.5" strokeLinecap="round" className="filter drop-shadow-[0_0_5px_rgba(255,255,255,0.8)]" />
             <circle cx="100" cy="100" r="4" fill="#000" stroke={color} strokeWidth="2" />
          </motion.g>
       </svg>

       <div className="absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-6 text-center">
          <span className="text-7xl font-black tracking-tighter text-white block leading-none">{displayValue}</span>
          <p className="text-[10px] text-gray-600 font-black uppercase tracking-[0.5em] mt-2">Active Bio Index</p>
       </div>
    </div>
  );
};

export default BMIHub;

import React, { useRef, useState, useEffect } from 'react';
import { Camera, ArrowLeft, History, Loader2, Scan, BrainCircuit, Activity } from 'lucide-react';
import { analyzeFoodImage } from '../services/geminiService';
import { FoodAnalysis, FoodHistoryItem } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

interface FoodLensProps {
  history: FoodHistoryItem[];
  onAddToHistory: (item: FoodHistoryItem) => void;
}

const FoodLens: React.FC<FoodLensProps> = ({ history, onAddToHistory }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<FoodAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showHistory, setShowHistory] = useState(false);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }
      });
      setStream(mediaStream);
    } catch (err) {
      setError("AI Vision requires camera access.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    if (!showHistory && !result) startCamera();
    else stopCamera();
    return () => stopCamera();
  }, [showHistory, result]);

  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
      videoRef.current.play().catch(e => console.error(e));
    }
  }, [stream]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || analyzing) return;
    setAnalyzing(true);

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.9);
        try {
            await new Promise(r => setTimeout(r, 2500)); // Dramatic AI effect
            const data = await analyzeFoodImage(base64);
            onAddToHistory({ id: Date.now().toString(), timestamp: Date.now(), analysis: data });
            setResult(data);
        } catch (err) {
            setError("Analysis Protocol Failure.");
        } finally {
            setAnalyzing(false);
        }
    }
  };

  const getColorClass = (code: string) => {
    switch(code) {
      case 'green': return 'text-luxury-neon border-luxury-neon';
      case 'yellow': return 'text-luxury-gold border-luxury-gold';
      case 'red': return 'text-red-500 border-red-500';
