import { GoogleGenAI, Type, Content } from "@google/genai";
import { FoodAnalysis, UserMetrics, ActivityData } from "../types";

// Initialize the Google GenAI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const foodResponseSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "Name of the food item" },
    macros: {
      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      },
      required: ["calories", "protein", "fat", "carbs"]
    },
    healthScore: { type: Type.NUMBER, description: "Score from 0-100" },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING, description: "Short nutritional tip" },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] },
    boundingBox: {
      type: Type.ARRAY,
      items: { type: Type.NUMBER },
      description: "Bounding box in [ymin, xmin, ymax, xmax] format (0-1)."
    }
  },
  required: ["name", "macros", "healthScore", "verdict", "advice", "colorCode"]
};

/**
 * Analyze food image using gemini-2.5-flash for multimodal vision capabilities
 */
export const analyzeFoodImage = async (base64Image: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] 
            }
          },
          { text: "Analyze this meal. Identify ingredients and provide strict nutrition JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: foodResponseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Image Analysis Error:", error);
    return getFallbackAnalysis("Scan failed. Ensure clear image.");
  }
};

/**
 * Analyze food description text
 */
export const analyzeFoodText = async (query: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Estimate nutrition for: ${query}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: foodResponseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Text Analysis Error:", error);
    return getFallbackAnalysis("Manual entry failed.");
  }
};

/**
 * Get the streaming coach chat with persistent context history.
 */
export const getCoachChatStream = async (
  message: string, 
  history: Content[],
  metrics: UserMetrics,
  activity: ActivityData
) => {
  const systemInstruction = `You are the Healthy.hub Elite Professional Trainer.

  CORE MEMORY & CONTEXT:
  - User Height: ${metrics.height}cm | Weight: ${metrics.weight}kg
  - Today's Activity: ${activity.steps} steps
  - You MUST remember equipment lists, injuries, or dietary preferences mentioned in previous messages.

  BEHAVIORAL PROTOCOLS:
  1. If the user asks for a workout, FIRST check if you know their equipment. If not, ask: "What equipment do you have available?"
  2. Maintain a "Tough Love" but "Luxury Service" persona. Concise, high-value advice.
  3. MANDATORY DISCLAIMER: End every response with: "⚠️ Consult a professional before starting."
  `;

  // We recreate the chat object with the full history to ensure stateful behavior in this stateless function call.
  // The SDK manages the concatenation of the new message.
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: systemInstruction,
      temperature: 0.7,
    },
    history: history,
  });

  return await chat.sendMessageStream({ message });
};

const getFallbackAnalysis = (reason: string): FoodAnalysis => ({
  name: "System Offline",
  macros: { calories: 0, protein: 0, fat: 0, carbs: 0 },
  healthScore: 0,
  verdict: "Avoid",
  advice: reason,
  colorCode: "red"
});

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, User, Bot, Sparkles, Loader2, Dumbbell, Signal } from 'lucide-react';
import { getCoachChatStream } from '../services/geminiService';
import { ChatMessage, UserMetrics, ActivityData } from '../types';
import { Content } from '@google/genai';

interface ChatBotProps {
  metrics: UserMetrics;
  activity: ActivityData;
}

const ChatBot: React.FC<ChatBotProps> = ({ metrics, activity }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Simulate initial connection to "Elite Coach Network"
    const timer = setTimeout(() => setIsLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isTyping, isLoading]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userText = input;
    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: userText,
      timestamp: Date.now(),
    };

    // Update UI immediately
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      // Filter history: remove errors, empty messages, and ensure strict role alternation if needed.
      // We map our ChatMessage type to the SDK's Content type.
      const history: Content[] = messages
        .filter(m => m.id !== 'error' && m.text.trim() !== '')
        .map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        }));

      const stream = await getCoachChatStream(userText, history, metrics, activity);

      const coachMessageId = (Date.now() + 1).toString();
      let coachText = '';

      setMessages(prev => [...prev, {
        id: coachMessageId,
        role: 'model',
        text: '',
        timestamp: Date.now(),
      }]);

      for await (const chunk of stream) {
        // Safe access to text
        const newText = chunk.text || '';
        coachText += newText;

        setMessages(prev => prev.map(m => 
          m.id === coachMessageId ? { ...m, text: coachText } : m
        ));
      }
    } catch (error) {
      console.error("Coach Chat Error:", error);
      setMessages(prev => [...prev, {
        id: 'error',
        role: 'model',
        text: "Connection to Elite Server interrupted. Please retry. \n\n⚠️ Note: Please cross-verify this plan with a certified medical or fitness professional before starting.",
        timestamp: Date.now(),
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (isLoading) {
    return (
      <div className="h-full w-full flex flex-col bg-[#050505] animate-fade-in relative">
         <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 bg-black/40">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-full bg-white/5 animate-pulse"></div>
              <div className="space-y-2">
                <div className="w-32 h-4 bg-white/5 rounded animate-pulse"></div>
                <div className="w-20 h-2 bg-white/5 rounded animate-pulse"></div>
              </div>
            </div>
         </div>
         <div className="flex-1 flex flex-col items-center justify-center p-8 text-center space-y-6">
             <div className="relative">
                <div className="w-24 h-24 rounded-full border-4 border-white/5 flex items-center justify-center animate-spin-slow">
                   <div className="w-20 h-20 rounded-full border-4 border-t-luxury-neon border-r-transparent border-b-transparent border-l-transparent"></div>
                </div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <Signal className="text-luxury-neon animate-pulse" size={32} />
                </div>
             </div>
             <div>
                <h3 className="text-lg font-bold text-white mb-2">Establishing Secure Link</h3>
                <p className="text-gray-500 text-xs uppercase tracking-widest">Connecting to Elite Coach AI...</p>
             </div>
         </div>
      </div>
    );
  }

  return (
    <div className="h-full w-full flex flex-col bg-[#050505] animate-fade-in relative">
      <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 backdrop-blur-md bg-black/40">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-full bg-luxury-neon/10 flex items-center justify-center border border-luxury-neon/30 shadow-[0_0_20px_rgba(0,230,118,0.2)]">
            <Dumbbell className="text-luxury-neon" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-white tracking-tight">Gemini AI Coach</h1>
            <div className="flex items-center gap-1.5">
              <span className="w-2 h-2 rounded-full bg-luxury-neon animate-pulse"></span>
              <p className="text-[10px] text-luxury-neon uppercase tracking-widest font-black">Professional Elite</p>
            </div>
          </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar pb-36">
        {messages.length === 0 && (
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="h-full flex flex-col items-center justify-center text-center space-y-6 px-8">
            <div className="p-6 bg-luxury-grey rounded-full border border-white/10">
              <Sparkles className="text-luxury-gold" size={48} />
            </div>
            <div className="space-y-2">
              <h3 className="text-2xl font-bold text-white">Elite AI Consultation</h3>
              <p className="text-gray-400 text-sm">Welcome back, Alex. I remember your metrics. Let's optimize your performance.</p>
            </div>
            <div className="grid grid-cols-1 gap-3 w-full max-w-xs">
              {["Suggest a workout plan", "Create a fat-loss diet"].map((suggestion, idx) => (
                <button key={idx} onClick={() => setInput(suggestion)} className="px-4 py-3 rounded-2xl bg-luxury-grey border border-white/5 text-xs text-gray-300 hover:border-luxury-neon hover:text-white transition-all active:scale-95">
                  {suggestion}
                </button>
              ))}
            </div>
          </motion.div>
        )}

        <AnimatePresence initial={false}>
          {messages.map((msg) => (
            <motion.div key={msg.id} initial={{ opacity: 0, y: 15, scale: 0.98 }} animate={{ opacity: 1, y: 0, scale: 1 }} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`max-w-[85%] p-4 rounded-2xl shadow-xl leading-relaxed whitespace-pre-wrap ${msg.role === 'user' ? 'bg-luxury-neon text-black font-semibold rounded-br-none shadow-[0_4px_15px_rgba(0,230,118,0.2)]' : 'bg-luxury-grey text-white border border-white/5 rounded-bl-none'}`}>
                <p className="text-sm">{msg.text}</p>
                {msg.role === 'model' && msg.text === '' && (
                  <div className="flex gap-1 py-1">
                    <span className="w-1.5 h-1.5 bg-luxury-gold rounded-full animate-bounce"></span>
                    <span className="w-1.5 h-1.5 bg-luxury-gold rounded-full animate-bounce delay-100"></span>
                    <span className="w-1.5 h-1.5 bg-luxury-gold rounded-full animate-bounce delay-200"></span>
                  </div>
                )}
              </div>
              <span className="text-[10px] text-gray-600 mt-2 px-1">
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      <div className="fixed bottom-24 left-4 right-4 z-20">
        <form onSubmit={handleSend} className="glass-panel p-2 rounded-3xl border border-white/10 focus-within:border-luxury-neon/40 transition-all flex items-center shadow-2xl bg-black/40">
          <div className="flex-1 px-4 py-2">
            <input type="text" value={input} onChange={(e) => setInput(e.target.value)} placeholder="Ask for an elite training plan..." className="w-full bg-transparent border-none outline-none text-sm text-white placeholder-gray-500 font-medium" />
          </div>
          <motion.button whileTap={{ scale: 0.9 }} whileHover={{ scale: 1.05 }} type="submit" disabled={!input.trim() || isTyping} className="w-12 h-12 rounded-2xl bg-luxury-neon text-black flex items-center justify-center disabled:opacity-30 disabled:grayscale transition-all shadow-[0_4px_15px_rgba(0,230,118,0.3)]">
            {isTyping ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
          </motion.button>
        </form>
      </div>
    </div>
  );
};

export default ChatBot;

import React, { useRef, useState, useEffect } from 'react';
import { ArrowLeft, History, Loader2, Scan, BrainCircuit, Zap, X, ChevronUp, Share2 } from 'lucide-react';
import { analyzeFoodImage } from '../services/geminiService';
import { FoodAnalysis, FoodHistoryItem } from '../types';
import { motion, AnimatePresence, useAnimation } from 'framer-motion';

interface FoodLensProps {
  history: FoodHistoryItem[];
  onAddToHistory: (item: FoodHistoryItem) => void;
}

const FoodLens: React.FC<FoodLensProps> = ({ history, onAddToHistory }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<FoodAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showHistory, setShowHistory] = useState(false);
  const scanLineControls = useAnimation();

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }
      });
      setStream(mediaStream);
    } catch (err) {
      setError("AI Vision requires camera access.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    if (!showHistory) startCamera();
    return () => stopCamera();
  }, [showHistory]);

  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
      videoRef.current.play().catch(e => console.error(e));
    }
  }, [stream]);

  useEffect(() => {
    if (analyzing) {
      scanLineControls.start({
        top: ["0%", "100%"],
        transition: { duration: 1.5, repeat: Infinity, ease: "linear" }
      });
    } else {
      scanLineControls.stop();
    }
  }, [analyzing, scanLineControls]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || analyzing) return;
    setAnalyzing(true);
    if (navigator.vibrate) navigator.vibrate(50);

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.85);
        try {
            await new Promise(r => setTimeout(r, 2000)); // Dramatic Scan Effect
            const data = await analyzeFoodImage(base64);
            onAddToHistory({ id: Date.now().toString(), timestamp: Date.now(), analysis: data });
            setResult(data);
            if (navigator.vibrate) navigator.vibrate([100, 50, 100]);
        } catch (err) {
            setError("Analysis Protocol Failure.");
        } finally {
            setAnalyzing(false);
        }
    }
