import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, User, Bot, Sparkles, Loader2, Dumbbell, Signal, Trash2 } from 'lucide-react';
import { getCoachChatStream } from '../services/geminiService';
import { ChatMessage, UserMetrics, ActivityData } from '../types';
import { Content } from '@google/genai';
import useLocalStorage from '../hooks/useLocalStorage';

interface ChatBotProps {
  metrics: UserMetrics;
  activity: ActivityData;
}

const ChatBot: React.FC<ChatBotProps> = ({ metrics, activity }) => {
  // Use LocalStorage to persist chat history across view changes
  const [messages, setMessages] = useLocalStorage<ChatMessage[]>('chat_history', []);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Simulate initial connection to "Elite Coach Network"
    const timer = setTimeout(() => setIsLoading(false), 1500);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isTyping, isLoading]);

  const handleClearChat = () => {
    if (confirm('Clear encrypted session history?')) {
        setMessages([]);
    }
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userText = input;
    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: userText,
      timestamp: Date.now(),
    };

    // Update UI immediately
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      // Filter history: remove errors and empty messages to ensure clean context for Gemini
      const history: Content[] = messages
        .filter(m => m.id !== 'error' && m.text.trim() !== '')
        .map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        }));

      // Pass the updated history + userText to the service
      const stream = await getCoachChatStream(userText, history, metrics, activity);

      const coachMessageId = (Date.now() + 1).toString();
      let coachText = '';

      setMessages(prev => [...prev, {
        id: coachMessageId,
        role: 'model',
        text: '',
        timestamp: Date.now(),
      }]);

      for await (const chunk of stream) {
        const newText = chunk.text || '';
        coachText += newText;

        setMessages(prev => prev.map(m => 
          m.id === coachMessageId ? { ...m, text: coachText } : m
        ));
      }
    } catch (error) {
      console.error("Coach Chat Error:", error);
      setMessages(prev => [...prev, {
        id: 'error',
        role: 'model',
        text: "Connection to Elite Server interrupted. Please retry. \n\n⚠️ Note: Please cross-verify this plan with a certified medical or fitness professional before starting.",
        timestamp: Date.now(),
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (isLoading) {
    return (
      <div className="h-full w-full flex flex-col bg-[#050505] animate-fade-in relative">
         <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 bg-black/40">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-full bg-white/5 animate-pulse"></div>
              <div className="space-y-2">
                <div className="w-32 h-4 bg-white/5 rounded animate-pulse"></div>
                <div className="w-20 h-2 bg-white/5 rounded animate-pulse"></div>
              </div>
            </div>
         </div>
         <div className="flex-1 flex flex-col items-center justify-center p-8 text-center space-y-6">
             <div className="relative">
                <div className="w-24 h-24 rounded-full border-4 border-white/5 flex items-center justify-center animate-spin-slow">
                   <div className="w-20 h-20 rounded-full border-4 border-t-luxury-neon border-r-transparent border-b-transparent border-l-transparent"></div>
                </div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <Signal className="text-luxury-neon animate-pulse" size={32} />
                </div>
             </div>
             <div>
                <h3 className="text-lg font-bold text-white mb-2">Establishing Secure Link</h3>
                <p className="text-gray-500 text-xs uppercase tracking-widest">Connecting to Elite Coach AI...</p>
             </div>
         </div>
      </div>
    );
  }

  return (
    <div className="h-full w-full flex flex-col bg-[#050505] animate-fade-in relative">
      <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 backdrop-blur-md bg-black/40">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-full bg-luxury-neon/10 flex items-center justify-center border border-luxury-neon/30 shadow-[0_0_20px_rgba(0,230,118,0.2)]">
            <Dumbbell className="text-luxury-neon" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-white tracking-tight">Gemini AI Coach</h1>
            <div className="flex items-center gap-1.5">
              <span className="w-2 h-2 rounded-full bg-luxury-neon animate-pulse"></span>
              <p className="text-[10px] text-luxury-neon uppercase tracking-widest font-black">Professional Elite</p>
            </div>
          </div>
        </div>
        <button onClick={handleClearChat} className="p-3 rounded-full bg-white/5 text-gray-400 hover:text-red-400 hover:bg-white/10 transition-colors">
            <Trash2 size={18} />
        </button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar pb-36">
        {messages.length === 0 && (
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="h-full flex flex-col items-center justify-center text-center space-y-6 px-8">
            <div className="p-6 bg-luxury-grey rounded-full border border-white/10">
              <Sparkles className="text-luxury-gold" size={48} />
            </div>
            <div className="space-y-2">
              <h3 className="text-2xl font-bold text-white">Elite AI Consultation</h3>
              <p className="text-gray-400 text-sm">Welcome back. I have access to your biometrics. How can we optimize your performance today?</p>
            </div>
            <div className="grid grid-cols-1 gap-3 w-full max-w-xs">
              {["Suggest a HIIT workout", "Meal plan for muscle gain", "Analyze my recovery needs"].map((suggestion, idx) => (
                <button key={idx} onClick={() => setInput(suggestion)} className="px-4 py-3 rounded-2xl bg-luxury-grey border border-white/5 text-xs text-gray-300 hover:border-luxury-neon hover:text-white transition-all active:scale-95 text-left flex justify-between items-center group">
                  {suggestion}
                  <ArrowRight size={14} className="opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all text-luxury-neon" />
                </button>
              ))}
            </div>
          </motion.div>
        )}

        <AnimatePresence initial={false}>
          {messages.map((msg) => (
            <motion.div key={msg.id} initial={{ opacity: 0, y: 15, scale: 0.98 }} animate={{ opacity: 1, y: 0, scale: 1 }} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`max-w-[85%] p-4 rounded-2xl shadow-xl leading-relaxed whitespace-pre-wrap ${msg.role === 'user' ? 'bg-luxury-neon text-black font-semibold rounded-br-none shadow-[0_4px_15px_rgba(0,230,118,0.2)]' : 'bg-luxury-grey text-white border border-white/5 rounded-bl-none'}`}>
                <p className="text-sm">{msg.text}</p>
                {msg.role === 'model' && msg.text === '' && (
                  <div className="flex gap-1 py-1">
                    <span className="w-1.5 h-1.5 bg-luxury-gold rounded-full animate-bounce"></span>
                    <span className="w-1.5 h-1.5 bg-luxury-gold rounded-full animate-bounce delay-100"></span>
                    <span className="w-1.5 h-1.5 bg-luxury-gold rounded-full animate-bounce delay-200"></span>
                  </div>
                )}
              </div>
              <span className="text-[10px] text-gray-600 mt-2 px-1">
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      <div className="fixed bottom-24 left-4 right-4 z-20">
        <form onSubmit={handleSend} className="glass-panel p-2 rounded-3xl border border-white/10 focus-within:border-luxury-neon/40 transition-all flex items-center shadow-2xl bg-black/80 backdrop-blur-md">
          <div className="flex-1 px-4 py-2">
            <input type="text" value={input} onChange={(e) => setInput(e.target.value)} placeholder="Type a message..." className="w-full bg-transparent border-none outline-none text-sm text-white placeholder-gray-500 font-medium" />
          </div>
          <motion.button whileTap={{ scale: 0.9 }} whileHover={{ scale: 1.05 }} type="submit" disabled={!input.trim() || isTyping} className="w-12 h-12 rounded-2xl bg-luxury-neon text-black flex items-center justify-center disabled:opacity-30 disabled:grayscale transition-all shadow-[0_4px_15px_rgba(0,230,118,0.3)]">
            {isTyping ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
          </motion.button>
        </form>
      </div>
    </div>
  );
};

