import { GoogleGenAI, Type, Content } from "@google/genai";
import { FoodAnalysis, UserMetrics, ActivityData } from "../types";

// Initialize the Google GenAI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const foodResponseSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "Name of the food item" },
    macros: {
      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      },
      required: ["calories", "protein", "fat", "carbs"]
    },
    healthScore: { type: Type.NUMBER, description: "Score from 0-100" },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING, description: "Short nutritional tip" },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] },
    boundingBox: {
      type: Type.ARRAY,
      items: { type: Type.NUMBER },
      description: "Bounding box in [ymin, xmin, ymax, xmax] format (0-1)."
    }
  },
  required: ["name", "macros", "healthScore", "verdict", "advice", "colorCode"]
};

/**
 * Analyze food image using gemini-2.5-flash for multimodal vision capabilities
 */
export const analyzeFoodImage = async (base64Image: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] 
            }
          },
          { text: "Analyze this meal. Identify ingredients and provide strict nutrition JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: foodResponseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Image Analysis Error:", error);
    return getFallbackAnalysis("Scan failed. Ensure clear image.");
  }
};

/**
 * Analyze food description text
 */
export const analyzeFoodText = async (query: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Estimate nutrition for: ${query}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: foodResponseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Text Analysis Error:", error);
    return getFallbackAnalysis("Manual entry failed.");
  }
};

/**
 * Get the streaming coach chat with persistent context history.
 * @param message Current user message
 * @param history Previous conversation history (Content objects)
 * @param metrics User biometric data
 * @param activity User activity data
 */
export const getCoachChatStream = async (
  message: string, 
  history: Content[],
  metrics: UserMetrics,
  activity: ActivityData
) => {
  const systemInstruction = `You are the Healthy.hub Elite Professional Trainer.

  CORE MEMORY & CONTEXT:
  - User Height: ${metrics.height}cm | Weight: ${metrics.weight}kg
  - Today's Activity: ${activity.steps} steps
  - You MUST remember equipment lists, injuries, or dietary preferences mentioned in previous messages.

  BEHAVIORAL PROTOCOLS:
  1. If the user asks for a workout, FIRST check if you know their equipment. If not, ask: "What equipment do you have available?"
  2. Maintain a "Tough Love" but "Luxury Service" persona. Concise, high-value advice.
  3. MANDATORY DISCLAIMER: End every response with: "⚠️ Consult a professional before starting."
  `;

  // We recreate the chat object with the full history to ensure stateful behavior.
  // The SDK automatically appends the new message to this history context.
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: systemInstruction,
      temperature: 0.7,
    },
    history: history,
  });

  return await chat.sendMessageStream({ message });
};

const getFallbackAnalysis = (reason: string): FoodAnalysis => ({
  name: "System Offline",
  macros: { calories: 0, protein: 0, fat: 0, carbs: 0 },
  healthScore: 0,
  verdict: "Avoid",
  advice: reason,
  colorCode: "red"
});

import React, { useRef, useState, useEffect } from 'react';
import { ArrowLeft, History, Loader2, Scan, BrainCircuit, Zap, X, ChevronUp, Share2 } from 'lucide-react';
import { analyzeFoodImage } from '../services/geminiService';
import { FoodAnalysis, FoodHistoryItem } from '../types';
import { motion, AnimatePresence, useAnimation } from 'framer-motion';

interface FoodLensProps {
  history: FoodHistoryItem[];
  onAddToHistory: (item: FoodHistoryItem) => void;
}

const FoodLens: React.FC<FoodLensProps> = ({ history, onAddToHistory }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<FoodAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showHistory, setShowHistory] = useState(false);
  const scanLineControls = useAnimation();

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }
      });
      setStream(mediaStream);
    } catch (err) {
      setError("AI Vision requires camera access.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    if (!showHistory) startCamera();
    return () => stopCamera();
  }, [showHistory]);

  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
      videoRef.current.play().catch(e => console.error(e));
    }
  }, [stream]);

  useEffect(() => {
    if (analyzing) {
      scanLineControls.start({
        top: ["0%", "100%"],
        transition: { duration: 1.5, repeat: Infinity, ease: "linear" }
      });
    } else {
      scanLineControls.stop();
    }
  }, [analyzing, scanLineControls]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || analyzing) return;
    setAnalyzing(true);
    if (navigator.vibrate) navigator.vibrate(50);

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.85);
        try {
            await new Promise(r => setTimeout(r, 2000)); // Dramatic Scan Effect
            const data = await analyzeFoodImage(base64);
            onAddToHistory({ id: Date.now().toString(), timestamp: Date.now(), analysis: data });
            setResult(data);
            if (navigator.vibrate) navigator.vibrate([100, 50, 100]);
        } catch (err) {
            setError("Analysis Protocol Failure.");
        } finally {
            setAnalyzing(false);
        }
    }
  };

  const getColorClass = (code: string) => {
    switch(code) {
      case 'green': return 'text-luxury-neon border-luxury-neon shadow-[0_0_30px_rgba(206,242,69,0.2)]';
      case 'yellow': return 'text-luxury-gold border-luxury-gold shadow-[0_0_30px_rgba(212,175,55,0.2)]';
      case 'red': return 'text-red-500 border-red-500 shadow-[0_0_30px_rgba(239,68,68,0.2)]';
      default: return 'text-white border-white';
    }
  };

  // HISTORY VIEW
  if (showHistory) {
    return (
      <div className="h-full w-full flex flex-col p-8 pt-16 bg-black">
        <div className="flex items-center gap-6 mb-12">
          <button onClick={() => setShowHistory(false)} className="glass-card p-3 rounded-2xl"><ArrowLeft size={20}/></button>
          <h1 className="text-3xl font-black text-white leading-none tracking-tight">Scan <span className="text-luxury-neon">Log</span></h1>
        </div>
        <div className="flex-1 overflow-y-auto space-y-5 pb-32 no-scrollbar">
          {history.length === 0 ? <p className="text-center text-gray-700 mt-24 text-sm font-bold uppercase tracking-widest">Database Empty</p> : history.map(item => (
            <div key={item.id} className="glass-card p-6 rounded-[2rem] flex justify-between items-center border border-white/5">
              <div>
                <h3 className="font-black text-white">{item.analysis.name}</h3>
                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest mt-1">{new Date(item.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
              </div>
              <div className="text-right">
                <span className="block font-black text-luxury-neon text-xl">{item.analysis.macros.calories}</span>
                <span className="text-[10px] uppercase text-gray-600 font-black tracking-widest">KCAL</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // MAIN CAMERA VIEW
  return (
    <div className="h-full w-full relative bg-black overflow-hidden flex flex-col">
      <canvas ref={canvasRef} className="hidden" />

      {/* Video Feed */}
      <div className="absolute inset-0 z-0">
        {stream ? (
           <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover opacity-80" />
        ) : (
           <div className="h-full w-full flex items-center justify-center bg-black">
             <Loader2 className="animate-spin text-luxury-neon" size={40} />
           </div>
        )}
      </div>

      {/* Grid Overlay for "High Tech" feel */}
      <div className="absolute inset-0 z-0 bg-[linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.03)_1px,transparent_1px)] bg-[size:50px_50px] pointer-events-none"></div>

      {/* HUD CONTROLS */}
      <div className="absolute inset-0 flex flex-col justify-between p-6 z-10 pointer-events-none">

        {/* Top Bar */}
        <div className="flex justify-between items-center pointer-events-auto pt-10">
          <button onClick={() => setShowHistory(true)} className="w-12 h-12 rounded-full glass-panel flex items-center justify-center border border-white/10 active:scale-95 transition-all">
             <History size={20} className="text-white"/>
          </button>
          <div className="px-4 py-2 glass-panel rounded-full border border-luxury-neon/30 flex items-center gap-2">
             <div className="w-1.5 h-1.5 bg-luxury-neon rounded-full animate-pulse"></div>
             <span className="text-[10px] font-black tracking-[0.3em] uppercase text-luxury-neon">Vision AI 2.0</span>
