export const onAuthStateChanged = (
  callback: (user: User | null) => void
) => {
  // Check initial session
  supabase.auth.getSession().then(({ data: { session } }) => {
    callback(session?.user ?? null);
  });

  // Listen for changes
  const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
    callback(session?.user ?? null);
  });

  return () => subscription.unsubscribe();
};

export const signInWithEmailAndPassword = async (email: string, psw: string) => {
  const { data, error } = await supabase.auth.signInWithPassword({
    email,
    password: psw,
  });
  if (error) throw error;
  return data;
};

export const createUserWithEmailAndPassword = async (email: string, psw: string) => {
  const { data, error } = await supabase.auth.signUp({
    email,
    password: psw,
  });
  if (error) throw error;
  return data;
};

export const signOut = async () => {
  const { error } = await supabase.auth.signOut();
  if (error) throw error;
};

export const updateProfile = async (user: User, profile: { displayName?: string, photoURL?: string }) => {
  const updates: any = {};
  // Supabase auth meta data is stored in data
  if (profile.displayName || profile.photoURL) {
      updates.data = {};
      if (profile.displayName) updates.data.full_name = profile.displayName;
      if (profile.photoURL) updates.data.avatar_url = profile.photoURL;

      const { error } = await supabase.auth.updateUser(updates);
      if (error) throw error;
  }
};

export const sendPasswordResetEmail = async (email: string) => {
  const { error } = await supabase.auth.resetPasswordForEmail(email);
  if (error) throw error;
  return true;
};

