import React, { useRef, useState, useEffect } from 'react';
import { ArrowLeft, History, Loader2, Scan, BrainCircuit, Zap, X, ChevronUp, Share2 } from 'lucide-react';
import { analyzeFoodImage } from '../services/geminiService';
import { FoodAnalysis, FoodHistoryItem } from '../types';
import { motion, AnimatePresence, useAnimation } from 'framer-motion';

interface FoodLensProps {
  history: FoodHistoryItem[];
  onAddToHistory: (item: FoodHistoryItem) => void;
}

const FoodLens: React.FC<FoodLensProps> = ({ history, onAddToHistory }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<FoodAnalysis | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showHistory, setShowHistory] = useState(false);
  const scanLineControls = useAnimation();

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }
      });
      setStream(mediaStream);
    } catch (err) {
      setError("AI Vision requires camera access.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    if (!showHistory) startCamera();
    return () => stopCamera();
  }, [showHistory]);

  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
      videoRef.current.play().catch(e => console.error(e));
    }
  }, [stream]);

  useEffect(() => {
    if (analyzing) {
      scanLineControls.start({
        top: ["0%", "100%"],
        transition: { duration: 1.5, repeat: Infinity, ease: "linear" }
      });
    } else {
      scanLineControls.stop();
    }
  }, [analyzing, scanLineControls]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || analyzing) return;
    setAnalyzing(true);
    if (navigator.vibrate) navigator.vibrate(50);

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.85);
        try {
            await new Promise(r => setTimeout(r, 2000)); // Dramatic Scan Effect
            const data = await analyzeFoodImage(base64);
            onAddToHistory({ id: Date.now().toString(), timestamp: Date.now(), analysis: data });
            setResult(data);
            if (navigator.vibrate) navigator.vibrate([100, 50, 100]);
        } catch (err) {
            setError("Analysis Protocol Failure.");
        } finally {
            setAnalyzing(false);
        }
    }
  };

  const getColorClass = (code: string) => {
    switch(code) {
      case 'green': return 'text-luxury-neon border-luxury-neon shadow-[0_0_30px_rgba(206,242,69,0.2)]';
      case 'yellow': return 'text-luxury-gold border-luxury-gold shadow-[0_0_30px_rgba(212,175,55,0.2)]';
      case 'red': return 'text-red-500 border-red-500 shadow-[0_0_30px_rgba(239,68,68,0.2)]';
      default: return 'text-white border-white';
    }
  };

  // HISTORY VIEW
  if (showHistory) {
    // Increased bottom padding to prevent the last item from being hidden by Nav Bar
    return (
      <div className="h-full w-full flex flex-col p-8 pt-16 bg-black">
        <div className="flex items-center gap-6 mb-12">
          <button onClick={() => setShowHistory(false)} className="glass-card p-3 rounded-2xl"><ArrowLeft size={20}/></button>
          <h1 className="text-3xl font-black text-white leading-none tracking-tight">Scan <span className="text-luxury-neon">Log</span></h1>
        </div>
        <div className="flex-1 overflow-y-auto space-y-5 pb-[calc(12rem+env(safe-area-inset-bottom))] no-scrollbar">
          {history.length === 0 ? <p className="text-center text-gray-700 mt-24 text-sm font-bold uppercase tracking-widest">Database Empty</p> : history.map(item => (
            <div key={item.id} className="glass-card p-6 rounded-[2rem] flex justify-between items-center border border-white/5">
              <div>
                <h3 className="font-black text-white">{item.analysis.name}</h3>
                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest mt-1">{new Date(item.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
              </div>
              <div className="text-right">
                <span className="block font-black text-luxury-neon text-xl">{item.analysis.macros.calories}</span>
                <span className="text-[10px] uppercase text-gray-600 font-black tracking-widest">KCAL</span>
              </div>
            </div>
          ))}
          {/* Explicit Spacer */}
          <div className="h-32"></div>
        </div>
      </div>
    );
  }

  // MAIN CAMERA VIEW
  return (
    <div className="h-full w-full relative bg-black overflow-hidden flex flex-col">
      <canvas ref={canvasRef} className="hidden" />

      {/* Video Feed */}
      <div className="absolute inset-0 z-0">
        {stream ? (
           <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover opacity-80" />
        ) : (
           <div className="h-full w-full flex items-center justify-center bg-black">
             <Loader2 className="animate-spin text-luxury-neon" size={40} />
           </div>
        )}
      </div>

      {/* Grid Overlay for "High Tech" feel */}
      <div className="absolute inset-0 z-0 bg-[linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.03)_1px,transparent_1px)] bg-[size:50px_50px] pointer-events-none"></div>

      {/* HUD CONTROLS */}
      <div className="absolute inset-0 flex flex-col justify-between p-6 z-10 pointer-events-none">

        {/* Top Bar */}
        <div className="flex justify-between items-center pointer-events-auto pt-10">
          <button onClick={() => setShowHistory(true)} className="w-12 h-12 rounded-full glass-panel flex items-center justify-center border border-white/10 active:scale-95 transition-all">
             <History size={20} className="text-white"/>
          </button>
          <div className="px-4 py-2 glass-panel rounded-full border border-luxury-neon/30 flex items-center gap-2">
             <div className="w-1.5 h-1.5 bg-luxury-neon rounded-full animate-pulse"></div>
             <span className="text-[10px] font-black tracking-[0.3em] uppercase text-luxury-neon">Vision AI 2.0</span>
          </div>
          <div className="w-12"></div> {/* Spacer */}
        </div>

        {/* Central Scanner Bracket Overlay */}
        <div className="flex-1 flex items-center justify-center relative">
            <div className={`relative w-[70vw] aspect-square transition-all duration-500 ${analyzing ? 'scale-105' : 'scale-100'}`}>
                {/* SVG Corners */}
                <svg className="absolute inset-0 w-full h-full drop-shadow-[0_0_10px_rgba(206,242,69,0.6)]">
                    <path d="M 40 0 L 0 0 L 0 40" fill="none" stroke="#CEF245" strokeWidth="4" strokeLinecap="round" />
                    <path d="M calc(100% - 40px) 0 L 100% 0 L 100% 40" fill="none" stroke="#CEF245" strokeWidth="4" strokeLinecap="round" />
                    <path d="M 40 100% L 0 100% L 0 calc(100% - 40px)" fill="none" stroke="#CEF245" strokeWidth="4" strokeLinecap="round" />
                    <path d="M calc(100% - 40px) 100% L 100% 100% L 100% calc(100% - 40px)" fill="none" stroke="#CEF245" strokeWidth="4" strokeLinecap="round" />
                </svg>

                {/* Laser Scan Line */}
                <motion.div 
                   animate={scanLineControls}
                   className="absolute left-0 right-0 h-0.5 bg-luxury-neon shadow-[0_0_20px_#CEF245] opacity-0"
                   style={{ opacity: analyzing ? 1 : 0 }}
                />

                {/* Focus Crosshair */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4">
                    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-0.5 h-full bg-white/30"></div>
                    <div className="absolute top-1/2 left-0 -translate-y-1/2 w-full h-0.5 bg-white/30"></div>
                </div>

                {/* Scanning Text */}
                <AnimatePresence>
                  {analyzing && (
                    <motion.div 
                       initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                       className="absolute -bottom-16 left-0 right-0 text-center"
                    >
                        <p className="text-luxury-neon font-black uppercase tracking-[0.3em] text-xs animate-pulse">Acquiring Bio-Data...</p>
                    </motion.div>
                  )}
                </AnimatePresence>
            </div>
        </div>

        {/* Bottom Controls - Lifted by 10rem to clear the navigation bar area */}
        <div className="h-32 flex items-center justify-center pointer-events-auto pb-[calc(10rem+env(safe-area-inset-bottom))] relative z-20">
            {!analyzing && (
                <button 
                  onClick={captureAndAnalyze}
                  className="group relative w-20 h-20 rounded-full flex items-center justify-center transition-all active:scale-95"
                >
                   {/* Glowing Ring */}
                   <div className="absolute inset-0 rounded-full border-4 border-luxury-neon opacity-50 group-hover:opacity-100 group-hover:scale-110 transition-all duration-500 shadow-[0_0_30px_rgba(206,242,69,0.3)]"></div>
                   <div className="absolute inset-2 rounded-full border-2 border-white/20"></div>

                   {/* Inner Core */}
                   <div className="w-14 h-14 bg-white rounded-full shadow-[0_0_20px_white] flex items-center justify-center group-hover:bg-luxury-neon transition-colors">
                      <Scan size={24} className="text-black" />
                   </div>
                </button>
            )}
        </div>
      </div>

      {/* RESULT BOTTOM SHEET (Glassmorphism) */}
      <AnimatePresence>
        {result && (
          <motion.div 
            initial={{ y: "100%" }}
            animate={{ y: 0 }}
            exit={{ y: "100%" }}
            transition={{ type: "spring", damping: 25, stiffness: 300 }}
            className="absolute bottom-0 left-0 right-0 z-50 rounded-t-[2.5rem] overflow-hidden border-t border-white/20 shadow-[0_-10px_50px_rgba(0,0,0,0.8)]"
          >
            {/* Blurry Background */}
            <div className="absolute inset-0 bg-black/80 backdrop-blur-xl"></div>

            {/* Content with padding at bottom for nav bar clearance */}
            <div className="relative p-8 pb-[calc(10rem+env(safe-area-inset-bottom))]">
                {/* Drag Handle */}
                <div className="w-12 h-1 bg-white/20 rounded-full mx-auto mb-6"></div>

                <div className="flex justify-between items-start mb-6">
                    <div>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Analysis Complete</p>
                        <h2 className="text-3xl font-black text-white leading-tight">{result.name}</h2>
                    </div>
                    <button onClick={() => setResult(null)} className="p-2 bg-white/10 rounded-full text-white hover:bg-white/20">
                        <X size={20} />
                    </button>
                </div>

                <div className={`p-6 rounded-[2rem] border ${getColorClass(result.colorCode)} bg-white/5 mb-6 flex justify-between items-center`}>
                    <div className="flex items-center gap-4">
                        <div className="p-3 rounded-full bg-white/10"><Zap size={24} className={result.colorCode === 'red' ? 'text-red-500' : 'text-luxury-neon'} /></div>
                        <div>
                            <span className="block text-3xl font-black text-white">{result.macros.calories}</span>
                            <span className="text-[10px] uppercase font-black tracking-widest text-gray-400">Total Calories</span>
                        </div>
                    </div>
                    <div className="text-right">
                        <span className="block text-xl font-bold text-white">{result.healthScore}<span className="text-sm text-gray-500">/100</span></span>
                        <span className="text-[10px] uppercase font-black tracking-widest text-gray-400">Score</span>
                    </div>
                </div>

                <div className="grid grid-cols-3 gap-3 mb-6">
                    {[
                        { label: 'Protein', val: result.macros.protein, color: 'text-luxury-neon' },
                        { label: 'Fat', val: result.macros.fat, color: 'text-luxury-gold' },
                        { label: 'Carbs', val: result.macros.carbs, color: 'text-blue-400' }
                    ].map(m => (
                        <div key={m.label} className="bg-white/5 border border-white/5 p-4 rounded-2xl text-center">
                            <span className={`block text-xl font-black ${m.color}`}>{m.val}g</span>
                            <span className="text-[9px] uppercase font-bold text-gray-500 tracking-widest">{m.label}</span>
                        </div>
                    ))}
