                <div className="p-5 rounded-2xl bg-white/5 border border-white/5 flex gap-4">
                    <BrainCircuit size={24} className="text-gray-400 shrink-0 mt-1" />
                    <div>
                        <h4 className="text-xs font-bold text-white uppercase tracking-widest mb-1">AI Verdict</h4>
                        <p className="text-sm text-gray-300 leading-relaxed">{result.advice}</p>
                    </div>
                </div>

                <div className="mt-6 flex gap-4">
                    <button onClick={() => setResult(null)} className="flex-1 py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-xl shadow-lg">New Scan</button>
                    <button className="px-6 py-4 bg-white/10 text-white rounded-xl font-bold"><Share2 size={18} /></button>
                </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

