import React, { useEffect, useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis } from 'recharts';
import { motion, AnimatePresence } from 'framer-motion';
import { ActivityData } from '../types';
import { Flame, Footprints, MapPin, Settings, Play, Pause, X, Bell, BrainCircuit } from 'lucide-react';
import DialControl from './DialControl';
import StreakWidget from './StreakWidget';
import { updateStreak, getMotivationalMessage } from '../services/streakService';

interface DashboardProps {
  data: ActivityData;
  onUpdateGoals: (newGoals: Partial<ActivityData>) => void;
  isTracking: boolean;
  onToggleTracking: () => void;
  status?: 'Idle' | 'Active' | 'Walking';
  adaptiveGoalsEnabled: boolean;
  onToggleAdaptiveGoals: (enabled: boolean) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  data, 
  onUpdateGoals, 
  isTracking, 
  onToggleTracking, 
  adaptiveGoalsEnabled,
  onToggleAdaptiveGoals
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [streakData, setStreakData] = useState<{ count: number, milestone: boolean } | null>(null);
  const [notification, setNotification] = useState<string | null>(null);

  useEffect(() => {
    const { currentStreak, milestoneReached } = updateStreak();
    setStreakData({ count: currentStreak, milestone: milestoneReached });
    const msg = getMotivationalMessage(currentStreak);
    const timer = setTimeout(() => {
       setNotification(msg);
       setTimeout(() => setNotification(null), 6000);
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  const stepsData = [
    { name: 'Done', value: Math.min(data.steps, data.stepGoal) },
    { name: 'Gap', value: Math.max(0, data.stepGoal - data.steps) },
  ];
  const calsData = [
    { name: 'Done', value: data.calories },
    { name: 'Gap', value: Math.max(0, data.calorieGoal - data.calories) },
  ];
  const distData = [
    { name: 'Done', value: data.distance },
    { name: 'Gap', value: Math.max(0, data.distanceGoal - data.distance) },
  ];

  return (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="min-h-full w-full flex flex-col p-8 space-y-8 relative"
    >
      <AnimatePresence>
        {notification && (
          <motion.div 
             initial={{ y: -50, opacity: 0 }}
             animate={{ y: 0, opacity: 1 }}
             exit={{ opacity: 0 }}
             className="fixed top-10 left-8 right-8 z-[100] mx-auto max-w-sm glass-card p-4 rounded-2xl flex items-center gap-4 shadow-2xl mt-[env(safe-area-inset-top)]"
          >
             <div className="p-2 bg-luxury-neon/20 rounded-xl">
               <Bell size={18} className="text-luxury-neon" />
             </div>
             <p className="text-white font-medium text-xs truncate flex-1">{notification}</p>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="flex justify-between items-center">
        <div className="flex-1 min-w-0">
          <p className="text-[10px] font-black text-gray-500 uppercase tracking-[0.4em] mb-1">Elite Session</p>
          <h1 className="text-3xl font-black text-white leading-none">
            Metric <span className="text-luxury-neon neon-glow-text">Sync</span>
          </h1>
        </div>
        <button 
          onClick={() => setIsEditing(true)}
          className="h-12 w-12 rounded-2xl flex items-center justify-center glass-card text-white hover:bg-white/10 transition-all"
        >
          <Settings size={20} />
        </button>
      </div>

      {streakData && (
         <div className="w-full">
           <StreakWidget streak={streakData.count} milestoneReached={streakData.milestone} />
         </div>
      )}

      {/* metallic Ingot Action Button */}
      <button 
        onClick={onToggleTracking} 
        className={`w-full py-5 rounded-2xl flex items-center justify-center gap-3 font-bold transition-all border metallic-button ${
          isTracking ? 'border-red-500/30 text-red-500' : 'border-luxury-neon/30 text-luxury-neon'
        }`}
      >
          {isTracking ? (
            <><div className="flex h-2 w-2 relative"><span className="animate-ping absolute h-full w-full rounded-full bg-red-400 opacity-75"></span><span className="relative rounded-full h-2 w-2 bg-red-500"></span></div>Tracking Protocols Active<Pause size={18} className="ml-2" /></>
          ) : (
            <><Play size={18} fill="currentColor" /> Initialize Live Tracking</>
          )}
      </button>

      {/* Suspended Neon Glass Rings */}
      <div className="relative w-full aspect-square max-h-[320px] mx-auto flex items-center justify-center">
        {/* Glow behind rings */}
        <div className="absolute inset-0 bg-luxury-neon/5 blur-[80px] rounded-full scale-90"></div>

        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie data={stepsData} cx="50%" cy="50%" innerRadius="78%" outerRadius="88%" startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={12} paddingAngle={2}>
              <Cell fill="#CEF245" className="filter drop-shadow-[0_0_8px_rgba(206,242,69,0.8)]" />
              <Cell fill="rgba(255,255,255,0.03)" />
            </Pie>
            <Pie data={calsData} cx="50%" cy="50%" innerRadius="64%" outerRadius="72%" startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={12} paddingAngle={2}>
              <Cell fill="#D4AF37" className="filter drop-shadow-[0_0_8px_rgba(212,175,55,0.8)]" />
              <Cell fill="rgba(255,255,255,0.03)" />
            </Pie>
            <Pie data={distData} cx="50%" cy="50%" innerRadius="52%" outerRadius="58%" startAngle={90} endAngle={-270} dataKey="value" stroke="none" cornerRadius={12} paddingAngle={2}>
              <Cell fill="#ef4444" className="filter drop-shadow-[0_0_8px_rgba(239,68,68,0.8)]" />
              <Cell fill="rgba(255,255,255,0.03)" />
            </Pie>
          </PieChart>
        </ResponsiveContainer>

        <div className="absolute flex flex-col items-center justify-center pointer-events-none text-center">
          <Footprints className="text-luxury-neon mb-2 opacity-80" size={24} />
          <span className="text-5xl font-black tracking-tighter text-white">{data.steps.toLocaleString()}</span>
          <span className="text-[10px] text-gray-500 uppercase font-black tracking-[0.3em] mt-1">Total Steps</span>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-5">
        <div className="glass-card p-6 rounded-[2rem] flex flex-col justify-between min-h-[140px]">
          <div className="flex justify-between items-start">
            <div className="p-2 bg-luxury-gold/10 rounded-xl"><Flame className="text-luxury-gold" size={20} /></div>
            <span className="text-[10px] text-gray-500 font-black tracking-widest">KCAL</span>
          </div>
          <div>
            <span className="text-3xl font-black block text-white">{Math.floor(data.calories)}</span>
            <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1 block">Burned</span>
          </div>
        </div>
        <div className="glass-card p-6 rounded-[2rem] flex flex-col justify-between min-h-[140px]">
          <div className="flex justify-between items-start">
            <div className="p-2 bg-red-500/10 rounded-xl"><MapPin className="text-red-500" size={20} /></div>
            <span className="text-[10px] text-gray-500 font-black tracking-widest">KM</span>
          </div>
