        distanceGoal: 5.0
    },
    current_activity: {
        steps: 0,
        calories: 0,
        distance: 0,
        history: [
            { day: 'Mon', steps: 0 },
            { day: 'Tue', steps: 0 },
            { day: 'Wed', steps: 0 },
            { day: 'Thu', steps: 0 },
            { day: 'Fri', steps: 0 },
            { day: 'Sat', steps: 0 },
            { day: 'Sun', steps: 0 },
        ]
    }
  };

