// Real-time subscription to user data
export const subscribeToUserData = (uid: string, onUpdate: (data: any) => void) => {
  // 1. Fetch initial data
  supabase
    .from('profiles')
    .select('*')
    .eq('id', uid)
    .single()
    .then(({ data, error }) => {
      if (data && !error) {
        onUpdate(mapProfileToAppFormat(data));
      }
    });

  // 2. Subscribe to changes
  const channel = supabase
    .channel(`public:profiles:id=eq.${uid}`)
    .on(
      'postgres_changes',
      { event: 'UPDATE', schema: 'public', table: 'profiles', filter: `id=eq.${uid}` },
      (payload) => {
        if (payload.new) {
          onUpdate(mapProfileToAppFormat(payload.new));
        }
      }
    )
    .subscribe();

  return () => {
    supabase.removeChannel(channel);
  };
};

export const updateUserActivity = async (uid: string, data: Partial<ActivityData>, goals?: Partial<ActivityData>) => {
  const updates: any = {};

  // We need to fetch current to merge, or trust the caller passed delta. 
  // However, Supabase jsonb updates usually replace the whole object or need specific path syntax.
  // For simplicity, we assume 'data' and 'goals' passed here are the *complete* objects or we do a shallow merge.
  // Ideally, we fetch current state first or use SQL functions.
  // Here we will try to just update the column.

  if (data) {
     // Fetch current to merge deep keys if needed, but here we'll assume app passes full object or we just update what we have.
     // To avoid overwriting history with just steps, we should ideally fetch-modify-save or use a jsonb_set in RPC.
     // For this frontend-focused impl, we will trust that `data` contains the fields we want to save.
     // NOTE: If 'data' is partial, this might overwrite 'current_activity' with incomplete data if we aren't careful.
     // Let's do a quick fetch to merge:

     const { data: current } = await supabase.from('profiles').select('current_activity').eq('id', uid).single();
     const merged = { ...current?.current_activity, ...data };
     updates.current_activity = merged;
  }

  if (goals) {
      const { data: current } = await supabase.from('profiles').select('goals').eq('id', uid).single();
      const merged = { ...current?.goals, ...goals };
      updates.goals = merged;
  }

  if (Object.keys(updates).length > 0) {
    const { error } = await supabase.from('profiles').update(updates).eq('id', uid);
    if (error) console.error("Error updating activity:", error);
  }
};

// Helper to map DB snake_case to App camelCase
const mapProfileToAppFormat = (dbProfile: any) => {
  return {
    uid: dbProfile.id,
    name: dbProfile.name,
    email: dbProfile.email,
    avatarUrl: dbProfile.avatar_url,
    goals: dbProfile.goals,
    currentActivity: dbProfile.current_activity
  };
};

