import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
// Updated imports to use Supabase service
import { 
  createUserDocument, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile,
  sendPasswordResetEmail
} from '../services/supabase';
import { Loader2, Eye, EyeOff, AlertCircle, User as UserIcon, Mail, Lock, CheckCircle } from 'lucide-react';

interface AuthProps {
  onLoginSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetError, setResetError] = useState<string | null>(null);

  const [name, setName] = useState('');
  // Default state is empty
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccessMsg(null);
    setIsLoading(true);

    try {
      if (isLogin) {
        await signInWithEmailAndPassword(email, password);
        onLoginSuccess();
      } else {
        if (password !== confirmPassword) throw new Error("Passwords do not match.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");

        const { user, session } = await createUserWithEmailAndPassword(email, password);

        if (user) {
            // Update profile immediately
            await updateProfile(user, { displayName: name });
            await createUserDocument(user, name);

            if (session) {
                // Auto-login successful
                onLoginSuccess();
            } else {
                // Email verification likely required
                setIsLogin(true);
                setSuccessMsg("Account created successfully! Please check your email to verify your account before logging in.");
                setPassword('');
                setConfirmPassword('');
            }
        }
      }
    } catch (err: any) {
      console.error(err);
      let msg = err.message || "Authentication failed.";
      if (msg.includes("Invalid login credentials")) {
        msg = "Invalid email or password. Please check your credentials or sign up if you haven't.";
      } else if (msg.includes("Email not confirmed")) {
        msg = "Your email address has not been verified. Please check your inbox for the confirmation link.";
      } else if (msg.toLowerCase().includes("rate limit")) {
        msg = "Security Rate Limit: Please wait a few minutes before trying again.";
      }
      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const handleResetPassword = async () => {
    if (!resetEmail) return;
    setResetError(null);
    try {
        await sendPasswordResetEmail(resetEmail);
        setSuccessMsg("Recovery link sent to " + resetEmail);
        setIsResetModalOpen(false);
    } catch(err: any) {
        let msg = err.message || "Failed to send reset link.";
        if (msg.toLowerCase().includes("rate limit")) {
            msg = "Too many requests. Please wait a few minutes before trying again.";
        }
        setResetError(msg);
    }
  };

  return (
    <div className="min-h-screen w-full flex flex-col bg-black font-sans relative overflow-y-auto no-scrollbar">
      <div className="absolute inset-0 z-0 bg-cover bg-center grayscale blur-md opacity-40 scale-105"
        style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1534438327276-14e5300c3a48?q=80&w=2070&auto=format&fit=crop")' }} />
      <div className="absolute inset-0 z-0 bg-gradient-to-b from-black/80 via-black/90 to-black"></div>

      <div className="relative z-10 flex-1 flex items-center justify-center p-6 py-12">
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="w-full max-w-md glass-panel rounded-3xl p-8 border border-white/10 shadow-2xl"
        >
