      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      },
      required: ["calories", "protein", "fat", "carbs"]
    },
    healthScore: { type: Type.NUMBER, description: "Score from 0-100" },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING, description: "Short nutritional tip" },
    alternatives: { type: Type.STRING, description: "A healthier alternative or modification to this meal." },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] },
    boundingBox: {
      type: Type.ARRAY,
      items: { type: Type.NUMBER },
      description: "Bounding box in [ymin, xmin, ymax, xmax] format (0-1)."
    }
  },
  required: ["name", "macros", "healthScore", "verdict", "advice", "alternatives", "colorCode"]
};

const workoutResponseSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "Catchy name for the workout" },
    difficulty: { type: Type.STRING },
    duration: { type: Type.STRING, description: "Estimated time e.g. '45 mins'" },
    exercises: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          sets: { type: Type.STRING },
          reps: { type: Type.STRING },
          notes: { type: Type.STRING, description: "Form tip or tempo instruction" }
        },
        required: ["name", "sets", "reps", "notes"]
      }
    }
  },
  required: ["title", "difficulty", "duration", "exercises"]
};

/**
 * Analyze food image using gemini-2.5-flash for multimodal vision capabilities
 */
export const analyzeFoodImage = async (base64Image: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] 
            }
          },
          { text: "Analyze this meal. Identify ingredients, provide strict nutrition JSON, and suggest a healthier alternative." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: foodResponseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Image Analysis Error:", error);
    return getFallbackAnalysis("Scan failed. Ensure clear image.");
  }
};

/**
 * Analyze food description text
 */
export const analyzeFoodText = async (query: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Estimate nutrition for: ${query}. Include a healthier alternative suggestion.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: foodResponseSchema
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FoodAnalysis;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Text Analysis Error:", error);
    return getFallbackAnalysis("Manual entry failed.");
  }
};

/**
 * Generate a personalized workout routine
 */
export const generateWorkoutRoutine = async (
  level: string,
  goal: string,
  equipment: string,
  metrics: UserMetrics
): Promise<WorkoutPlan> => {
  try {
    const prompt = `Create a high-intensity luxury fitness routine.
    User Stats: Height ${metrics.height}cm, Weight ${metrics.weight}kg.
    Level: ${level}.
    Goal: ${goal}.
    Equipment Available: ${equipment}.
    Format: Structured JSON.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: workoutResponseSchema
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text);
      return {
        id: Date.now().toString(),
        timestamp: Date.now(),
        ...data
      } as WorkoutPlan;
    }
    throw new Error("Empty AI response");
  } catch (error) {
    console.error("Workout Generation Error:", error);
    throw error;
  }
};

/**
 * Get the streaming coach chat with persistent context history.
 */
export const getCoachChatStream = async (
  message: string, 
  history: Content[],
  metrics: UserMetrics,
  activity: ActivityData
) => {
  const systemInstruction = `You are the Healthy.hub Elite Professional Trainer.

  CORE MEMORY & CONTEXT:
  - User Height: ${metrics.height}cm | Weight: ${metrics.weight}kg
  - Today's Activity: ${activity.steps} steps
  - You MUST remember equipment lists, injuries, or dietary preferences mentioned in previous messages.

  BEHAVIORAL PROTOCOLS:
  1. If the user asks for a workout, FIRST check if you know their equipment. If not, ask: "What equipment do you have available?"
  2. Maintain a "Tough Love" but "Luxury Service" persona. Concise, high-value advice.
  3. MANDATORY DISCLAIMER: End every response with: "⚠️ Consult a professional before starting."
  `;

  // We recreate the chat object with the full history to ensure stateful behavior.
  // The SDK automatically appends the new message to this history context.
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: systemInstruction,
      temperature: 0.7,
    },
    history: history,
  });

  return await chat.sendMessageStream({ message });
};

