  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccessMsg(null);
    setIsLoading(true);

    try {
      if (isLogin) {
        await signInWithEmailAndPassword(email, password);
        onLoginSuccess();
      } else {
        if (password !== confirmPassword) throw new Error("Passwords do not match.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");

        const { user, session } = await createUserWithEmailAndPassword(email, password);

        if (user) {
            // Update profile immediately
            if (name) {
                await updateProfile(user, { displayName: name });
                await createUserDocument(user, name);
            } else {
                await createUserDocument(user, 'User');
            }

            if (session) {
                // Auto-login successful
                onLoginSuccess();
            } else {
                // Email verification likely required
                setIsLogin(true);
                setSuccessMsg("Account created successfully! Please check your email to verify your account before logging in.");
                setPassword('');
                setConfirmPassword('');
            }
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      let msg = err.message || "Authentication failed.";

      // Detailed Error Handling
      const lowerMsg = msg.toLowerCase();
      if (msg.includes("Invalid login credentials")) {
        msg = "Invalid email or password. Please check your credentials.";
      } else if (msg.includes("Email not confirmed")) {
        msg = "Your email address has not been verified. Please check your inbox.";
      } else if (lowerMsg.includes("rate limit") || lowerMsg.includes("email rate limit exceeded")) {
        msg = "Too many attempts. Please wait a moment before trying again (Rate Limit).";
      } else if (lowerMsg.includes("user already registered")) {
        msg = "This email is already registered. Please log in instead.";
      }

      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const handleResetPassword = async () => {
    if (!resetEmail) return;
    setResetError(null);
    setResetSuccess(null);
    try {
        await sendPasswordResetEmail(resetEmail);
        setResetSuccess("Recovery link sent to " + resetEmail);
        setTimeout(() => setIsResetModalOpen(false), 3000);
    } catch(err: any) {
        let msg = err.message || "Failed to send reset link.";
        const lowerMsg = msg.toLowerCase();
        if (lowerMsg.includes("rate limit") || lowerMsg.includes("email rate limit exceeded")) {
            msg = "Too many requests. Please wait a few minutes before trying again.";
        }
        setResetError(msg);
    }
  };

  return (
    <div className="min-h-screen w-full flex flex-col bg-black font-sans relative overflow-y-auto no-scrollbar">
