              <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} className="bg-red-500/10 border border-red-500/20 rounded-xl p-3 mb-6 flex items-center gap-3 text-red-400 text-xs font-bold">
                <AlertCircle size={14} className="shrink-0" /> <span className="flex-1">{error}</span>
              </motion.div>
            )}
            {successMsg && (
              <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} className="bg-green-500/10 border border-green-500/20 rounded-xl p-3 mb-6 flex items-center gap-3 text-green-400 text-xs font-bold">
                <CheckCircle size={14} className="shrink-0" /> <span className="flex-1">{successMsg}</span>
