        history: [
            { day: 'Mon', steps: 0 },
            { day: 'Tue', steps: 0 },
            { day: 'Wed', steps: 0 },
            { day: 'Thu', steps: 0 },
            { day: 'Fri', steps: 0 },
            { day: 'Sat', steps: 0 },
            { day: 'Sun', steps: 0 },
        ]
    }
  };

  const { error } = await supabase
