// Real-time subscription to user data with Self-Healing Logic
export const subscribeToUserData = (uid: string, onUpdate: (data: any) => void) => {
  const init = async () => {
    try {
      // 1. Attempt to fetch existing profile using maybeSingle to avoid 0-row errors
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .maybeSingle();

      if (error) {
        console.error("Database Error (Check RLS Policies):", error.message);
        // Even if error, call onUpdate(null) to stop the loading spinner
        onUpdate(null);
        return;
      }

      if (data) {
        onUpdate(mapProfileToAppFormat(data));
      } else {
        // 2. SELF-HEALING: No profile found. Automatically create one.
        console.warn("Profile missing for user. Initiating Self-Healing (Creating Default Profile)...");

        const { data: { user } } = await supabase.auth.getUser();

        if (user && user.id === uid) {
             const name = user.user_metadata?.full_name || user.email?.split('@')[0] || 'Member';

             try {
                await createUserDocument(user, name);

                // 3. Retry fetch after creation
                const { data: newData, error: newError } = await supabase
                  .from('profiles')
                  .select('*')
                  .eq('id', uid)
                  .single();

                if (newData && !newError) {
                    onUpdate(mapProfileToAppFormat(newData));
                } else {
                    console.error("Self-healing verification failed:", newError);
                    onUpdate(null);
                }
             } catch (createErr) {
                 console.error("Failed to create default profile:", createErr);
                 onUpdate(null);
             }
        } else {
             onUpdate(null);
        }
      }
    } catch (e) {
      console.error("Unexpected error in subscription init:", e);
      onUpdate(null);
    }
  };

  init();

  // 4. Subscribe to changes
  const channel = supabase
    .channel(`public:profiles:id=eq.${uid}`)
    .on(
      'postgres_changes',
      { event: 'UPDATE', schema: 'public', table: 'profiles', filter: `id=eq.${uid}` },
      (payload) => {
        if (payload.new) {
          onUpdate(mapProfileToAppFormat(payload.new));
        }
      }
    )
    .subscribe();

  return () => {
    supabase.removeChannel(channel);
  };
};

export const updateUserActivity = async (uid: string, data: Partial<ActivityData>, goals?: Partial<ActivityData>) => {
  const updates: any = {};

  if (data) {
     const { data: current } = await supabase.from('profiles').select('current_activity').eq('id', uid).single();
     const merged = { ...current?.current_activity, ...data };
     updates.current_activity = merged;
  }

  if (goals) {
      const { data: current } = await supabase.from('profiles').select('goals').eq('id', uid).single();
      const merged = { ...current?.goals, ...goals };
      updates.goals = merged;
  }

  if (Object.keys(updates).length > 0) {
    const { error } = await supabase.from('profiles').update(updates).eq('id', uid);
    if (error) console.error("Error updating activity:", error);
  }
};

// Helper to map DB snake_case to App camelCase
const mapProfileToAppFormat = (dbProfile: any) => {
  return {
    uid: dbProfile.id,
    name: dbProfile.name,
    email: dbProfile.email,
    avatarUrl: dbProfile.avatar_url,
    goals: dbProfile.goals,
    currentActivity: dbProfile.current_activity
  };
};

import { useState, useEffect, useRef, useCallback } from 'react';

interface PedometerHook {
  isTracking: boolean;
  toggleTracking: () => Promise<void>;
  liveSteps: number;
  resetLiveSteps: () => void;
  status: 'Idle' | 'Active' | 'Walking';
}

const usePedometer = (): PedometerHook => {
  const [isTracking, setIsTracking] = useState(false);
  const [liveSteps, setLiveSteps] = useState(0);
  const [status, setStatus] = useState<'Idle' | 'Active' | 'Walking'>('Idle');

  const wakeLock = useRef<WakeLockSentinel | null>(null);
  const lastStepTime = useRef(0);

  // Refs for state variables needed inside the event listener
  // We use refs so we can access the latest value inside the memoized callback
  // without having to add them as dependencies (which would recreate the function and break removeEventListener)
  const isTrackingRef = useRef(isTracking);
  const statusRef = useRef(status);

  // Sync refs with state
  useEffect(() => { isTrackingRef.current = isTracking; }, [isTracking]);
  useEffect(() => { statusRef.current = status; }, [status]);

  // Thresholds
  const THRESHOLD = 1.3; 
  const MIN_STEP_DELAY = 350;

  // Memoize the handler so it stays the same reference for add/removeEventListener
  const handleMotion = useCallback((event: DeviceMotionEvent) => {
    // --- LOGIC GATE ---
    // Explicitly check tracking status via Ref before processing any sensor data.
    // This ensures that even if the listener wasn't removed for some reason, we don't count steps.
    if (!isTrackingRef.current) return;

    if (!event.acceleration) return;

    const { x, y, z } = event.acceleration;
    if (x === null || y === null || z === null) return;

    const mag = Math.sqrt(x*x + y*y + z*z);
    const now = Date.now();

    if (mag > 0.5) {
      if (statusRef.current === 'Idle') {
          setStatus('Active');
      }
    }

    if (mag > THRESHOLD) {
      if (now - lastStepTime.current > MIN_STEP_DELAY) {
        setLiveSteps(prev => prev + 1);
        lastStepTime.current = now;
        setStatus('Walking');
        if (navigator.vibrate) navigator.vibrate(5);
      }
    }

    if (now - lastStepTime.current > 2000) {
      if (statusRef.current !== 'Idle') {
          setStatus('Idle');
      }
    }
  }, []);

  const toggleTracking = async () => {
    if (isTracking) {
      // STOP TRACKING
      // Because handleMotion is memoized, this reference now matches the one added, ensuring removal works.
      window.removeEventListener('devicemotion', handleMotion);

      if (wakeLock.current) {
        await wakeLock.current.release();
        wakeLock.current = null;
      }
      setIsTracking(false);
      setStatus('Idle');
    } else {
      // START TRACKING
      // @ts-ignore
      if (typeof DeviceMotionEvent !== 'undefined' && typeof DeviceMotionEvent.requestPermission === 'function') {
        // @ts-ignore
        const permission = await DeviceMotionEvent.requestPermission();
        if (permission !== 'granted') return;
      }

      window.addEventListener('devicemotion', handleMotion);
      if ('wakeLock' in navigator) {
        try {
          wakeLock.current = await navigator.wakeLock.request('screen');
        } catch {}
      }
      setIsTracking(true);
      setStatus('Active');
    }
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      window.removeEventListener('devicemotion', handleMotion);
      if (wakeLock.current) wakeLock.current.release().catch(() => {});
    };
  }, [handleMotion]);

  return { isTracking, toggleTracking, liveSteps, resetLiveSteps: () => setLiveSteps(0), status };
};

export default usePedometer;
